thread_local! {
    static TOUCH_DISABLED: Cell<bool> = const { Cell::new(false) };
}

struct TouchGuard {
    previous: bool,
}

impl TouchGuard {
    fn new(disabled: bool) -> Self {
        let previous = TOUCH_DISABLED.with(|flag| {
            let prev = flag.get();
            flag.set(disabled);
            prev
        });
        Self { previous }
    }
}

impl Drop for TouchGuard {
    fn drop(&mut self) {
        TOUCH_DISABLED.with(|flag| flag.set(self.previous));
    }
}

fn touch_disabled() -> bool {
    TOUCH_DISABLED.with(Cell::get)
}

/// Temporarily disable LRU/LFU touch updates for the current thread.
pub fn with_touch_disabled<T>(disabled: bool, f: impl FnOnce() -> T) -> T {
    let _guard = TouchGuard::new(disabled);
    f()
}

// ── Keyspace notification flags (matching Redis server.h) ───────────
pub const NOTIFY_KEYSPACE: u32 = 1 << 0; // K
pub const NOTIFY_KEYEVENT: u32 = 1 << 1; // E
pub const NOTIFY_GENERIC: u32 = 1 << 2; // g
pub const NOTIFY_STRING: u32 = 1 << 3; // $
pub const NOTIFY_LIST: u32 = 1 << 4; // l
pub const NOTIFY_SET: u32 = 1 << 5; // s
pub const NOTIFY_HASH: u32 = 1 << 6; // h
pub const NOTIFY_ZSET: u32 = 1 << 7; // z
pub const NOTIFY_EXPIRED: u32 = 1 << 8; // x
pub const NOTIFY_EVICTED: u32 = 1 << 9; // e
pub const NOTIFY_STREAM: u32 = 1 << 10; // t
pub const NOTIFY_KEY_MISS: u32 = 1 << 11; // m
pub const NOTIFY_NEW: u32 = 1 << 12; // n
pub const NOTIFY_MODULE: u32 = 1 << 13; // d (module key-type notification)
// Upstream server.h: the `A` alias covers every class EXCEPT key-miss (m)
// and new-key (n) — and DOES include the module class (d). (frankenredis-nkednfix)
pub const NOTIFY_ALL: u32 = NOTIFY_GENERIC
    | NOTIFY_STRING
    | NOTIFY_LIST
    | NOTIFY_SET
    | NOTIFY_HASH
    | NOTIFY_ZSET
    | NOTIFY_EXPIRED
    | NOTIFY_EVICTED
    | NOTIFY_STREAM
    | NOTIFY_MODULE;

/// Parse a notify-keyspace-events configuration string into flags.
/// Returns None if the string contains invalid characters.
#[must_use]
pub fn keyspace_events_parse(classes: &str) -> Option<u32> {
    let mut flags = 0u32;
    for c in classes.chars() {
        match c {
            'A' => flags |= NOTIFY_ALL,
            'g' => flags |= NOTIFY_GENERIC,
            '$' => flags |= NOTIFY_STRING,
            'l' => flags |= NOTIFY_LIST,
            's' => flags |= NOTIFY_SET,
            'h' => flags |= NOTIFY_HASH,
            'z' => flags |= NOTIFY_ZSET,
            'x' => flags |= NOTIFY_EXPIRED,
            'e' => flags |= NOTIFY_EVICTED,
            'K' => flags |= NOTIFY_KEYSPACE,
            'E' => flags |= NOTIFY_KEYEVENT,
            't' => flags |= NOTIFY_STREAM,
            'm' => flags |= NOTIFY_KEY_MISS,
            'n' => flags |= NOTIFY_NEW,
            'd' => flags |= NOTIFY_MODULE,
            _ => return None,
        }
    }
    // Upstream keeps the class flags in the config regardless of K/E: the
    // K/E requirement only gates whether an event actually *fires*
    // (notify_keyspace_event checks NOTIFY_KEYSPACE / NOTIFY_KEYEVENT at
    // emit time), so e.g. `CONFIG SET notify-keyspace-events g` round-trips
    // back as `g`. fr previously zeroed everything when K/E were absent,
    // dropping the class flags from CONFIG GET. (frankenredis-nkednfix)
    Some(flags)
}

/// Convert notification flags back to a configuration string.
///
/// Mirrors upstream `notify.c::keyspaceEventsFlagsToString`: canonical
/// order is A | g $ l s h z x e t d n | K E m, where the per-class chars
/// (incl. `d` NOTIFY_MODULE and `n` NOTIFY_NEW) only appear when `A` is
/// NOT set (upstream lists them inside the per-class else branch), while
/// `m` (NOTIFY_KEY_MISS) is emitted after K/E. This matters for CONFIG GET
/// parity: `CONFIG SET notify-keyspace-events KEA` must echo back `AKE`,
/// not `KEA`. (br-frankenredis-xmev)
#[must_use]
pub fn keyspace_events_to_string(flags: u32) -> String {
    let mut s = String::new();
    if (flags & NOTIFY_ALL) == NOTIFY_ALL {
        s.push('A');
    } else {
        if flags & NOTIFY_GENERIC != 0 {
            s.push('g');
        }
        if flags & NOTIFY_STRING != 0 {
            s.push('$');
        }
        if flags & NOTIFY_LIST != 0 {
            s.push('l');
        }
        if flags & NOTIFY_SET != 0 {
            s.push('s');
        }
        if flags & NOTIFY_HASH != 0 {
            s.push('h');
        }
        if flags & NOTIFY_ZSET != 0 {
            s.push('z');
        }
        if flags & NOTIFY_EXPIRED != 0 {
            s.push('x');
        }
        if flags & NOTIFY_EVICTED != 0 {
            s.push('e');
        }
        if flags & NOTIFY_STREAM != 0 {
            s.push('t');
        }
        if flags & NOTIFY_MODULE != 0 {
            s.push('d');
        }
        if flags & NOTIFY_NEW != 0 {
            s.push('n');
        }
    }
    if flags & NOTIFY_KEYSPACE != 0 {
        s.push('K');
    }
    if flags & NOTIFY_KEYEVENT != 0 {
        s.push('E');
    }
    if flags & NOTIFY_KEY_MISS != 0 {
        s.push('m');
    }
    s
}

pub type StreamId = (u64, u64);
pub type StreamField = (Vec<u8>, Vec<u8>);
/// A whole stream's entries: a single shared arena plus a sorted
/// `BTreeMap<StreamId, FieldSpan>` index ([`PackedStreamLog`]) — instead of a
/// `BTreeMap<StreamId, PackedStreamFields>` that paid a separate heap allocation
/// AND a 28-byte (`Vec` header + count) value PER entry (frankenredis-p8wd1
/// step 3). The per-entry field bytes are byte-identical to the old
/// `PackedStreamFields` layout, so DUMP / DEBUG DIGEST / XRANGE output is
/// unchanged; only the container shrinks. Reads hand back a `FieldsRef` view
/// whose `to_pairs`/`iter` mirror the old type, so callers are unchanged.
pub type StreamEntries = PackedStreamLog;
pub type StreamRecord = (StreamId, Vec<StreamField>);
pub type StreamInfoBounds = (usize, Option<StreamRecord>, Option<StreamRecord>);
/// (name, pending_count, idle_ms)
pub type StreamConsumerInfo = (Vec<u8>, usize, u64);
pub type StreamPendingEntries = BTreeMap<StreamId, StreamPendingEntry>;
pub type StreamPendingSummaryConsumer = (Vec<u8>, usize);
pub type StreamPendingSummary = (
    usize,
    Option<StreamId>,
    Option<StreamId>,
    Vec<StreamPendingSummaryConsumer>,
);
pub type StreamPendingRecord = (StreamId, Vec<u8>, u64, u64);
pub type StreamAutoClaimDeleted = Vec<StreamId>;
type BorrowedStreamField<'a> = (&'a [u8], &'a [u8]);
type BorrowedDumpStreamEntry<'a> = (u64, u64, Vec<BorrowedStreamField<'a>>);

/// An asynchronous server message queued for delivery to a client.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum PubSubMessage {
    /// Direct channel subscription match: `["message", channel, data]`.
    Message { channel: Vec<u8>, data: Vec<u8> },
    /// Pattern subscription match: `["pmessage", pattern, channel, data]`.
    PMessage {
        pattern: Vec<u8>,
        channel: Vec<u8>,
        data: Vec<u8>,
    },
    /// Shard-channel subscription match: `["smessage", channel, data]`.
    SMessage { channel: Vec<u8>, data: Vec<u8> },
    /// Client-side caching invalidation: `["invalidate", [keys...]]`.
    Invalidate { keys: Vec<Vec<u8>> },
}

/// A single SLOWLOG entry recording a command that exceeded the threshold.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SlowlogEntry {
    pub id: u64,
    pub timestamp_sec: u64,
    pub duration_us: u64,
    pub argv: Vec<Vec<u8>>,
    pub client_address: Vec<u8>,
    pub client_name: Vec<u8>,
}

/// Max number of arguments retained per slowlog entry (slowlog.c
/// `SLOWLOG_ENTRY_MAX_ARGC`). When a command has more, the last retained slot
/// is replaced by a `... (N more arguments)` summary.
const SLOWLOG_ENTRY_MAX_ARGC: usize = 32;
/// Max byte length of any single retained argument (slowlog.c
/// `SLOWLOG_ENTRY_MAX_STRING`). Longer args are trimmed and suffixed with
/// `... (M more bytes)`.
pub const SLOWLOG_ENTRY_MAX_STRING: usize = 128;

/// Build the argv stored in a slowlog entry, mirroring slowlog.c
/// `slowlogCreateEntry`: cap at `SLOWLOG_ENTRY_MAX_ARGC` arguments (the last
/// retained slot becomes a `... (N more arguments)` summary) and trim any single
/// argument longer than `SLOWLOG_ENTRY_MAX_STRING` bytes to a
/// `<128 bytes>... (M more bytes)` form.
fn slowlog_build_argv(argv: &[Vec<u8>]) -> Vec<Vec<u8>> {
    let argc = argv.len();
    let slargc = argc.min(SLOWLOG_ENTRY_MAX_ARGC);
    let mut out = Vec::with_capacity(slargc);
    for (j, arg) in argv.iter().take(slargc).enumerate() {
        if slargc != argc && j == slargc - 1 {
            // Last slot summarises the arguments that were dropped. Upstream
            // counts the displaced last real arg too: argc - slargc + 1.
            out.push(format!("... ({} more arguments)", argc - slargc + 1).into_bytes());
        } else if arg.len() > SLOWLOG_ENTRY_MAX_STRING {
            let mut s = arg[..SLOWLOG_ENTRY_MAX_STRING].to_vec();
            s.extend_from_slice(
                format!("... ({} more bytes)", arg.len() - SLOWLOG_ENTRY_MAX_STRING).as_bytes(),
            );
            out.push(s);
        } else {
            out.push(arg.clone());
        }
    }
    out
}

/// Score bound for sorted set range queries (ZRANGEBYSCORE, ZCOUNT, etc.).
/// Supports inclusive (default), exclusive (`(` prefix), and infinity (`-inf`/`+inf`).
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum ScoreBound {
    Inclusive(f64),
    Exclusive(f64),
}

/// Numerical f64 of a score bound, used to detect inverted ranges
/// (start > end) without panicking the BTreeMap range walker.
#[inline]
fn score_bound_value(bound: ScoreBound) -> f64 {
    match bound {
        ScoreBound::Inclusive(s) | ScoreBound::Exclusive(s) => s,
    }
}

impl ScoreBound {
    /// Check if `score` satisfies this bound as a minimum (lower bound).
    pub fn check_min(self, score: f64) -> bool {
        match self {
            ScoreBound::Inclusive(v) => score >= v,
            ScoreBound::Exclusive(v) => score > v,
        }
    }

    /// Check if `score` satisfies this bound as a maximum (upper bound).
    pub fn check_max(self, score: f64) -> bool {
        match self {
            ScoreBound::Inclusive(v) => score <= v,
            ScoreBound::Exclusive(v) => score < v,
        }
    }
}

/// Check if a score falls within the given min/max bounds.
pub fn score_in_range(score: f64, min: ScoreBound, max: ScoreBound) -> bool {
    min.check_min(score) && max.check_max(score)
}

