    pub fn llen(&mut self, key: &[u8], now_ms: u64) -> Result<usize, StoreError> {
        // (CrimsonHawk) Non-LFU single-lookup collapse — see `scard`. Byte-identical.
        if !self.lfu_tracking_enabled() {
            return match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => match &entry.value {
                    Value::List(l) => {
                        let len = l.len();
                        entry.touch(now_ms);
                        Ok(len)
                    }
                    _ => Err(StoreError::WrongType),
                },
                None => Ok(0),
            };
        }
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(0);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::List(l) => {
                        let len = l.len();
                        entry.touch(now_ms);
                        Ok(len)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(0),
        }
    }

    /// List length WITHOUT recording a keyspace hit/miss. LMPOP iterates its
    /// candidate keys to find the first non-empty list; upstream lmpopCommand
    /// reaches each via lookupKeyWrite, which does not touch keyspace stats, so
    /// the stat-counting `llen` would over-count. Returns WRONGTYPE for a
    /// non-list key (same as llen), 0 for missing/expired.
    pub fn llen_no_stat(&mut self, key: &[u8], now_ms: u64) -> Result<usize, StoreError> {
        if !self.drop_if_expired(key, now_ms) {
            return Ok(0);
        }
        match self.entries.get(key) {
            Some(entry) => match &entry.value {
                Value::List(l) => Ok(l.len()),
                _ => Err(StoreError::WrongType),
            },
            None => Ok(0),
        }
    }

    pub fn lrange(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
    ) -> Result<Vec<Vec<u8>>, StoreError> {
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(Vec::new());
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        let s = normalize_index(start, len).max(0);
                        let e = normalize_index(stop, len).min(len - 1);
                        if s > e || s >= len || e < 0 {
                            return Ok(Vec::new());
                        }
                        let s = s as usize;
                        let e = e as usize;
                        // (frankenredis-3r9lz) Seek to `s` at the chunk level
                        // (O(s/chunk)) instead of an O(s) element-by-element skip.
                        let result: Vec<Vec<u8>> =
                            l.iter_from(s).take(e - s + 1).map(<[u8]>::to_vec).collect();
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(Vec::new()),
        }
    }

    /// Borrow-scan variant of `lrange` for the zero-copy reply fast path: IDENTICAL
    /// bookkeeping and index normalization to `lrange` (keyspace hit/miss, LFU bump
    /// before the type check, chunk-level `iter_from` seek, `touch` only on a
    /// non-empty in-range result) but drives a single `SmembersScanEvent` sink —
    /// `Len(count)` then one `Member(&[u8])` per element by borrow — so the runtime
    /// encodes straight into the output buffer with no `Vec<Vec<u8>>`/`Vec<RespFrame>`
    /// materialization. Emits `Len(0)` (no members, no touch) for missing keys and
    /// out-of-range windows, matching `lrange`'s empty reply; `Err(WrongType)` for a
    /// non-list value. (frankenredis: LRANGE borrow-encode)
    pub fn lrange_borrow_scan(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
        mut sink: impl FnMut(SmembersScanEvent<'_>),
    ) -> Result<(), StoreError> {
        // (CrimsonHawk) Non-LFU single-lookup collapse — see `scard`. Byte-identical.
        if !self.lfu_tracking_enabled() {
            return match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => match &entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        let s = normalize_index(start, len).max(0);
                        let e = normalize_index(stop, len).min(len - 1);
                        if s > e || s >= len || e < 0 {
                            sink(SmembersScanEvent::Len(0));
                            return Ok(());
                        }
                        let s = s as usize;
                        let e = e as usize;
                        sink(SmembersScanEvent::Len(e - s + 1));
                        for m in l.iter_from(s).take(e - s + 1) {
                            sink(SmembersScanEvent::Member(m));
                        }
                        entry.touch(now_ms);
                        Ok(())
                    }
                    _ => Err(StoreError::WrongType),
                },
                None => {
                    sink(SmembersScanEvent::Len(0));
                    Ok(())
                }
            };
        }
        if !self.record_keyspace_lookup(key, now_ms) {
            sink(SmembersScanEvent::Len(0));
            return Ok(());
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        let s = normalize_index(start, len).max(0);
                        let e = normalize_index(stop, len).min(len - 1);
                        if s > e || s >= len || e < 0 {
                            sink(SmembersScanEvent::Len(0));
                            return Ok(());
                        }
                        let s = s as usize;
                        let e = e as usize;
                        sink(SmembersScanEvent::Len(e - s + 1));
                        for m in l.iter_from(s).take(e - s + 1) {
                            sink(SmembersScanEvent::Member(m));
                        }
                        entry.touch(now_ms);
                        Ok(())
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => {
                sink(SmembersScanEvent::Len(0));
                Ok(())
            }
        }
    }

    pub fn lindex(
        &mut self,
        key: &[u8],
        index: i64,
        now_ms: u64,
    ) -> Result<Option<Vec<u8>>, StoreError> {
        // (frankenredis-9s4ls sibling) NO-STAT drop_if_expired: both production
        // callers (the generic lindexCommand and the borrowed fast path) already
        // record the single keyspace hit/miss via the store.key_type precheck
        // run for the lidxorder WRONGTYPE-before-index-parse precedence, so a
        // counting lookup here double-bumped keyspace_hits for a present list.
        if !self.drop_if_expired(key, now_ms) {
            return Ok(None);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        if index < -len || index >= len {
                            return Ok(None);
                        }
                        let idx = normalize_index(index, len) as usize;
                        let result = l.get(idx).map(<[u8]>::to_vec);
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(None),
        }
    }

    /// Zero-copy LINDEX: borrows the addressed list element (or `None` for a
    /// missing key / out-of-range index) into the closure instead of
    /// `l.get(idx).map(<[u8]>::to_vec)`, letting the runtime `_into` fast path
    /// encode straight into the write buffer (skips the per-read element `Vec`
    /// alloc + a second copy). Side effects (no-stat `drop_if_expired`, LFU bump,
    /// touch-only-on-valid-index) match `lindex` exactly. (TealHeron — zero-copy
    /// `_into` migration vein)
    pub fn lindex_with<R>(
        &mut self,
        key: &[u8],
        index: i64,
        now_ms: u64,
        f: impl FnOnce(Option<&[u8]>) -> R,
    ) -> Result<R, StoreError> {
        if !self.drop_if_expired(key, now_ms) {
            return Ok(f(None));
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                let idx = match &entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        if index < -len || index >= len {
                            return Ok(f(None));
                        }
                        normalize_index(index, len) as usize
                    }
                    _ => return Err(StoreError::WrongType),
                };
                entry.touch(now_ms);
                let Value::List(l) = &entry.value else {
                    unreachable!("value type cannot change between borrows")
                };
                Ok(f(l.get(idx)))
            }
            None => Ok(f(None)),
        }
    }

    pub fn lset(
        &mut self,
        key: &[u8],
        index: i64,
        value: Vec<u8>,
        now_ms: u64,
    ) -> Result<(), StoreError> {
        // (CrimsonHawk) Skip the always-2-lookup drop_if_expired when no key has a TTL
        // (the entry access below re-probes entries). Byte-identical; see sadd.
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        // Upstream lsetCommand runs the listpack→quicklist
                        // GROWING conversion (with the new value) BEFORE the
                        // index range check, so an LSET on a full listpack node
                        // stickily converts even when the index is out of range.
                        // (frankenredis-lsetql)
                        l.note_lset_grow(value.len() as u64, self.list_max_listpack_size);
                        if index < -len || index >= len {
                            return Err(StoreError::IndexOutOfRange);
                        }
                        let idx = normalize_index(index, len) as usize;
                        l.set(idx, value);
                        Self::mark_digest_stale_fields(
                            &mut self.digest_stale,
                            &mut self.digest_mutations,
                        );
                        entry.touch_write(now_ms, lfu_tracking_enabled);
                        self.dirty = self.dirty.saturating_add(1);
                        Ok(())
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Err(StoreError::KeyNotFound),
        }
    }

    pub fn lpos(
        &mut self,
        key: &[u8],
        element: &[u8],
        now_ms: u64,
    ) -> Result<Option<usize>, StoreError> {
        // (CrimsonHawk) Non-LFU single-lookup collapse — see `scard`. Byte-identical.
        if !self.lfu_tracking_enabled() {
            return match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => match &entry.value {
                    Value::List(l) => {
                        let result = l.iter().position(|v| v == element);
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                },
                None => Ok(None),
            };
        }
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(None);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::List(l) => {
                        let result = l.iter().position(|v| v == element);
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(None),
        }
    }

    /// LPOS with RANK, COUNT, and MAXLEN support.
    /// rank: 1-based rank of match (positive=head-to-tail, negative=tail-to-head). 0 is invalid.
    /// count: if Some(0) return all matches; if Some(n) return up to n; if None return first match only.
    /// maxlen: limit scan to first/last maxlen entries.
    pub fn lpos_full(
        &mut self,
        key: &[u8],
        element: &[u8],
        rank: i64,
        count: Option<u64>,
        maxlen: usize,
        now_ms: u64,
    ) -> Result<Vec<usize>, StoreError> {
        // (frankenredis-lposmiss) LPOS is a keyspace read: upstream t_list.c::
        // lposCommand uses lookupKeyReadOrReply, so a hit/miss must be recorded
        // for INFO `keyspace_hits`/`keyspace_misses`. lpos_full previously only
        // dropped expired keys without accounting (record_keyspace_lookup wraps
        // drop_if_expired and adds the hit/miss bump), so LPOS — both the generic
        // and the borrowed fast path, which share this backend — never moved the
        // counters. A missing key returns the empty result, as before.
        // (CrimsonHawk) Acquire the live entry in ONE keyspace lookup on the non-LFU fast
        // path (`lookup_live_for_read_mut` folds `record_keyspace_lookup` + `get_mut`), LFU
        // path verbatim, then run the RANK/COUNT scan ONCE (no body duplication).
        // Byte-identical: same key lazy-expiry, hit/miss, single touch, WRONGTYPE, results.
        let entry = if !self.lfu_tracking_enabled() {
            match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => entry,
                None => return Ok(Vec::new()),
            }
        } else {
            if !self.record_keyspace_lookup(key, now_ms) {
                return Ok(Vec::new());
            }
            let lfu_decay = self.lfu_decay_time;
            let lfu_log_factor = self.lfu_log_factor;
            let rand_sample = if self.entries.contains_key(key) {
                self.next_rand()
            } else {
                0
            };
            match self.entries.get_mut(key) {
                Some(entry) => {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                    entry
                }
                None => return Ok(Vec::new()),
            }
        };
        match &entry.value {
            Value::List(l) => {
                let len = l.len();
                let limit = if maxlen == 0 { len } else { maxlen.min(len) };
                let max_results = match count {
                    Some(0) => usize::MAX,
                    Some(n) => n as usize,
                    None => 1,
                };
                let mut results = Vec::new();
                let abs_rank = rank.unsigned_abs() as usize;
                let skip = if abs_rank > 0 { abs_rank - 1 } else { 0 };
                let mut matched = 0_usize;

                if rank >= 0 {
                    // Forward scan
                    for (i, item) in l.iter().enumerate().take(limit) {
                        if item == element {
                            matched += 1;
                            if matched > skip {
                                results.push(i);
                                if results.len() >= max_results {
                                    break;
                                }
                            }
                        }
                    }
                } else {
                    // (frankenredis-gjyzr) Reverse scan the last `limit`
                    // elements via the chunk-level reverse iterator —
                    // O(limit) instead of an O(limit*chunks) get(i)-per-
                    // index walk on a quicklist. `i` descends from len-1.
                    let mut i = len;
                    for item in l.iter_rev().take(limit) {
                        i -= 1;
                        if item == element {
                            matched += 1;
                            if matched > skip {
                                results.push(i);
                                if results.len() >= max_results {
                                    break;
                                }
                            }
                        }
                    }
                }
                entry.touch(now_ms);
                Ok(results)
            }
            _ => Err(StoreError::WrongType),
        }
    }

    pub fn linsert_before(
        &mut self,
        key: &[u8],
        pivot: &[u8],
        value: Vec<u8>,
        now_ms: u64,
    ) -> Result<i64, StoreError> {
        // (CrimsonHawk) Skip the always-2-lookup drop_if_expired when no key has a TTL
        // (the entry access below re-probes entries). Byte-identical; see sadd.
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::List(l) => {
                        if let Some(pos) = l.iter().position(|v| v == pivot) {
                            let lp_pre = l.listpack_byte_len();
                            let raw_add = value.len() as u64;
                            l.insert(pos, value);
                            l.note_command_grow(lp_pre, raw_add, self.list_max_listpack_size);
                            let len = l.len();
                            Self::mark_digest_stale_fields(
                                &mut self.digest_stale,
                                &mut self.digest_mutations,
                            );
                            entry.touch_write(now_ms, lfu_tracking_enabled);
                            self.dirty = self.dirty.saturating_add(1);
                            Ok(len as i64)
                        } else {
                            Ok(-1)
                        }
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(0),
        }
    }

