    pub fn lrem(
        &mut self,
        key: &[u8],
        count: i64,
        value: &[u8],
        now_ms: u64,
    ) -> Result<u64, StoreError> {
        // (CrimsonHawk) Skip the always-2-lookup drop_if_expired when no key has a TTL
        // (the entry access below re-probes entries). Byte-identical; see sadd.
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::List(l) => {
                        // (frankenredis-387i6) For a small bounded count, redis
                        // stops after `count` matches; fr's retain visited every
                        // element AND on_remove_bulk re-scanned the whole list to
                        // recompute lp_bytes — O(n) regardless of count. Early-stop
                        // the find and remove by index (ListValue::remove is
                        // incremental), so LREM of a few near the front/back is
                        // O(pos + count) not O(n). Large count / count==0 keep the
                        // single-pass retain (O(n), the right complexity there).
                        const LREM_INDEX_REMOVE_MAX: usize = 128;
                        let mut removed = 0_u64;
                        if count > 0 && (count as usize) <= LREM_INDEX_REMOVE_MAX {
                            let limit = count as usize;
                            let mut idxs: Vec<usize> = Vec::with_capacity(limit);
                            for (i, v) in l.iter().enumerate() {
                                if v == value {
                                    idxs.push(i);
                                    if idxs.len() >= limit {
                                        break;
                                    }
                                }
                            }
                            for &i in idxs.iter().rev() {
                                l.remove(i);
                            }
                            removed = idxs.len() as u64;
                        } else if count < 0
                            && count.unsigned_abs() as usize <= LREM_INDEX_REMOVE_MAX
                        {
                            let limit = count.unsigned_abs() as usize;
                            let len = l.len();
                            // iter_rev yields back-to-front, so the collected
                            // indices descend — remove them in that order.
                            let mut idxs: Vec<usize> = Vec::with_capacity(limit);
                            for (k, v) in l.iter_rev().enumerate() {
                                if v == value {
                                    idxs.push(len - 1 - k);
                                    if idxs.len() >= limit {
                                        break;
                                    }
                                }
                            }
                            for &i in &idxs {
                                l.remove(i);
                            }
                            removed = idxs.len() as u64;
                        } else if count > 0 {
                            let limit = count as u64;
                            l.retain(|v| {
                                if removed < limit && v == value {
                                    removed += 1;
                                    false
                                } else {
                                    true
                                }
                            });
                        } else if count < 0 {
                            let limit = count.unsigned_abs();
                            let total = l.iter().filter(|v| *v == value).count() as u64;
                            let skip = total.saturating_sub(limit);
                            let mut seen = 0_u64;
                            l.retain(|v| {
                                if v == value {
                                    seen += 1;
                                    if seen > skip {
                                        removed += 1;
                                        return false;
                                    }
                                }
                                true
                            });
                        } else {
                            let old_len = l.len();
                            if l.iter().any(|v| v == value) {
                                l.retain(|v| v != value);
                                removed = (old_len - l.len()) as u64;
                            }
                        }
                        if removed > 0 {
                            self.dirty = self.dirty.saturating_add(removed);
                            if l.is_empty() {
                                self.internal_entries_remove(key);
                                self.stream_groups.remove(key);
                                self.stream_last_ids.remove(key);
                            } else {
                                Self::mark_digest_stale_fields(
                                    &mut self.digest_stale,
                                    &mut self.digest_mutations,
                                );
                                entry.touch_write(now_ms, lfu_tracking_enabled);
                            }
                        }
                        Ok(removed)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(0),
        }
    }

    pub fn rpoplpush(
        &mut self,
        source: &[u8],
        destination: &[u8],
        now_ms: u64,
    ) -> Result<Option<Vec<u8>>, StoreError> {
        // (CrimsonHawk) Guard the two bare drops on `expires_count != 0`: with no volatile keys
        // neither source nor destination can be expired, so both drops are no-ops; the get(source)
        // + destination lookup below re-probe. Byte-identical. (RPOPLPUSH / LMOVE — reliable queues.)
        if self.expires_count != 0 {
            self.drop_if_expired(source, now_ms);
            self.drop_if_expired(destination, now_ms);
        }

        match self.entries.get(source) {
            Some(entry) => {
                if !matches!(&entry.value, Value::List(_)) {
                    return Err(StoreError::WrongType);
                }
            }
            None => return Ok(None),
        }
        if source != destination
            && let Some(entry) = self.entries.get(destination)
            && !matches!(&entry.value, Value::List(_))
        {
            return Err(StoreError::WrongType);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();

        // Pop from source
        let popped = match self.entries.get_mut(source) {
            Some(entry) => match &mut entry.value {
                Value::List(l) => {
                    let val = l.pop_back();
                    if val.is_some() && !l.is_empty() {
                        Self::mark_digest_stale_fields(
                            &mut self.digest_stale,
                            &mut self.digest_mutations,
                        );
                        entry.touch_write(now_ms, lfu_tracking_enabled);
                    }
                    val
                }
                _ => return Err(StoreError::WrongType),
            },
            None => return Ok(None),
        };
        let Some(val) = popped else {
            return Ok(None);
        };

        let mut source_ttl = None;
        if source == destination {
            source_ttl = self.expiry_ms(source);
        }

        // Clean up empty source.
        if let Some(entry) = self.entries.get(source)
            && let Value::List(l) = &entry.value
            && l.is_empty()
        {
            self.internal_entries_remove(source);
            self.stream_groups.remove(source);
            self.stream_last_ids.remove(source);
        }

        // Push to destination
        match self.entries.get_mut(destination) {
            Some(entry) => match &mut entry.value {
                Value::List(l) => {
                    let lp_pre = l.listpack_byte_len();
                    l.push_front(val.clone());
                    l.note_command_grow(lp_pre, val.len() as u64, self.list_max_listpack_size);
                    Self::mark_digest_stale_fields(
                        &mut self.digest_stale,
                        &mut self.digest_mutations,
                    );
                    entry.touch_write(now_ms, lfu_tracking_enabled);
                }
                _ => return Err(StoreError::WrongType),
            },
            None => {
                let mut l = ListValue::default();
                l.push_front(val.clone());
                l.note_command_grow(
                    ListValue::empty_listpack_bytes(),
                    val.len() as u64,
                    self.list_max_listpack_size,
                );
                self.internal_entries_insert_with_expiry(
                    destination.to_vec(),
                    Entry::new(Value::List(Box::new(l)), now_ms),
                    source_ttl,
                );
            }
        }
        self.dirty = self.dirty.saturating_add(1);
        Ok(Some(val))
    }

    pub fn ltrim(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
    ) -> Result<(), StoreError> {
        // (CrimsonHawk) Guard the bare drop_if_expired on `expires_count != 0`: when nothing is
        // volatile no key can be expired, so drop is a pure no-op; the lookup below re-probes.
        // Byte-identical. (LTRIM — common capped-list/bounded-log pattern.)
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        // Set when the command was a valid LTRIM on an existing list that
        // removed NOTHING (range covered the whole list). Upstream ltrimCommand
        // still fires "ltrim" + signalModifiedKey unconditionally in that case
        // (server.dirty is NOT bumped, so the dirty-gated keyspace dispatcher
        // would miss it); fire the event here after the entry borrow ends.
        let mut noop_ltrim_on_list = false;
        let result = match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::List(l) => {
                        let len = l.len() as i64;
                        let s = normalize_index(start, len).max(0);
                        let e = normalize_index(stop, len).min(len - 1);
                        let old_len = l.len();
                        if s > e || s >= len || e < 0 {
                            l.clear();
                        } else {
                            let s = s as usize;
                            let e = e as usize;
                            for _ in 0..s {
                                l.pop_front();
                            }
                            while l.len() > (e - s + 1) {
                                l.pop_back();
                            }
                        }
                        let removed = old_len - l.len();
                        if l.is_empty() {
                            self.internal_entries_remove(key);
                            self.stream_groups.remove(key);
                            self.stream_last_ids.remove(key);
                        } else if removed > 0 {
                            Self::mark_digest_stale_fields(
                                &mut self.digest_stale,
                                &mut self.digest_mutations,
                            );
                            entry.touch_write(now_ms, lfu_tracking_enabled);
                        } else {
                            noop_ltrim_on_list = true;
                        }
                        if removed > 0 {
                            self.dirty = self.dirty.saturating_add(removed as u64);
                        }
                        Ok(())
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(()),
        };
        if noop_ltrim_on_list {
            let (db, logical_key) = match decode_db_key(key) {
                Some((db, lk)) => (db, lk.to_vec()),
                None => (0, key.to_vec()),
            };
            self.notify_keyspace_event(NOTIFY_LIST, "ltrim", &logical_key, db);
        }
        result
    }

    pub fn lpushx(
        &mut self,
        key: &[u8],
        values: &[Vec<u8>],
        now_ms: u64,
    ) -> Result<usize, StoreError> {
        // (CrimsonHawk) Skip the always-2-lookup drop_if_expired when no key has a TTL
        // (the entry access below re-probes entries). Byte-identical; see sadd.
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::List(l) => {
                        let lp_pre = l.listpack_byte_len();
                        let mut raw_add = 0u64;
                        for v in values {
                            raw_add += v.len() as u64;
                            l.push_front(v.clone());
                        }
                        l.note_command_grow(lp_pre, raw_add, self.list_max_listpack_size);
                        let len = l.len();
                        if !values.is_empty() {
                            Self::mark_digest_stale_fields(
                                &mut self.digest_stale,
                                &mut self.digest_mutations,
                            );
                            // (frankenredis-lpushx-dirty) LPUSHX mutates the
                            // list, so it must update the write time and bump
                            // dirty — otherwise the push is invisible to
                            // RDB/AOF persistence, replication, and keyspace
                            // notifications (all gate on dirty changing).
                            entry.touch_write(now_ms, lfu_tracking_enabled);
                            self.dirty = self.dirty.saturating_add(values.len() as u64);
                        }
                        Ok(len)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(0),
        }
    }

