    /// (CrimsonHawk) `ZRANK`/`ZREVRANK key member WITHSCORE` — returns `(rank, score)`
    /// from a SINGLE keyspace lookup + single zset traversal. The previous handler called
    /// `zrank` then `zmscore`, doubling both the `entries` probe and the member lookup;
    /// since `rank` already decodes the score to form the rank-tree key, this folds the
    /// two into one. Stat accounting mirrors `zrank` exactly (one `record_keyspace_lookup`).
    pub fn zrank_withscore(
        &mut self,
        key: &[u8],
        member: &[u8],
        reverse: bool,
        now_ms: u64,
    ) -> Result<Option<(usize, f64)>, StoreError> {
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(None);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::SortedSet(zs) => {
                        let res = if reverse {
                            zs.rev_rank_with_score(member)
                        } else {
                            zs.rank_with_score(member)
                        };
                        entry.touch(now_ms);
                        Ok(res)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(None),
        }
    }

    /// Return elements sorted ascending by score, by index range.
    pub fn zrange(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
    ) -> Result<Vec<Vec<u8>>, StoreError> {
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(Vec::new());
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::SortedSet(zs) => {
                        let len = zs.len() as i64;
                        let s = normalize_index(start, len);
                        let e = normalize_index(stop, len);
                        if s > e || s >= len || e < 0 {
                            return Ok(Vec::new());
                        }
                        let s_idx = s.max(0) as usize;
                        let e_idx = e.min(len - 1) as usize;
                        let count = e_idx - s_idx + 1;
                        let result: Vec<Vec<u8>> = zs
                            .index_slice_asc_adaptive(s_idx, count)
                            .into_iter()
                            .map(|(m, _)| m)
                            .collect();
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(Vec::new()),
        }
    }

    /// (frankenredis-zrange-into) Borrow-scan variant of [`Store::zrange`] (plain,
    /// no WITHSCORES) for the zero-copy reply fast path: IDENTICAL bookkeeping to
    /// `zrange` — keyspace hit/miss, unconditional-on-found LFU bump, `touch` ONLY
    /// on a non-empty range, and the same `normalize_index` range math — but drives
    /// a single `SmembersScanEvent` sink (`Len(count)` then one borrowed
    /// `Member(&[u8])` per member in ascending rank order) so the runtime encodes
    /// the `*N` array straight into the output buffer with no
    /// `Vec<Vec<u8>>`/`Vec<RespFrame>` materialization. The member CLONE is the
    /// dominant ZRANGE cost (measured 2.6-4.6x on the member-copy work); this walks
    /// the ordered set by borrow via `iter_asc().skip(s).take(count)`. The linear
    /// skip stays cheaper than the adaptive treap-seek + clone even at mid-offset
    /// (probe: 2.62x at start=N/2), so there is no large-offset regression vs the
    /// owned path. `Len(0)` for a missing / out-of-range / empty result;
    /// `Err(WrongType)` for a non-zset value (after the LFU bump, matching `zrange`).
    pub fn zrange_borrow_scan(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
        mut sink: impl FnMut(SmembersScanEvent<'_>),
    ) -> Result<(), StoreError> {
        // (CrimsonHawk) Unified-acquire single-lookup collapse — see `lpos_full`. The
        // member-borrow vein avoided the member CLONE but left `record_keyspace_lookup` + a
        // separate `get_mut` (two key hashes); fold to one `lookup_live_for_read_mut` on the
        // non-LFU path, LFU verbatim, range body once. Byte-identical (lazy-expiry, hit/miss,
        // single touch, WRONGTYPE, empty-range Len(0), member stream).
        let entry = if !self.lfu_tracking_enabled() {
            match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => entry,
                None => {
                    sink(SmembersScanEvent::Len(0));
                    return Ok(());
                }
            }
        } else {
            if !self.record_keyspace_lookup(key, now_ms) {
                sink(SmembersScanEvent::Len(0));
                return Ok(());
            }
            let lfu_decay = self.lfu_decay_time;
            let lfu_log_factor = self.lfu_log_factor;
            let rand_sample = if self.entries.contains_key(key) {
                self.next_rand()
            } else {
                0
            };
            match self.entries.get_mut(key) {
                Some(entry) => {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                    entry
                }
                None => {
                    sink(SmembersScanEvent::Len(0));
                    return Ok(());
                }
            }
        };
        match &entry.value {
            Value::SortedSet(zs) => {
                let len = zs.len() as i64;
                let s = normalize_index(start, len);
                let e = normalize_index(stop, len);
                if s > e || s >= len || e < 0 {
                    sink(SmembersScanEvent::Len(0));
                    return Ok(());
                }
                let s_idx = s.max(0) as usize;
                let e_idx = e.min(len - 1) as usize;
                let count = e_idx - s_idx + 1;
                sink(SmembersScanEvent::Len(count));
                for (m, _score) in zs.iter_asc().skip(s_idx).take(count) {
                    sink(SmembersScanEvent::Member(m));
                }
                entry.touch(now_ms);
                Ok(())
            }
            _ => Err(StoreError::WrongType),
        }
    }

    /// (frankenredis-zrange-into) Borrow-scan variant of [`Store::zrevrange`] — the
    /// descending twin of [`Store::zrange_borrow_scan`]. IDENTICAL bookkeeping to
    /// `zrevrange` (keyspace hit/miss, unconditional-on-found LFU bump, `touch` ONLY
