    /// Create or overwrite a sorted set from member-score pairs.
    pub fn zstore_from_pairs(
        &mut self,
        key: Vec<u8>,
        pairs: Vec<(Vec<u8>, f64)>,
        force_skiplist: bool,
        now_ms: u64,
    ) {
        // (frankenredis-zsetbulk) ZRANGESTORE source is a zset range, so `pairs`
        // has unique members — bulk-build the dest in one O(n) BTreeMap pass
        // instead of N incremental inserts. The force_skiplist flag below sets
        // the Entry encoding flag and is independent of the SortedSet storage.
        let zset_max_entries = self.zset_max_listpack_entries;
        let zset_max_value = self.zset_max_listpack_value;
        let zs = SortedSet::from_unique_pairs_with_limits(pairs, zset_max_entries, zset_max_value);
        self.stream_groups.remove(key.as_slice());
        self.stream_last_ids.remove(key.as_slice());
        let mut entry = Entry::new(Value::SortedSet(Box::new(zs)), now_ms);
        // (frankenredis-t8rma) Upstream ZRANGESTORE pre-creates the destination
        // via zsetTypeCreate(length, 0). For BYSCORE / BYLEX the result count is
        // unknown so upstream passes length = -1, which as size_t is SIZE_MAX and
        // always exceeds zset_max_listpack_entries — so the destination is created
        // (and stays) skiplist-encoded regardless of how few members actually
        // match. Rank mode passes the exact count, so its encoding derives
        // naturally (handled by the live OBJECT ENCODING derivation). Mirror the
        // forced-skiplist sizing here so OBJECT ENCODING matches byte-for-byte.
        if force_skiplist {
            entry.set_flag(ENTRY_FORCE_ZSET_SKIPLIST_ENCODING, true);
        } else {
            // (frankenredis-v4ba8) Rank-mode ZRANGESTORE: re-derive listpack vs
            // skiplist from the result content. Post-a0p5p OBJECT ENCODING reads
            // the sticky flag only, so the stale "derives naturally" assumption
            // left an over-threshold rank result reporting listpack.
            Self::refresh_zset_encoding_flag(&mut entry, zset_max_entries, zset_max_value);
        }
        self.internal_entries_insert(key, entry);
        // (frankenredis-bhd3u) Writing the destination set is a keyspace
        // mutation — bump dirty so ZRANGESTORE is persisted to RDB/AOF,
        // replicated, and surfaces keyspace notifications (all gate on the
        // dirty counter changing). Only caller is zrangestore_cmd.
        self.dirty = self.dirty.saturating_add(1);
    }

    /// Count members with scores within the given bounds.
    pub fn zcount(
        &mut self,
        key: &[u8],
        min: ScoreBound,
        max: ScoreBound,
        now_ms: u64,
    ) -> Result<usize, StoreError> {
        // (CrimsonHawk) Non-LFU single-lookup collapse — see `scard`. The inverted-bounds
        // early-return is kept INSIDE the hit branch (before the type check), byte-for-byte
        // matching the slow path's order: an inverted range on a present key returns 0 after
        // recording the hit, without touching or checking the value type. LFU path verbatim.
        if !self.lfu_tracking_enabled() {
            return match self.lookup_live_for_read_mut(key, now_ms) {
                Some(entry) => {
                    if score_bound_value(min) > score_bound_value(max) {
                        return Ok(0);
                    }
                    match &mut entry.value {
                        Value::SortedSet(zs) => {
                            let result = zs.score_bound_count_adaptive(min, max);
                            entry.touch(now_ms);
                            Ok(result)
                        }
                        _ => Err(StoreError::WrongType),
                    }
                }
                None => Ok(0),
            };
        }
        if !self.record_keyspace_lookup(key, now_ms) {
            return Ok(0);
        }
        // (frankenredis-xc0ty) Inverted score bounds (min > max) make
        // the resulting BTreeMap::range start > end, which panics
        // with 'range start is greater than range end in BTreeMap' —
        // a trivial DoS triggerable by any client via
        // `ZCOUNT key +inf -inf`. Upstream zsetzCount returns 0 for
        // inverted ranges since the result set is empty by definition.
        // zrangebyscore / zrangebyscore_withscores already have this
        // guard; mirror it here.
        if score_bound_value(min) > score_bound_value(max) {
            return Ok(0);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::SortedSet(zs) => {
                        let result = zs.score_bound_count_adaptive(min, max);
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(0),
        }
    }

    /// Increment score of member by delta. Creates member with delta as score if absent.
    pub fn zincrby(
        &mut self,
        key: &[u8],
        member: Vec<u8>,
        delta: f64,
        now_ms: u64,
    ) -> Result<f64, StoreError> {
        self.zincrby_with_options(key, member, delta, ZaddOptions::default(), now_ms)
            .map(|opt| opt.unwrap_or(0.0)) // ZINCRBY without options always succeeds
    }

    /// Increment score of member by delta, respecting ZADD options (NX, XX, GT, LT).
    /// Returns None if the operation was aborted due to options.
    pub fn zincrby_with_options(
        &mut self,
        key: &[u8],
        member: Vec<u8>,
        delta: f64,
        opts: ZaddOptions,
        now_ms: u64,
    ) -> Result<Option<f64>, StoreError> {
        // (CrimsonHawk) Guard the bare drop_if_expired on `expires_count != 0` — see `zadd`.
        // Byte-identical (return discarded; no volatile key ⇒ nothing to evict).
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }

        let key_existed = self.entries.contains_key(key);
        if opts.xx && !key_existed {
            return Ok(None);
        }

        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && key_existed {
            self.next_rand()
        } else {
            0
        };

        let zset_max_entries = self.zset_max_listpack_entries;
        let zset_max_value = self.zset_max_listpack_value;
        let (res, is_empty, touched) = {
            let entry =
                self.internal_entry(key, || Value::SortedSet(Box::new(SortedSet::new())), now_ms);
            if lfu_tracking_enabled && key_existed {
                entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
            }
            let Value::SortedSet(zs) = &mut entry.value else {
                return Err(StoreError::WrongType);
            };

            let old_score = zs.get_score(&member);

            let res = if (opts.nx && old_score.is_some()) || (opts.xx && old_score.is_none()) {
                Ok(None)
            } else {
                // (frankenredis-zincrnegzero) Upstream zaddGenericCommand in INCR
                // mode sets a NEW member's score to the increment DIRECTLY (not
                // `0 + incr`), so a `-0` increment yields a `-0` reply (while the
                // STORED score is canonicalized to `+0` by insert_with_limits, so
                // ZSCORE still returns `0`). `0.0 + delta` is the additive
                // identity for every double EXCEPT `-0.0`, where IEEE gives
                // `0.0 + (-0.0) = +0.0` — collapsing the sign and diverging from
                // redis only in that one case. Compute old+delta for existing
                // members; use delta verbatim for new members.
                let new_score = match old_score {
                    Some(old) => old + delta,
                    None => delta,
                };

                if new_score.is_nan() {
                    Err(StoreError::IncrFloatNaN)
                } else if let Some(old) = old_score {
                    if (opts.gt && new_score <= old) || (opts.lt && new_score >= old) {
                        Ok(None)
                    } else {
                        zs.insert_with_limits(member, new_score, zset_max_entries, zset_max_value);
                        Ok(Some(new_score))
                    }
                } else {
                    zs.insert_with_limits(member, new_score, zset_max_entries, zset_max_value);
                    Ok(Some(new_score))
                }
            };
            let is_empty = zs.is_empty();
            let touched = matches!(&res, Ok(Some(_)));
            if touched {
                entry.touch_write(now_ms, lfu_tracking_enabled);
                // (frankenredis-yp503) Crossing the entries count via
                // zincrby on a new member can promote to skiplist.
                Self::refresh_zset_encoding_flag(entry, zset_max_entries, zset_max_value);
            }
            (res, is_empty, touched)
        };

        if touched {
            Self::mark_digest_stale_fields(&mut self.digest_stale, &mut self.digest_mutations);
            self.dirty = self.dirty.saturating_add(1);
        }
        if is_empty {
            self.internal_entries_remove(key);
        }
        res
    }

    /// Remove and return the member with the lowest score.
    pub fn zpopmin(
        &mut self,
        key: &[u8],
        now_ms: u64,
    ) -> Result<Option<(Vec<u8>, f64)>, StoreError> {
        // (frankenredis-byq16) Skip the redundant second keyspace lookup on the
        // missing/expired-key path. `drop_if_expired` already probed `entries`
        // and reports presence; when the key is absent the `entries.get_mut`
        // below can only return None, so early-returning here is byte-identical
        // to the get_mut-else-None arm. Mirrors `Store::spop`'s
        // `if !self.drop_if_expired { return Ok(None); }` guard. RNG state is
        // unchanged: `next_rand()` is only reached when the key exists.
        // (CrimsonHawk) `expires_count != 0 &&` short-circuit: when nothing is volatile the
        // key can't be expired, so skip the drop probe entirely — the `get_mut`-else-None
        // below serves the missing case identically (byq16's early-return was already
        // byte-identical to it). Net: 2 probes → 1 on the common present/no-TTL pop.
        if self.expires_count != 0 && !self.drop_if_expired(key, now_ms) {
            return Ok(None);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        let Some(entry) = self.entries.get_mut(key) else {
            return Ok(None);
        };
        if lfu_tracking_enabled {
            entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
        }
        let Value::SortedSet(zs) = &mut entry.value else {
            return Err(StoreError::WrongType);
        };
        let result = zs.pop_min();
        let is_empty = zs.is_empty();
        if result.is_some() {
            self.dirty = self.dirty.saturating_add(1);
            if is_empty {
                self.internal_entries_remove(key);
                self.stream_groups.remove(key);
                self.stream_last_ids.remove(key);
            } else {
                Self::mark_digest_stale_fields(&mut self.digest_stale, &mut self.digest_mutations);
                entry.touch_write(now_ms, lfu_tracking_enabled);
            }
        }
        Ok(result)
    }

