    /// Return range with scores (ascending order by score).
    pub fn zrange_withscores(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
    ) -> Result<Vec<(Vec<u8>, f64)>, StoreError> {
        self.drop_if_expired(key, now_ms);
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &mut entry.value {
                    Value::SortedSet(zs) => {
                        let len = zs.len() as i64;
                        let s = normalize_index(start, len);
                        let e = normalize_index(stop, len);
                        if s > e || s >= len || e < 0 {
                            return Ok(Vec::new());
                        }
                        let s_idx = s.max(0) as usize;
                        let e_idx = e.min(len - 1) as usize;
                        let count = e_idx - s_idx + 1;
                        let result: Vec<(Vec<u8>, f64)> = zs.index_slice_asc_adaptive(s_idx, count);
                        entry.touch(now_ms);
                        Ok(result)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(Vec::new()),
        }
    }

    /// (frankenredis-zrange-into) Borrow-scan variant of [`Store::zrange_withscores`]
    /// for the WITHSCORES zero-copy reply fast path: byte-identical bookkeeping to
    /// `zrange_withscores` (the SAME `drop_if_expired`, LFU bump, `touch`-only-on-
    /// non-empty-range, and `normalize_index` rank math) but drives a
    /// `ZRangeWithScoresScanEvent` sink — `Len(count)` then one `Pair(&member, score)`
    /// per rank in ascending (score, member) order — so the runtime encodes the
    /// interleaved member/score reply straight into the output buffer with no
    /// `Vec<(Vec<u8>, f64)>` member clone. `Len(0)` for a missing / out-of-range /
    /// empty result; `Err(WrongType)` for a non-zset value.
    pub fn zrange_withscores_borrow_scan(
        &mut self,
        key: &[u8],
        start: i64,
        stop: i64,
        now_ms: u64,
        mut sink: impl FnMut(ZRangeWithScoresScanEvent<'_>),
    ) -> Result<(), StoreError> {
        // (CrimsonHawk) Guard the bare drop_if_expired on `expires_count != 0`: the rank-based
        // ZRANGE WITHSCORES borrow-scan records NO keyspace stat (bare drop), so drop's no-TTL
        // fast-exit `contains_key` is pure overhead when nothing is volatile; `get_mut` below
        // re-probes. Byte-identical (an expired key needs a TTL ⇒ count>0 ⇒ drop runs).
        if self.expires_count != 0 {
            self.drop_if_expired(key, now_ms);
        }
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::SortedSet(zs) => {
                        let len = zs.len() as i64;
                        let s = normalize_index(start, len);
                        let e = normalize_index(stop, len);
                        if s > e || s >= len || e < 0 {
                            sink(ZRangeWithScoresScanEvent::Len(0));
                            return Ok(());
                        }
                        let s_idx = s.max(0) as usize;
                        let e_idx = e.min(len - 1) as usize;
                        let count = e_idx - s_idx + 1;
                        sink(ZRangeWithScoresScanEvent::Len(count));
                        for (member, score) in zs.iter_asc().skip(s_idx).take(count) {
                            sink(ZRangeWithScoresScanEvent::Pair(member, score));
                        }
                        entry.touch(now_ms);
                        Ok(())
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => {
                sink(ZRangeWithScoresScanEvent::Len(0));
                Ok(())
            }
        }
    }

    /// Apply `f` to every (member, score) of the sorted set at `key` in
    /// ascending (score, member) order, borrowing each member instead of
    /// cloning it. Performs exactly the same expiry / LFU / touch bookkeeping as
    /// `zrange_withscores(key, 0, -1, now_ms)`, so a scan-and-filter caller can
    /// clone only the elements it keeps. Returns Ok(true) when the key held a
    /// sorted set, Ok(false) when it was missing/expired, WrongType otherwise.
    /// (frankenredis-5nimj)
    pub fn zset_for_each_asc(
        &mut self,
        key: &[u8],
        now_ms: u64,
        mut f: impl FnMut(&[u8], f64),
    ) -> Result<bool, StoreError> {
        self.drop_if_expired(key, now_ms);
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::SortedSet(zs) => {
                        for (member, score) in zs.iter_asc() {
                            f(member, score);
                        }
                        entry.touch(now_ms);
                        Ok(true)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(false),
        }
    }

    /// Apply `f` to every (member, score) of the sorted set at `key` whose score
    /// falls in any of the inclusive `ranges`, borrowing members. Each range is
    /// walked in ascending order via the ordered index (O(ranges * log n + matched)).
    /// Performs the SAME single expiry / LFU / touch bookkeeping as one
    /// `zrange_withscores(key, 0, -1, now_ms)` (one lookup, one bump, one touch),
    /// so a multi-range scan does not diverge from a single full scan on LFU or
    /// keyspace stats. Returns Ok(true) when the key held a sorted set, Ok(false)
    /// when missing/expired, WrongType otherwise. Caller must ensure ranges are
    /// disjoint to avoid visiting a member twice. (frankenredis-7hg0r)
    pub fn zset_for_each_in_score_ranges(
        &mut self,
        key: &[u8],
        ranges: &[(f64, f64)],
        now_ms: u64,
        mut f: impl FnMut(&[u8], f64),
    ) -> Result<bool, StoreError> {
        self.drop_if_expired(key, now_ms);
        let lfu_tracking_enabled = self.lfu_tracking_enabled();
        let lfu_decay = self.lfu_decay_time;
        let lfu_log_factor = self.lfu_log_factor;
        let rand_sample = if lfu_tracking_enabled && self.entries.contains_key(key) {
            self.next_rand()
        } else {
            0
        };
        match self.entries.get_mut(key) {
            Some(entry) => {
                if lfu_tracking_enabled {
                    entry.bump_lfu_freq(now_ms, lfu_decay, lfu_log_factor, rand_sample);
                }
                match &entry.value {
                    Value::SortedSet(zs) => {
                        for &(lo, hi) in ranges {
                            zs.for_each_in_score_range(lo, hi, &mut f);
                        }
                        entry.touch(now_ms);
                        Ok(true)
                    }
                    _ => Err(StoreError::WrongType),
                }
            }
            None => Ok(false),
        }
    }

