    #[test]
    fn object_refcount_copy_of_shared_int_is_private() {
        // (frankenredis-gt318) Upstream COPY duplicates via dupStringObject,
        // which for an int-encoded value allocates a fresh private object
        // (refcount 1) instead of the interned shared integer. A plain SET of a
        // shared-range int still reports INT_MAX; the COPY destination reports 1
        // (while still OBJECT ENCODING int); and a later int-producing write
        // (INCR/SET) replaces the entry and re-shares it.
        let mut store = Store::new();
        store.set(b"src".to_vec(), b"3".to_vec(), None, 0);
        assert_eq!(store.object_refcount(b"src", 0), Some(i64::from(i32::MAX)));
        assert!(store.copy(b"src", b"dst", false, 0).unwrap());
        assert_eq!(store.object_encoding(b"dst", 0), Some("int"));
        assert_eq!(store.object_refcount(b"dst", 0), Some(1));
        // INCR replaces the entry -> re-shared.
        let _ = store.incr(b"dst", 0).unwrap();
        assert_eq!(store.object_refcount(b"dst", 0), Some(i64::from(i32::MAX)));
        // A non-shared-range int copy is 1 regardless (already was).
        store.set(b"big".to_vec(), b"50000".to_vec(), None, 0);
        assert!(store.copy(b"big", b"bigdst", false, 0).unwrap());
        assert_eq!(store.object_refcount(b"bigdst", 0), Some(1));
    }

    #[test]
    fn copy_large_deque_list_mutations_are_isolated() -> Result<(), StoreError> {
        let mut store = Store::new();
        let values: Vec<Vec<u8>> = (0..160u16)
            .map(|idx| format!("v{idx:03}").into_bytes())
            .collect();
        store.rpush(b"src", &values, 0)?;
        assert!(store.copy(b"src", b"dst", false, 0)?);

        assert_eq!(store.lrange(b"src", 0, -1, 0)?, values);
        assert_eq!(store.lrange(b"dst", 0, -1, 0)?, values);

        store.lpush(b"src", &[b"src-head".to_vec()], 0)?;
        store.rpush(b"src", &[b"src-tail".to_vec()], 0)?;
        store.lset(b"src", 2, b"src-set".to_vec(), 0)?;
        store.linsert_after(b"src", b"v005", b"src-after".to_vec(), 0)?;
        assert_eq!(store.lrem(b"src", 1, b"v010", 0)?, 1);
        assert_eq!(
            store.lrange(b"dst", 0, -1, 0)?,
            values,
            "mutating the copied source must not affect the destination"
        );

        let mut dst_expected = values.clone();
        dst_expected.pop();
        dst_expected.remove(0);
        let _ = store.rpop(b"dst", 0)?;
        let _ = store.lpop(b"dst", 0)?;
        assert_eq!(store.lrange(b"dst", 0, -1, 0)?, dst_expected);
        assert_eq!(store.lindex(b"src", 0, 0)?, Some(b"src-head".to_vec()));
        assert_eq!(store.lindex(b"src", -1, 0)?, Some(b"src-tail".to_vec()));

        store.linsert_before(b"dst", b"v020", b"dst-before".to_vec(), 0)?;
        store.lset(b"dst", 3, b"dst-set".to_vec(), 0)?;
        store.ltrim(b"dst", 1, -2, 0)?;
        assert_eq!(
            store.lrange(b"src", 0, 8, 0)?,
            vec![
                b"src-head".to_vec(),
                b"v000".to_vec(),
                b"src-set".to_vec(),
                b"v002".to_vec(),
                b"v003".to_vec(),
                b"v004".to_vec(),
                b"v005".to_vec(),
                b"src-after".to_vec(),
                b"v006".to_vec(),
            ],
            "mutating the copied destination must not affect the source"
        );
        Ok(())
    }

    #[test]
    fn object_encoding_list_lset_growing_conversion_is_sticky() {
        // (frankenredis-lsetql) Upstream lsetCommand runs the listpack→quicklist
        // GROWING conversion (lpLength + 1 vs the count limit) BEFORE the index
        // range check, and the conversion is sticky. With a count limit of 4 and
        // exactly 4 elements, an LSET — even an out-of-range one — converts to
        // quicklist and STAYS quicklist; with 3 elements it stays listpack.
        let mut store = Store::new();
        store.list_max_listpack_size = 4;

        // count == limit: valid in-range LSET converts (count+1 = 5 > 4).
        let _ = store.rpush(
            b"full",
            &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec(), b"d".to_vec()],
            0,
        );
        assert_eq!(store.object_encoding(b"full", 0), Some("listpack"));
        store.lset(b"full", 0, b"z".to_vec(), 0).unwrap();
        assert_eq!(store.object_encoding(b"full", 0), Some("quicklist"));

        // count == limit, out-of-range LSET errors but STILL converts.
        let _ = store.rpush(
            b"oor",
            &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec(), b"d".to_vec()],
            0,
        );
        assert!(store.lset(b"oor", 100, b"z".to_vec(), 0).is_err());
        assert_eq!(store.object_encoding(b"oor", 0), Some("quicklist"));

        // count < limit: LSET stays listpack (count+1 = 4, not > 4).
        let _ = store.rpush(b"sub", &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec()], 0);
        store.lset(b"sub", 0, b"z".to_vec(), 0).unwrap();
        assert_eq!(store.object_encoding(b"sub", 0), Some("listpack"));
    }

    #[test]
    fn object_encoding_list_shrink_hysteresis_below_half_limit() {
        // (frankenredis-lsetql) A quicklist (grown past the count limit) collapses
        // back to a single listpack node only once it has fallen to at most HALF
        // the limit (LIST_CONV_SHRINKING hysteresis). With limit 4: popping from 5
        // down to 3 stays quicklist (3 > 4/2); down to 2 reverts to listpack.
        let mut store = Store::new();
        store.list_max_listpack_size = 4;
        let _ = store.rpush(
            b"l",
            &[
                b"a".to_vec(),
                b"b".to_vec(),
                b"c".to_vec(),
                b"d".to_vec(),
                b"e".to_vec(),
            ],
            0,
        );
        assert_eq!(store.object_encoding(b"l", 0), Some("quicklist"));
        let _ = store.rpop(b"l", 0);
        let _ = store.rpop(b"l", 0); // -> 3 elements, > 2
        assert_eq!(store.object_encoding(b"l", 0), Some("quicklist"));
        let _ = store.rpop(b"l", 0); // -> 2 elements, <= 2
        assert_eq!(store.object_encoding(b"l", 0), Some("listpack"));
    }

    #[test]
    fn object_encoding_list_honors_legacy_listpack_byte_limit() {
        let mut store = Store::new();
        store.list_max_listpack_size = -1;
        let large = vec![b'x'; 5000];
        let _ = store.rpush(b"list", &[large], 0);

        assert_eq!(store.object_encoding(b"list", 0), Some("quicklist"));
    }

    #[test]
    fn object_encoding_list_keeps_listpack_above_legacy_entry_count() {
        // (frankenredis-llry) Upstream Redis 7.2 has no entries-count
        // gate for the listpack/quicklist transition; the byte budget
        // alone decides. fr historically flipped to quicklist at 129
        // entries (the fr-only `list-max-listpack-entries` default
        // 128). With that gate removed, a 200-element list of
        // single-char values stays as listpack — matching vendored
        // redis 7.2.4 for the same payload.
        let mut store = Store::new();
        let entries: Vec<Vec<u8>> = (0..200u16).map(|i| format!("v{i}").into_bytes()).collect();
        let _ = store.rpush(b"list", &entries, 0);

        assert_eq!(store.object_encoding(b"list", 0), Some("listpack"));

        // (frankenredis-10lqb) The fr-only `list_max_listpack_entries`
        // field has been removed entirely. Vendored Redis 7.2.4 has no
        // entry-count cap for lists — only the byte budget governs the
        // listpack/quicklist transition.

        // Crossing the byte budget still flips to quicklist.
        store.list_max_listpack_size = -2; // 8 KiB
        let big_chunk = vec![b'x'; 10_000];
        let _ = store.rpush(b"list", &[big_chunk], 0);
        assert_eq!(store.object_encoding(b"list", 0), Some("quicklist"));
    }

    /// (frankenredis-rc49s) The incremental `lp_bytes` tracked on the list value
    /// must equal the byte-exact `encode_listpack_strings` length at every step,
    /// across int-width boundaries, string-header boundaries, and through
    /// pushes/pops/sets/inserts/removes/retain. This is the golden proof that the
    /// O(1) tracking is isomorphic to a full re-encode of the contents.
    #[test]
    fn list_lp_bytes_matches_byte_exact_encoder() {
        use crate::packed_set::ListValue;

        let check = |l: &ListValue| {
            let refs: Vec<&[u8]> = l.iter().collect();
            let exact = encode_listpack_strings(&refs).unwrap().len() as u64;
            assert_eq!(
                l.listpack_byte_len(),
                exact,
                "lp_bytes drift for {:?}",
                refs.iter().map(|r| r.len()).collect::<Vec<_>>()
            );
        };

        // Elements spanning every int-encoding width plus string-header widths.
        let samples: Vec<Vec<u8>> = vec![
            b"0".to_vec(),
            b"127".to_vec(),
            b"128".to_vec(),
            b"-1".to_vec(),
            b"4095".to_vec(),
            b"-4096".to_vec(),
            b"32767".to_vec(),
            b"-32768".to_vec(),
            b"8388607".to_vec(),
            b"2147483647".to_vec(),
            b"9223372036854775807".to_vec(),
            b"007".to_vec(),  // non-canonical int -> string-encoded
            b"a".to_vec(),    // 1-byte string
            vec![b'z'; 63],   // <64 header
            vec![b'y'; 64],   // 2-byte header boundary
            vec![b'w'; 4096], // 5-byte header boundary
        ];

        let mut l = ListValue::default();
        check(&l);
        for s in &samples {
            l.push_back(s.clone());
            check(&l);
        }
        for s in samples.iter().rev() {
            l.push_front(s.clone());
            check(&l);
        }
        // LSET across widths.
        l.set(0, b"4242".to_vec());
        check(&l);
        l.set(l.len() - 1, vec![b'q'; 200]);
        check(&l);
        // LINSERT in the middle.
        l.insert(l.len() / 2, b"-9999999999".to_vec());
        check(&l);
        // Pops from both ends.
        for _ in 0..5 {
            let _ = l.pop_front();
            check(&l);
            let _ = l.pop_back();
            check(&l);
        }
        // Arbitrary removal + retain.
        let _ = l.remove(l.len() / 2);
        check(&l);
        l.retain(|e| e.len() != 1);
        check(&l);
        while l.pop_back().is_some() {
            check(&l);
        }
    }

    /// (frankenredis-rc49s) redis decides listpack→quicklist ONCE per command
    /// over the batch's RAW total — a multi-element `RPUSH` whose raw lengths
    /// keep `lpBytes(before) + Σraw <= 8192` stays listpack even though the
    /// fully-encoded size exceeds the budget (a stateless re-encode over-counts
    /// the encoded-vs-raw inflation of the batch's earlier elements and flips
    /// early). This is the exact seed-99 shape.
    #[test]
    fn list_encoding_decided_per_command_not_per_element() {
        let mut store = Store::new(); // default list_max_listpack_size = -2

        // One RPUSH of many single-byte 'a' elements. Each 'a' encodes to 3
        // listpack bytes (0x81 'a' + 1 backlen) but its raw length is 1, so the
        // per-element-encoded model would convert ~2x sooner than redis.
        let n = 4000usize; // raw total 4000 + 7 < 8192; encoded ~12007 > 8192
        let batch: Vec<Vec<u8>> = (0..n).map(|_| b"a".to_vec()).collect();
        let _ = store.rpush(b"l", &batch, 0).unwrap();
        assert_eq!(
            store.object_encoding(b"l", 0),
            Some("listpack"),
            "single-command raw total stays under budget -> listpack"
        );

        // Sticky AUTO hysteresis on a separate small list: a single huge add
        // forces quicklist; removing it back below half the budget reverts.
        let small: Vec<Vec<u8>> = (0..10).map(|_| b"a".to_vec()).collect();
        let _ = store.rpush(b"s", &small, 0).unwrap();
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));
        let _ = store.rpush(b"s", &[vec![b'x'; 9000]], 0).unwrap();
        assert_eq!(store.object_encoding(b"s", 0), Some("quicklist"));
        let _ = store.rpop(b"s", 0).unwrap(); // remove the huge element
        assert_eq!(
            store.object_encoding(b"s", 0),
            Some("listpack"),
            "shrink below half-budget reverts to listpack (AUTO hysteresis)"
        );
    }

    // (frankenredis-listpacksafe) With a POSITIVE (entry-count) list-max-listpack-size,
    // upstream quicklistNodeExceedsLimit still converts to quicklist once the listpack
    // tops the 8192-byte SIZE_SAFETY_LIMIT, regardless of element count.
    #[test]
    fn list_listpack_size_safety_limit_with_positive_fill() {
        let mut store = Store::new();
        store.list_max_listpack_size = 128;

        // 8100-byte element: 1 entry (<=128) and listpack < 8192 -> listpack.
        let _ = store.rpush(b"a", &[vec![b'x'; 8100]], 0).unwrap();
        assert_eq!(store.object_encoding(b"a", 0), Some("listpack"));

        // 8192-byte element: listpack tops 8192 -> quicklist despite 1 entry.
        let _ = store.rpush(b"b", &[vec![b'x'; 8192]], 0).unwrap();
        assert_eq!(store.object_encoding(b"b", 0), Some("quicklist"));

        // 100 x 100-byte: under the 128-entry count but listpack > 8192 -> quicklist.
        let many: Vec<Vec<u8>> = (0..100).map(|_| vec![b'y'; 100]).collect();
        let _ = store.rpush(b"c", &many, 0).unwrap();
        assert_eq!(store.object_encoding(b"c", 0), Some("quicklist"));

        // Small list under both limits stays listpack.
        let _ = store
            .rpush(b"d", &[b"x".to_vec(), b"y".to_vec()], 0)
            .unwrap();
        assert_eq!(store.object_encoding(b"d", 0), Some("listpack"));
    }

    #[test]
    fn object_encoding_set_rejects_noncanonical_integer_members() {
        let mut store = Store::new();
        store.sadd(b"s", &[b"01".to_vec()], 0).expect("sadd");
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));

        let mut store = Store::new();
        store.sadd(b"t", &[b"1".to_vec()], 0).expect("sadd");
        assert_eq!(store.object_encoding(b"t", 0), Some("intset"));
    }

    #[test]
    fn intset_memory_usage_uses_minimal_encoding_width() {
        // (frankenredis-intset-memusage-width) A redis intset packs every
        // member at ONE width = the widest member's minimal int encoding
        // (INT16=2 / INT32=4 / INT64=8), so the VALUE estimate is
        // REDIS_OBJECT_OVERHEAD + redis_allocation_size(8 + len*width).
        // Previously fr used 8 bytes/member, over-reporting small-int sets.
        let val = |width: usize, len: usize| {
            REDIS_OBJECT_OVERHEAD_BYTES + redis_allocation_size(8 + len * width)
        };
        // {1,2,3}: all fit i16 -> width 2 -> 16 + alloc(14)=16 -> 32
        assert_eq!(
            estimate_set_memory_usage_bytes(&SetValue::Int(vec![1, 2, 3])),
            val(2, 3)
        );
        // 10 small ints -> width 2 -> 16 + alloc(28)=32 -> 48
        assert_eq!(
            estimate_set_memory_usage_bytes(&SetValue::Int((0..10).collect())),
            val(2, 10)
        );
        // a value needing INT32 -> width 4
        assert_eq!(
            estimate_set_memory_usage_bytes(&SetValue::Int(vec![1, 100_000])),
            val(4, 2)
        );
        // a value needing INT64 -> width 8
        assert_eq!(
            estimate_set_memory_usage_bytes(&SetValue::Int(vec![1, 5_000_000_000])),
            val(8, 2)
        );
        // sanity: small-int width is strictly smaller than the old 8-wide model
        assert!(
            estimate_set_memory_usage_bytes(&SetValue::Int(vec![1, 2, 3]))
                < REDIS_OBJECT_OVERHEAD_BYTES + redis_allocation_size(8 + 3 * REDIS_SCORE_BYTES)
        );
    }

    #[test]
    fn zset_listpack_score_entry_models_listpack_encoding() {
        // (frankenredis-zset-lp-score-memusage) A zset listpack stores the
        // score as a full listpack entry: integer-looking scores use listpack
        // integer encoding (total 1..=9 bytes by magnitude), others a string
        // entry, plus a 1-byte backlen. Previously only the digit/string length
        // was counted, undercounting every score.
        // 7-bit ints (0..=127): 1-byte encoding + 1 backlen = 2
        assert_eq!(estimate_listpack_score_bytes(0.0), 2);
        assert_eq!(estimate_listpack_score_bytes(127.0), 2);
        // 13-bit (|v| <= 4095): 2 + 1 = 3
        assert_eq!(estimate_listpack_score_bytes(128.0), 3);
        assert_eq!(estimate_listpack_score_bytes(-4096.0), 3);
        // 16-bit: 3 + 1 = 4
        assert_eq!(estimate_listpack_score_bytes(30000.0), 4);
        // 24-bit: 4 + 1 = 5
        assert_eq!(estimate_listpack_score_bytes(1_000_000.0), 5);
        // 32-bit: 5 + 1 = 6
        assert_eq!(estimate_listpack_score_bytes(2_000_000_000.0), 6);
        // 64-bit: 9 + 1 = 10
        assert_eq!(estimate_listpack_score_bytes(5_000_000_000.0), 10);
        // non-integer score -> string entry (d2string bytes + 2)
        let frac = redis_score_to_string(1.2345);
        assert_eq!(
            estimate_listpack_score_bytes(1.2345),
            estimate_listpack_entry_bytes(frac.as_bytes())
        );
        // 1e20 renders as "1e+20" (d2string), a 5-byte string entry -> 5 + 2
        assert_eq!(redis_score_to_string(1e20), "1e+20");
        assert_eq!(estimate_listpack_score_bytes(1e20), 7);
        // every variant is strictly larger than the old length-only model
        assert!(estimate_listpack_score_bytes(0.0) > "0".len());
    }

    #[test]
    fn set_intset_stays_intset_past_listpack_cap_7vogx() {
        // (frankenredis-7vogx) Upstream t_set.c keeps the intset
        // encoding until either a non-integer member arrives or the
        // cardinality crosses set-max-intset-entries (default 512).
        // The listpack cap (default 128) only matters once intset
        // is no longer applicable. fr was promoting to hashtable as
        // soon as set.len() > set-max-listpack-entries, even when
        // every member was still an integer.
        let mut store = Store::new();

        // 127 integers — well within intset.
        let members: Vec<Vec<u8>> = (0..127).map(|i| i.to_string().into_bytes()).collect();
        store.sadd(b"s", &members, 0).expect("sadd 127");
        assert_eq!(store.object_encoding(b"s", 0), Some("intset"));

        // 129 integers — past the listpack cap (128) but well
        // under set-max-intset-entries (512). Should stay intset.
        store
            .sadd(
                b"s",
                &[b"127".to_vec(), b"128".to_vec(), b"129".to_vec()],
                0,
            )
            .expect("sadd 129");
        assert_eq!(store.object_encoding(b"s", 0), Some("intset"));

        // Crossing 512 integers triggers the intset→listpack/
        // hashtable transition. With 513 integers and the default
        // 128-entry listpack cap, the next stop is hashtable.
        let bulk: Vec<Vec<u8>> = (130..=513).map(|i| i.to_string().into_bytes()).collect();
        store.sadd(b"s", &bulk, 0).expect("sadd 513");
        assert_eq!(store.object_encoding(b"s", 0), Some("hashtable"));

        // A small, all-integer set with one short non-integer
        // member still promotes to listpack (not hashtable) — both
        // values are short.
        let mut store2 = Store::new();
        store2
            .sadd(
                b"t",
                &[
                    b"1".to_vec(),
                    b"2".to_vec(),
                    b"3".to_vec(),
                    b"alpha".to_vec(),
                ],
                0,
            )
            .expect("sadd mixed");
        assert_eq!(store2.object_encoding(b"t", 0), Some("listpack"));
    }

    #[test]
    fn set_listpack_value_cap_drives_hashtable_promotion_r6xt3() {
        // (frankenredis-r6xt3) Upstream t_set.c respects
        // set-max-listpack-value as the per-element cap on the
        // listpack encoding. fr previously hardcoded 64 bytes
        // and ignored CONFIG SET set-max-listpack-value, so
        // listpack-encoded sets stayed listpack even with
        // 12-byte members under a 5-byte cap.
        let mut store = Store::new();
        store.set_max_listpack_value = 5;
        // Mix in one non-integer so we land on listpack first.
        store.sadd(b"s", &[b"short".to_vec()], 0).expect("sadd 5");
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));
        store
            .sadd(b"s", &[b"longerstring".to_vec()], 0)
            .expect("sadd 12");
        assert_eq!(
            store.object_encoding(b"s", 0),
            Some("hashtable"),
            "12-byte member with cap=5 must promote listpack→hashtable"
        );
    }

    #[test]
    fn hscan_sscan_zscan_short_circuit_on_small_encodings_yvxq6() {
        // (frankenredis-yvxq6) Upstream's HSCAN/SSCAN/ZSCAN return
        // the full collection in one round with cursor=0 when the
        // value is listpack-encoded (or intset for sets) — COUNT
        // and an out-of-range cursor are ignored. Only the
        // hashtable / skiplist path honors them.
        let mut store = Store::new();

        // Listpack hash
        for (f, v) in [
            (b"f1".to_vec(), b"v1".to_vec()),
            (b"f2".to_vec(), b"v2".to_vec()),
            (b"f3".to_vec(), b"v3".to_vec()),
        ] {
            store.hset(b"h", f, v, 0).expect("hset");
        }
        assert_eq!(store.object_encoding(b"h", 0), Some("listpack"));

        // COUNT=1 still returns everything, cursor=0.
        let (cursor, items) = store
            .hscan(b"h", 0, None, 1, 0)
            .expect("hscan listpack count 1");
        assert_eq!(cursor, 0, "listpack cursor must reset to 0");
        assert_eq!(items.len(), 3, "listpack returns all in one shot");

        // Out-of-range cursor still returns everything.
        let (cursor, items) = store
            .hscan(b"h", 99_999, None, 10, 0)
            .expect("hscan listpack bogus cursor");
        assert_eq!(cursor, 0);
        assert_eq!(items.len(), 3);

        // Listpack set
        store
            .sadd(
                b"s",
                &[
                    b"a".to_vec(),
                    b"b".to_vec(),
                    b"c".to_vec(),
                    b"alpha".to_vec(),
                ],
                0,
            )
            .expect("sadd");
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));
        let (cursor, items) = store.sscan(b"s", 0, None, 1, 0).expect("sscan listpack");
        assert_eq!(cursor, 0);
        assert_eq!(items.len(), 4);

        // Intset
        store
            .sadd(b"si", &[b"1".to_vec(), b"2".to_vec(), b"3".to_vec()], 0)
            .expect("sadd intset");
        assert_eq!(store.object_encoding(b"si", 0), Some("intset"));
        let (cursor, items) = store
            .sscan(b"si", 99_999, None, 1, 0)
            .expect("sscan intset bogus cursor");
        assert_eq!(cursor, 0);
        assert_eq!(items.len(), 3);

        // Listpack zset
        store
            .zadd(
                b"z",
                &[
                    (1.0, b"a".to_vec()),
                    (2.0, b"b".to_vec()),
                    (3.0, b"c".to_vec()),
                ],
                0,
            )
            .expect("zadd");
        assert_eq!(store.object_encoding(b"z", 0), Some("listpack"));
        let (cursor, items) = store.zscan(b"z", 0, None, 1, 0).expect("zscan listpack");
        assert_eq!(cursor, 0);
        assert_eq!(items.len(), 3);

        // MATCH still filters per-call.
        let (cursor, items) = store
            .hscan(b"h", 0, Some(b"f1"), 100, 0)
            .expect("hscan filter");
        assert_eq!(cursor, 0);
        assert_eq!(items.len(), 1);
        assert_eq!(items[0].0, b"f1".to_vec());
    }

    #[test]
    fn set_object_encoding_promotions_do_not_downgrade_after_srem() {
        let mut store = Store::new();
        let integer_members: Vec<Vec<u8>> = (0..10)
            .map(|value| value.to_string().into_bytes())
            .collect();
        store.sadd(b"s", &integer_members, 0).expect("sadd");
        assert_eq!(store.object_encoding(b"s", 0), Some("intset"));

        store.sadd(b"s", &[b"alpha".to_vec()], 0).expect("sadd");
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));

        store.srem(b"s", &[b"alpha"], 0).expect("srem");
        assert_eq!(store.object_encoding(b"s", 0), Some("listpack"));

        store.set_max_listpack_entries = 2;
        store
            .sadd(
                b"h",
                &[b"alpha".to_vec(), b"beta".to_vec(), b"gamma".to_vec()],
                0,
            )
            .expect("sadd");
        assert_eq!(store.object_encoding(b"h", 0), Some("hashtable"));

        store.srem(b"h", &[b"gamma"], 0).expect("srem");
        assert_eq!(store.object_encoding(b"h", 0), Some("hashtable"));
    }

    #[test]
    fn non_positive_expire_values_delete_immediately_property() {
        for seconds in [0_i64, -1, -30] {
            let mut store = Store::new();
            store.set(b"k".to_vec(), b"v".to_vec(), None, 1_000);
            assert!(store.expire_seconds(b"k", seconds, 1_000));
            assert_eq!(store.get(b"k", 1_000).unwrap(), None);
        }

        for milliseconds in [0_i64, -1, -500] {
            let mut store = Store::new();
            store.set(b"k".to_vec(), b"v".to_vec(), None, 1_000);
            assert!(store.expire_milliseconds(b"k", milliseconds, 1_000));
            assert_eq!(store.get(b"k", 1_000).unwrap(), None);
        }
    }

    #[test]
    fn lazy_expiration_evicts_key_one_ms_past_deadline() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"v".to_vec(), Some(1_000), 5_000); // deadline 6_000
        assert!(store.exists(b"k", 5_999));
        // Upstream keyIsExpired uses `now > when`, so the key is still alive in
        // its final millisecond (now == deadline) and is only evicted once the
        // clock passes the deadline.
        assert!(store.exists(b"k", 6_000));
        assert!(!store.exists(b"k", 6_001));
        assert_eq!(store.get(b"k", 6_001).unwrap(), None);
        assert_eq!(store.stat_expired_keys, 1);
    }

    #[test]
    fn fr_p2c_008_u001_active_expire_cycle_evicts_expired_keys() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), Some(1), 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(1), 0);
        store.set(b"c".to_vec(), b"3".to_vec(), None, 0);

        let result = store.run_active_expire_cycle(10, None, 10);
        // (frankenredis-yvg7h) Active-expire now samples only volatile keys, so
        // the persistent `c` is not sampled (2 sampled, not 3) — matching
        // upstream's expires-dict scan. The eviction outcome is unchanged.
        assert_eq!(result.sampled_keys, 2);
        assert_eq!(result.evicted_keys, 2);
        assert_eq!(store.stat_expired_keys, 2);
        assert_eq!(store.dbsize_in_db(0), 1);
        assert_eq!(store.get(b"c", 10).unwrap(), Some(b"3".to_vec()));
    }

    #[test]
    fn fr_p2c_008_u002_active_expire_cycle_cursor_is_deterministic() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), Some(1), 0);
        store.set(b"b".to_vec(), b"2".to_vec(), None, 0);
        store.set(b"c".to_vec(), b"3".to_vec(), Some(1), 0);
        store.set(b"d".to_vec(), b"4".to_vec(), None, 0);

        // (frankenredis-yvg7h) Sampling the volatile set {a, c} (persistent b, d
        // are excluded): a limit-2 cycle now reaps BOTH expired keys at once and
        // the cursor wraps to None — the effectiveness gain over diluting the
        // sample with persistent keys. A follow-up cycle has nothing to do.
        let first = store.run_active_expire_cycle(10, None, 2);
        assert_eq!(first.sampled_keys, 2);
        assert_eq!(first.evicted_keys, 2);
        assert_eq!(first.next_cursor, None);

        let second = store.run_active_expire_cycle(10, first.next_cursor.clone(), 2);
        assert_eq!(second.sampled_keys, 0);
        assert_eq!(second.evicted_keys, 0);
    }

    #[test]
    fn volatile_keys_index_tracks_ttl_transitions() {
        // (frankenredis-yvg7h) The volatile-key sampling set must follow every
        // TTL transition so active-expire samples exactly the keys with a TTL.
        let mut store = Store::new();
        store.set(b"p".to_vec(), b"v".to_vec(), None, 0); // persistent
        store.set(b"v".to_vec(), b"x".to_vec(), Some(5_000), 0); // volatile
        store.rebuild_volatile_keys_if_dirty();
        assert!(!store.volatile_keys.contains(b"p".as_slice()));
        assert!(store.volatile_keys.contains(b"v".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), Some(5_000));

        // PERSIST drops the TTL -> leaves the volatile set.
        assert!(store.persist(b"v", 0));
        assert!(!store.volatile_keys.contains(b"v".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), None);

        // EXPIREAT adds a TTL to a persistent key -> enters the set.
        assert!(store.expire_at_milliseconds(b"p", 9_999, 0));
        store.rebuild_volatile_keys_if_dirty();
        assert!(store.volatile_keys.contains(b"p".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), Some(9_999));

        // Overwriting with a TTL-less SET clears it again.
        store.set(b"p".to_vec(), b"y".to_vec(), None, 0);
        assert!(!store.volatile_keys.contains(b"p".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), None);

        // DEL of a volatile key removes it from the set.
        store.set(b"d".to_vec(), b"z".to_vec(), Some(1_000), 0);
        store.rebuild_volatile_keys_if_dirty();
        assert!(store.volatile_keys.contains(b"d".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), Some(1_000));
        store.del(&[b"d".to_vec()], 0);
        assert!(!store.volatile_keys.contains(b"d".as_slice()));
        assert_eq!(store.earliest_expiry_deadline_ms(), None);

        // FLUSHDB clears the set.
        store.set(b"f".to_vec(), b"z".to_vec(), Some(1_000), 0);
        store.rebuild_volatile_keys_if_dirty();
        assert!(!store.volatile_keys.is_empty());
        assert!(!store.expiry_deadline_counts.is_empty());
        store.flushdb();
        assert!(store.volatile_keys.is_empty());
        assert!(store.expiry_deadline_counts.is_empty());
    }

    #[test]
    fn avg_ttl_in_db_reports_exact_volatile_mean() {
        // (frankenredis-xn7xr) INFO keyspace cannot reproduce Redis's sampled,
        // decaying avg_ttl byte-for-byte, but it should report a meaningful
        // current volatile-key TTL instead of the old hard-coded zero.
        let mut store = Store::new();
        store.set(b"persistent".to_vec(), b"v".to_vec(), None, 1_000);
        store.set(b"a".to_vec(), b"v".to_vec(), Some(1_000), 1_000);
        store.set(b"b".to_vec(), b"v".to_vec(), Some(3_000), 1_000);
        store.set(encode_db_key(1, b"c"), b"v".to_vec(), Some(5_000), 1_000);

        assert_eq!(store.expires_in_db(0), 2);
        assert_eq!(store.avg_ttl_in_db(0, 1_500), 1_500);
        assert_eq!(store.avg_ttl_in_db(1, 1_500), 4_500);
        assert_eq!(store.avg_ttl_in_db(0, 5_000), 0);
    }

    #[test]
    fn active_expire_samples_volatile_keys_only_not_persistent() {
        // (frankenredis-yvg7h) With a mostly-persistent keyspace, active-expire
        // must still reap expired volatile keys promptly — it samples the
        // volatile set, not the whole keyspace. All-key sampling with the same
        // small sample_limit would almost never hit the handful of TTL keys.
        let mut store = Store::new();
        for i in 0..1000u32 {
            store.set(
                format!("persist:{i:04}").into_bytes(),
                b"v".to_vec(),
                None,
                0,
            );
        }
        for i in 0..5u32 {
            store.set(format!("vol:{i}").into_bytes(), b"v".to_vec(), Some(100), 0);
        }
        // Single cycle at t=1000 (all 5 volatile keys expired), sample_limit=10.
        let result = store.run_active_expire_cycle(1000, None, 10);
        assert_eq!(
            result.sampled_keys, 5,
            "must sample only the 5 volatile keys, not the 1000 persistent ones"
        );
        assert_eq!(result.evicted_keys, 5, "every expired volatile key reaped");
        assert_eq!(result.next_cursor, None);
        // The 1000 persistent keys are untouched.
        assert_eq!(store.entries.len(), 1000);
        // No volatile keys remain -> the next cycle is an O(1) no-op.
        assert!(store.volatile_keys.is_empty());
        let empty = store.run_active_expire_cycle(2000, None, 10);
        assert_eq!(empty.sampled_keys, 0);
        assert_eq!(empty.evicted_keys, 0);
    }

    #[test]
    fn active_expire_cycle_wraparound_samples_each_key_once() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), Some(1), 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(10_000), 0);
        store.set(b"c".to_vec(), b"3".to_vec(), Some(10_000), 0);

        // `a` (deadline 1) is only due once now passes it (`now > when`), so
        // sample at now=2; `b`/`c` (deadline 10_000) stay alive.
        let result = store.run_active_expire_cycle(2, Some(b"b".to_vec()), 5);

        assert_eq!(result.sampled_keys, 3);
        assert_eq!(result.evicted_keys, 1);
        assert_eq!(result.next_cursor, None);
        assert!(!store.entries.contains_key(b"a".as_slice()));
        assert!(store.entries.contains_key(b"b".as_slice()));
        assert!(store.entries.contains_key(b"c".as_slice()));
    }

    #[test]
    fn active_expire_cycle_skips_until_earliest_deadline_is_due() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), Some(10_000), 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(20_000), 0);

        let early = store.run_active_expire_cycle(9_999, Some(b"a".to_vec()), 5);
        assert_eq!(early.sampled_keys, 0);
        assert_eq!(early.evicted_keys, 0);
        assert_eq!(early.next_cursor, Some(b"a".to_vec()));
        assert_eq!(store.dbsize_in_db(0), 2);

        // `a` (deadline 10_000) becomes due only once now passes it (`now > when`).
        let due = store.run_active_expire_cycle(10_001, None, 5);
        assert_eq!(due.sampled_keys, 2);
        assert_eq!(due.evicted_keys, 1);
        assert_eq!(store.dbsize_in_db(0), 1);
        assert!(!store.entries.contains_key(b"a".as_slice()));
        assert!(store.entries.contains_key(b"b".as_slice()));
    }

    #[test]
    fn volatile_key_sort_is_lazy_until_a_deadline_is_due() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), Some(10_000), 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(20_000), 0);

        assert!(store.volatile_keys_dirty);
        assert!(store.volatile_keys.is_empty());

        let early = store.run_active_expire_cycle(9_999, None, 10);
        assert_eq!(early.sampled_keys, 0);
        assert_eq!(early.evicted_keys, 0);
        assert!(store.volatile_keys_dirty);
        assert!(store.volatile_keys.is_empty());

        // `a` (deadline 10_000) becomes due only once now passes it (`now > when`).
        let due = store.run_active_expire_cycle(10_001, None, 10);
        assert_eq!(due.sampled_keys, 2);
        assert_eq!(due.evicted_keys, 1);
        assert!(!store.volatile_keys_dirty);
        assert!(!store.volatile_keys.contains(b"a".as_slice()));
        assert!(store.volatile_keys.contains(b"b".as_slice()));
    }

