    #[test]
    fn append_creates_or_extends() {
        let mut store = Store::new();
        assert_eq!(store.append(b"k", b"hello", 0).unwrap(), 5);
        assert_eq!(store.append(b"k", b" world", 0).unwrap(), 11);
        assert_eq!(store.get(b"k", 0).unwrap(), Some(b"hello world".to_vec()));
    }

    #[test]
    fn append_and_setrange_promote_embstr_string_encoding_to_raw() {
        let mut store = Store::new();

        store.set(b"append".to_vec(), b"short".to_vec(), None, 0);
        assert_eq!(store.object_encoding(b"append", 0), Some("embstr"));
        assert_eq!(store.append(b"append", b"_more", 1).unwrap(), 10);
        assert_eq!(store.object_encoding(b"append", 1), Some("raw"));

        store.set(b"setrange".to_vec(), b"short".to_vec(), None, 0);
        assert_eq!(store.object_encoding(b"setrange", 0), Some("embstr"));
        assert_eq!(store.setrange(b"setrange", 1, b"X", 1).unwrap(), 5);
        assert_eq!(store.object_encoding(b"setrange", 1), Some("raw"));

        assert_eq!(store.setrange(b"created", 0, b"hi", 1).unwrap(), 2);
        assert_eq!(store.object_encoding(b"created", 1), Some("raw"));
    }

    #[test]
    fn strlen_returns_length_or_zero() {
        let mut store = Store::new();
        assert_eq!(store.strlen(b"missing", 0).unwrap(), 0);
        store.set(b"k".to_vec(), b"hello".to_vec(), None, 0);
        assert_eq!(store.strlen(b"k", 0).unwrap(), 5);
    }

    // (CrimsonHawk) `drop_if_expired`'s `expires_count == 0` fast-exit must be byte-identical
    // to the full body: report existence with no eviction when nothing can expire, and still
    // evict + report absent when a key's TTL is actually due (expires_count > 0).
    #[test]
    fn drop_if_expired_fastexit_matches_full_body() {
        // expires_count == 0: pure existence, no side effects.
        let mut s = Store::new();
        s.set(b"present".to_vec(), b"v".to_vec(), None, 100);
        assert_eq!(s.expires_count, 0);
        let dirty0 = s.dirty;
        assert!(s.drop_if_expired(b"present", 200)); // present → true
        assert!(!s.drop_if_expired(b"absent", 200)); // absent → false
        assert_eq!(s.dirty, dirty0, "no-TTL drop_if_expired must not dirty");
        assert!(s.get(b"present", 200).unwrap().is_some(), "must not evict");

        // expires_count > 0: an actually-due key is still evicted + reported absent.
        let mut t = Store::new();
        t.set(b"live".to_vec(), b"L".to_vec(), None, 100);
        t.set(b"dead".to_vec(), b"D".to_vec(), Some(50), 100); // due by t=500
        assert!(t.expires_count >= 1);
        assert!(t.drop_if_expired(b"live", 500)); // live present → true
        assert!(!t.drop_if_expired(b"dead", 500)); // expired → evicted → false
        assert!(
            t.get(b"dead", 600).unwrap().is_none(),
            "expired key removed"
        );
        assert!(t.get(b"live", 600).unwrap().is_some());
    }

    // (CrimsonHawk) SCARD/ZCARD/SISMEMBER non-LFU single-lookup collapse must be byte-
    // identical to the double-lookup path: same result, WRONGTYPE, keyspace hit/miss
    // accounting, and lazy-expiry behavior (expired key → miss + evicted).
    #[test]
    fn cardinality_single_lookup_collapse_matches_full_path() {
        let mut s = Store::new();
        s.sadd(b"set", &[b"a".to_vec(), b"b".to_vec()], 1).unwrap();
        s.zadd(b"zs", &[(1.0, b"m".to_vec())], 1).unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        // Hits + correct values.
        assert_eq!(s.scard(b"set", 2).unwrap(), 2);
        assert_eq!(s.zcard(b"zs", 2).unwrap(), 1);
        assert!(s.sismember(b"set", b"a", 2).unwrap());
        assert!(!s.sismember(b"set", b"nope", 2).unwrap());
        // Missing key → 0/false + miss (no error).
        assert_eq!(s.scard(b"absent", 2).unwrap(), 0);
        assert_eq!(s.zcard(b"absent", 2).unwrap(), 0);
        assert!(!s.sismember(b"absent", b"x", 2).unwrap());
        // WRONGTYPE on a string key (still a hit).
        assert!(matches!(s.scard(b"str", 2), Err(StoreError::WrongType)));
        assert!(matches!(s.zcard(b"str", 2), Err(StoreError::WrongType)));
        assert!(matches!(
            s.sismember(b"str", b"x", 2),
            Err(StoreError::WrongType)
        ));
        // hits: scard,zcard,sismemberx2,scard(str),zcard(str),sismember(str) = 7;
        // misses: scard(absent),zcard(absent),sismember(absent) = 3.
        assert_eq!(s.stat_keyspace_hits, h0 + 7);
        assert_eq!(s.stat_keyspace_misses, m0 + 3);

        // Lazy expiry: an expired set key → SCARD 0 + evicted.
        let mut t = Store::new();
        t.sadd(b"exp", &[b"a".to_vec()], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1); // absolute deadline at t=50
        assert!(t.expires_count >= 1);
        assert_eq!(t.scard(b"exp", 500).unwrap(), 0);
        assert!(
            t.get(b"exp", 600).unwrap().is_none(),
            "expired key evicted by SCARD"
        );
    }

    // (CrimsonHawk) LLEN/ZSCORE/ZRANK/ZREVRANK non-LFU single-lookup collapse: byte-identical
    // results, WRONGTYPE, keyspace hit/miss, and lazy-expiry to the double-lookup path.
    #[test]
    fn list_zset_read_single_lookup_collapse_matches_full_path() {
        let mut s = Store::new();
        s.rpush(b"list", &[b"x".to_vec(), b"y".to_vec(), b"z".to_vec()], 1)
            .unwrap();
        s.zadd(b"zs", &[(1.0, b"a".to_vec()), (2.0, b"b".to_vec())], 1)
            .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        assert_eq!(s.llen(b"list", 2).unwrap(), 3);
        assert_eq!(s.zscore(b"zs", b"b", 2).unwrap(), Some(2.0));
        assert_eq!(s.zscore(b"zs", b"none", 2).unwrap(), None);
        assert_eq!(s.zrank(b"zs", b"b", 2).unwrap(), Some(1));
        assert_eq!(s.zrevrank(b"zs", b"a", 2).unwrap(), Some(1));
        // Missing key → default + miss.
        assert_eq!(s.llen(b"absent", 2).unwrap(), 0);
        assert_eq!(s.zscore(b"absent", b"a", 2).unwrap(), None);
        assert_eq!(s.zrank(b"absent", b"a", 2).unwrap(), None);
        // WRONGTYPE (still a hit).
        assert!(matches!(s.llen(b"str", 2), Err(StoreError::WrongType)));
        assert!(matches!(
            s.zscore(b"str", b"a", 2),
            Err(StoreError::WrongType)
        ));
        // hits: llen,zscore(b),zscore(none),zrank(b),zrevrank(a),llen(str),zscore(str) = 7;
        // misses: llen(absent),zscore(absent),zrank(absent) = 3.
        assert_eq!(s.stat_keyspace_hits, h0 + 7);
        assert_eq!(s.stat_keyspace_misses, m0 + 3);

        // Lazy expiry via LLEN on an expired list key.
        let mut t = Store::new();
        t.rpush(b"exp", &[b"a".to_vec()], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert!(t.expires_count >= 1);
        assert_eq!(t.llen(b"exp", 500).unwrap(), 0);
        assert!(
            t.get(b"exp", 600).unwrap().is_none(),
            "expired key evicted by LLEN"
        );

        // Timing headline (no-TTL, LFU off).
        let mut b = Store::new();
        let members: Vec<Vec<u8>> = (0..8u32).map(|i| format!("m{i}").into_bytes()).collect();
        b.rpush(b"benchlist:key", &members, 1).unwrap();
        let k: &[u8] = b"benchlist:key";
        for _ in 0..2000 {
            std::hint::black_box(b.llen(std::hint::black_box(k), 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.llen(std::hint::black_box(k), 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "LLEN@8 no-TTL collapsed: full={full:.2} ns/op | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) SMISMEMBER single-lookup collapse + ZMSCORE drop-guard must be
    // byte-identical: correct results, WRONGTYPE, and (with a TTL present) lazy eviction.
    // ZMSCORE records NO keyspace stat; SMISMEMBER records one hit/miss per call.
    #[test]
    fn smismember_zmscore_lookup_opt_matches_full_path() {
        let mut s = Store::new();
        s.sadd(b"set", &[b"a".to_vec(), b"b".to_vec()], 1).unwrap();
        s.zadd(b"zs", &[(1.0, b"a".to_vec()), (2.0, b"b".to_vec())], 1)
            .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        assert_eq!(
            s.smismember(b"set", &[b"a", b"x", b"b"], 2).unwrap(),
            vec![true, false, true]
        );
        assert_eq!(
            s.smismember(b"absent", &[b"a", b"b"], 2).unwrap(),
            vec![false, false]
        );
        assert!(matches!(
            s.smismember(b"str", &[b"a"], 2),
            Err(StoreError::WrongType)
        ));
        // SMISMEMBER records keyspace stats: hits = set + str(wrongtype) = 2; misses = absent = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 2);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);

        // ZMSCORE: correct scores, WRONGTYPE, missing→all-None; NO keyspace stat change.
        let (h1, m1) = (s.stat_keyspace_hits, s.stat_keyspace_misses);
        assert_eq!(
            s.zmscore(b"zs", &[b"b", b"none", b"a"], 2).unwrap(),
            vec![Some(2.0), None, Some(1.0)]
        );
        assert_eq!(s.zmscore(b"absent", &[b"a"], 2).unwrap(), vec![None]);
        assert!(matches!(
            s.zmscore(b"str", &[b"a"], 2),
            Err(StoreError::WrongType)
        ));
        assert_eq!(s.stat_keyspace_hits, h1, "ZMSCORE records no keyspace hit");
        assert_eq!(
            s.stat_keyspace_misses, m1,
            "ZMSCORE records no keyspace miss"
        );

        // Lazy expiry (expires_count > 0 branch): expired zset key → all-None + evicted.
        let mut t = Store::new();
        t.zadd(b"exp", &[(1.0, b"m".to_vec())], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert!(t.expires_count >= 1);
        assert_eq!(t.zmscore(b"exp", &[b"m"], 500).unwrap(), vec![None]);
        assert!(
            t.get(b"exp", 600).unwrap().is_none(),
            "ZMSCORE evicts expired key"
        );
        // SMISMEMBER lazy-expiry on a set.
        let mut u = Store::new();
        u.sadd(b"sexp", &[b"a".to_vec()], 1).unwrap();
        u.expire_at_milliseconds(b"sexp", 50, 1);
        assert_eq!(u.smismember(b"sexp", &[b"a"], 500).unwrap(), vec![false]);
        assert!(u.get(b"sexp", 600).unwrap().is_none());

        // Timing headline for SMISMEMBER (no-TTL, LFU off).
        let mut b = Store::new();
        for i in 0..8u32 {
            b.sadd(b"benchset:key", &[format!("m{i}").into_bytes()], 1)
                .unwrap();
        }
        let k: &[u8] = b"benchset:key";
        let q: &[&[u8]] = &[b"m0", b"m3", b"m7", b"nope"];
        for _ in 0..2000 {
            std::hint::black_box(b.smismember(std::hint::black_box(k), q, 2)).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.smismember(std::hint::black_box(k), q, 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "SMISMEMBER@8/4q no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) SMEMBERS/LRANGE borrow-scan single-lookup collapse: byte-identical
    // reply stream (Len + members), WRONGTYPE, keyspace hit/miss, lazy-expiry eviction.
    #[test]
    fn smembers_lrange_borrow_scan_collapse_matches_full_path() {
        fn collect_smembers(
            s: &mut Store,
            key: &[u8],
            now: u64,
        ) -> Result<(usize, Vec<Vec<u8>>), StoreError> {
            use crate::SmembersScanEvent;
            let mut len = 0usize;
            let mut members = Vec::new();
            s.smembers_borrow_scan(key, now, |e| match e {
                SmembersScanEvent::Len(n) => len = n,
                SmembersScanEvent::Member(m) => members.push(m.to_vec()),
            })?;
            Ok((len, members))
        }
        fn collect_lrange(
            s: &mut Store,
            key: &[u8],
            a: i64,
            b: i64,
            now: u64,
        ) -> Result<(usize, Vec<Vec<u8>>), StoreError> {
            use crate::SmembersScanEvent;
            let mut len = 0usize;
            let mut items = Vec::new();
            s.lrange_borrow_scan(key, a, b, now, |e| match e {
                SmembersScanEvent::Len(n) => len = n,
                SmembersScanEvent::Member(m) => items.push(m.to_vec()),
            })?;
            Ok((len, items))
        }

        let mut s = Store::new();
        s.sadd(b"set", &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec()], 1)
            .unwrap();
        s.rpush(b"list", &[b"x".to_vec(), b"y".to_vec(), b"z".to_vec()], 1)
            .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let (slen, mut smem) = collect_smembers(&mut s, b"set", 2).unwrap();
        smem.sort();
        assert_eq!(slen, 3);
        assert_eq!(smem, vec![b"a".to_vec(), b"b".to_vec(), b"c".to_vec()]);
        assert_eq!(
            collect_lrange(&mut s, b"list", 0, -1, 2).unwrap(),
            (3, vec![b"x".to_vec(), b"y".to_vec(), b"z".to_vec()])
        );
        assert_eq!(
            collect_lrange(&mut s, b"list", 1, 1, 2).unwrap(),
            (1, vec![b"y".to_vec()])
        );
        // Missing key → Len(0), empty; hit stats still recorded on hits.
        assert_eq!(collect_smembers(&mut s, b"absent", 2).unwrap(), (0, vec![]));
        assert_eq!(
            collect_lrange(&mut s, b"absent", 0, -1, 2).unwrap(),
            (0, vec![])
        );
        // WRONGTYPE (still a hit).
        assert!(matches!(
            collect_smembers(&mut s, b"str", 2),
            Err(StoreError::WrongType)
        ));
        assert!(matches!(
            collect_lrange(&mut s, b"str", 0, -1, 2),
            Err(StoreError::WrongType)
        ));
        // hits: set,list(0-1),list(1-1),smembers(str),lrange(str) = 5; misses: 2 absents = 2.
        assert_eq!(s.stat_keyspace_hits, h0 + 5);
        assert_eq!(s.stat_keyspace_misses, m0 + 2);

        // Lazy expiry via SMEMBERS on an expired set key.
        let mut t = Store::new();
        t.sadd(b"exp", &[b"a".to_vec()], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert!(t.expires_count >= 1);
        assert_eq!(collect_smembers(&mut t, b"exp", 500).unwrap(), (0, vec![]));
        assert!(
            t.get(b"exp", 600).unwrap().is_none(),
            "SMEMBERS evicts expired key"
        );

        // Timing headline for SMEMBERS@8 (no-TTL, LFU off).
        let mut b = Store::new();
        for i in 0..8u32 {
            b.sadd(b"benchset:key", &[format!("m{i}").into_bytes()], 1)
                .unwrap();
        }
        let k: &[u8] = b"benchset:key";
        for _ in 0..2000 {
            b.smembers_borrow_scan(k, 2, |_| {}).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            b.smembers_borrow_scan(std::hint::black_box(k), 2, |e| {
                std::hint::black_box(&e);
            })
            .ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "SMEMBERS@8 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) HGET/hget_with single-lookup collapse (gated on empty field-TTL map)
    // must be byte-identical: value/WRONGTYPE/missing, keyspace hit/miss, unconditional
    // touch (incl WRONGTYPE), key lazy-expiry — AND still reap an expired FIELD when a
    // per-field TTL exists (the non-empty-map fallback path).
    #[test]
    fn hget_single_lookup_collapse_and_field_ttl_fallback() {
        let mut s = Store::new();
        s.hset(b"h", b"f".to_vec(), b"v".to_vec(), 1).unwrap();
        s.hset(b"h", b"g".to_vec(), b"w".to_vec(), 1).unwrap();
        s.set(b"str".to_vec(), b"x".to_vec(), None, 1);
        assert!(s.hash_field_expires.is_empty());
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        // Collapse path (empty field-TTL map).
        assert_eq!(s.hget(b"h", b"f", 2).unwrap(), Some(b"v".to_vec()));
        assert_eq!(s.hget(b"h", b"absent_field", 2).unwrap(), None);
        assert_eq!(s.hget(b"missing_key", b"f", 2).unwrap(), None);
        assert!(matches!(
            s.hget(b"str", b"f", 2),
            Err(StoreError::WrongType)
        ));
        // hget_with (borrow) parity.
        let got = s
            .hget_with(b"h", b"g", 2, |v| v.map(<[u8]>::to_vec))
            .unwrap();
        assert_eq!(got, Some(b"w".to_vec()));
        // hits: hget(f),hget(absent_field on present key),hget(str wrongtype),hget_with(g) = 4;
        // misses: hget(missing_key) = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 4);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);

        // Key-level lazy expiry via HGET (collapse path).
        let mut t = Store::new();
        t.hset(b"hexp", b"f".to_vec(), b"v".to_vec(), 1).unwrap();
        t.expire_at_milliseconds(b"hexp", 50, 1);
        assert!(t.hash_field_expires.is_empty());
        assert_eq!(t.hget(b"hexp", b"f", 500).unwrap(), None);
        assert!(
            t.get(b"hexp", 600).unwrap().is_none(),
            "HGET evicts expired key"
        );

        // FIELD-TTL FALLBACK: a per-field TTL makes the map non-empty → original path,
        // and an expired field must be reaped (invisible) while a live field remains.
        let mut u = Store::new();
        u.hset(b"h2", b"live".to_vec(), b"1".to_vec(), 1).unwrap();
        u.hset(b"h2", b"dead".to_vec(), b"2".to_vec(), 1).unwrap();
        u.hash_field_expires
            .insert((b"h2".to_vec(), b"dead".to_vec()), 50); // due by t=500
        assert!(!u.hash_field_expires.is_empty());
        assert_eq!(u.hget(b"h2", b"live", 500).unwrap(), Some(b"1".to_vec()));
        assert_eq!(
            u.hget(b"h2", b"dead", 500).unwrap(),
            None,
            "expired field reaped"
        );

        // Timing headline HGET@small-hash (no field TTL, LFU off).
        let mut b = Store::new();
        for i in 0..8u32 {
            b.hset(
                b"benchhash:key",
                format!("f{i}").into_bytes(),
                b"val".to_vec(),
                1,
            )
            .unwrap();
        }
        let k: &[u8] = b"benchhash:key";
        for _ in 0..2000 {
            std::hint::black_box(b.hget(std::hint::black_box(k), b"f3", 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.hget(std::hint::black_box(k), b"f3", 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "HGET@8fields no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) HEXISTS/HSTRLEN/HLEN + HGETALL/HKEYS/HVALS borrow-scan field-TTL-gated
    // collapse: byte-identical in the empty-map case AND still reaping expired fields in the
    // non-empty-map fallback.
    #[test]
    fn hash_read_family_collapse_and_field_ttl_fallback() {
        use crate::SmembersScanEvent;
        fn scan_len_members(
            s: &mut Store,
            f: impl FnOnce(&mut Store, &mut dyn FnMut(SmembersScanEvent)) -> Result<(), StoreError>,
        ) -> Result<(usize, Vec<Vec<u8>>), StoreError> {
            let mut len = 0usize;
            let mut out = Vec::new();
            let mut sink = |e: SmembersScanEvent| match e {
                SmembersScanEvent::Len(n) => len = n,
                SmembersScanEvent::Member(m) => out.push(m.to_vec()),
            };
            f(s, &mut sink)?;
            Ok((len, out))
        }

        let mut s = Store::new();
        s.hset(b"h", b"a".to_vec(), b"1".to_vec(), 1).unwrap();
        s.hset(b"h", b"bb".to_vec(), b"22".to_vec(), 1).unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        assert!(s.hash_field_expires.is_empty());
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        assert!(s.hexists(b"h", b"a", 2).unwrap());
        assert!(!s.hexists(b"h", b"none", 2).unwrap());
        assert!(!s.hexists(b"absent", b"a", 2).unwrap());
        assert_eq!(s.hstrlen(b"h", b"bb", 2).unwrap(), 2);
        assert_eq!(s.hstrlen(b"h", b"none", 2).unwrap(), 0);
        assert_eq!(s.hlen(b"h", 2).unwrap(), 2);
        assert!(matches!(
            s.hexists(b"str", b"a", 2),
            Err(StoreError::WrongType)
        ));
        assert!(matches!(s.hlen(b"str", 2), Err(StoreError::WrongType)));
        // hits: hexists(a),hexists(none),hstrlen(bb),hstrlen(none),hlen,hexists(str),hlen(str) = 7;
        // misses: hexists(absent) = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 7);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);

        // HGETALL borrow-scan: Len + interleaved k,v (insertion order).
        let (glen, gkv) =
            scan_len_members(&mut s, |s, sink| s.hgetall_borrow_scan(b"h", 2, sink)).unwrap();
        assert_eq!(glen, 2);
        assert_eq!(
            gkv,
            vec![b"a".to_vec(), b"1".to_vec(), b"bb".to_vec(), b"22".to_vec()]
        );
        // HKEYS / HVALS.
        let (klen, keys) = scan_len_members(&mut s, |s, sink| {
            s.hcollection_borrow_scan(b"h", 2, false, sink)
        })
        .unwrap();
        assert_eq!((klen, keys), (2, vec![b"a".to_vec(), b"bb".to_vec()]));
        let (vlen, vals) = scan_len_members(&mut s, |s, sink| {
            s.hcollection_borrow_scan(b"h", 2, true, sink)
        })
        .unwrap();
        assert_eq!((vlen, vals), (2, vec![b"1".to_vec(), b"22".to_vec()]));

        // Key lazy expiry via HLEN (collapse path).
        let mut t = Store::new();
        t.hset(b"hexp", b"a".to_vec(), b"1".to_vec(), 1).unwrap();
        t.expire_at_milliseconds(b"hexp", 50, 1);
        assert_eq!(t.hlen(b"hexp", 500).unwrap(), 0);
        assert!(t.get(b"hexp", 600).unwrap().is_none());

        // FIELD-TTL fallback: non-empty map → original path reaps the expired field.
        let mut u = Store::new();
        u.hset(b"h2", b"live".to_vec(), b"1".to_vec(), 1).unwrap();
        u.hset(b"h2", b"dead".to_vec(), b"2".to_vec(), 1).unwrap();
        u.hash_field_expires
            .insert((b"h2".to_vec(), b"dead".to_vec()), 50);
        assert!(!u.hash_field_expires.is_empty());
        assert!(
            !u.hexists(b"h2", b"dead", 500).unwrap(),
            "expired field invisible to HEXISTS"
        );
        assert!(u.hexists(b"h2", b"live", 500).unwrap());
        assert_eq!(u.hlen(b"h2", 600).unwrap(), 1, "HLEN excludes reaped field");

        // Timing headline HLEN@8fields (no field TTL, LFU off).
        let mut b = Store::new();
        for i in 0..8u32 {
            b.hset(
                b"benchhash:key",
                format!("f{i}").into_bytes(),
                b"v".to_vec(),
                1,
            )
            .unwrap();
        }
        let k: &[u8] = b"benchhash:key";
        for _ in 0..2000 {
            std::hint::black_box(b.hlen(std::hint::black_box(k), 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.hlen(std::hint::black_box(k), 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "HLEN@8fields no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) ZADD/ZINCRBY bare-drop guard must be byte-identical, incl the
    // expires_count>0 branch: an expired zset key is evicted before the write (so ZADD
    // creates a fresh set / ZINCRBY starts from 0), exactly as the unguarded call did.
    #[test]
    fn zadd_zincrby_drop_guard_matches_and_evicts_expired() {
        use crate::ZaddOptions;
        // No-TTL path: normal add/increment.
        let mut s = Store::new();
        assert_eq!(s.expires_count, 0);
        assert_eq!(
            s.zadd(b"z", &[(1.0, b"a".to_vec()), (2.0, b"b".to_vec())], 1)
                .unwrap(),
            2
        );
        assert_eq!(s.zadd(b"z", &[(3.0, b"a".to_vec())], 1).unwrap(), 0); // update, not new
        assert_eq!(s.zscore(b"z", b"a", 1).unwrap(), Some(3.0));
        let inc = s
            .zincrby_with_options(b"z", b"a".to_vec(), 1.5, ZaddOptions::default(), 1)
            .unwrap();
        assert_eq!(inc, Some(4.5));

        // expires_count>0 branch: expired zset key evicted, then ZADD makes a fresh set.
        let mut t = Store::new();
        t.zadd(b"exp", &[(9.0, b"old".to_vec())], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1); // due by t=500
        assert!(t.expires_count >= 1);
        // ZADD at t=500 must not see the expired "old"; fresh set with only "new".
        assert_eq!(t.zadd(b"exp", &[(1.0, b"new".to_vec())], 500).unwrap(), 1);
        assert_eq!(
            t.zscore(b"exp", b"old", 500).unwrap(),
            None,
            "expired member gone"
        );
        assert_eq!(t.zscore(b"exp", b"new", 500).unwrap(), Some(1.0));

        // ZINCRBY on an expired key starts fresh from 0.
        let mut u = Store::new();
        u.zadd(b"e2", &[(100.0, b"m".to_vec())], 1).unwrap();
        u.expire_at_milliseconds(b"e2", 50, 1);
        let r = u
            .zincrby_with_options(b"e2", b"m".to_vec(), 5.0, ZaddOptions::default(), 500)
            .unwrap();
        assert_eq!(r, Some(5.0), "ZINCRBY on expired key starts from 0");

        // Timing headline: ZADD update on existing key (no TTL, LFU off).
        let mut b = Store::new();
        b.zadd(b"benchz:key", &[(1.0, b"m".to_vec())], 1).unwrap();
        let k: &[u8] = b"benchz:key";
        let m = &[(2.0, b"m".to_vec())];
        for _ in 0..2000 {
            b.zadd(std::hint::black_box(k), m, 2).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            b.zadd(std::hint::black_box(k), m, 2).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "ZADD update no-TTL guarded: full={full:.2} ns | elided drop's probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) ZREMRANGEBYRANK/BYSCORE/BYLEX bare-drop guard: byte-identical removal
    // counts + the expires_count>0 branch still evicts an expired key (→ removes 0).
    #[test]
    fn zremrangeby_drop_guard_matches_and_evicts_expired() {
        let seed = |s: &mut Store, key: &[u8]| {
            s.zadd(
                key,
                &[
                    (1.0, b"a".to_vec()),
                    (2.0, b"b".to_vec()),
                    (3.0, b"c".to_vec()),
                    (4.0, b"d".to_vec()),
                ],
                1,
            )
            .unwrap();
        };
        // No-TTL path: correct range removals.
        let mut s = Store::new();
        seed(&mut s, b"zr");
        assert_eq!(s.zremrangebyrank(b"zr", 0, 1, 2).unwrap(), 2); // removes a,b
        assert_eq!(s.zcard(b"zr", 2).unwrap(), 2);
        let mut s3 = Store::new();
        s3.zadd(
            b"zl",
            &[
                (0.0, b"a".to_vec()),
                (0.0, b"b".to_vec()),
                (0.0, b"c".to_vec()),
            ],
            1,
        )
        .unwrap();
        assert_eq!(s3.zremrangebylex(b"zl", b"[a", b"[b", 2).unwrap(), 2); // a,b
        assert_eq!(s3.zcard(b"zl", 2).unwrap(), 1);
        // Missing key → 0.
        assert_eq!(s.zremrangebyrank(b"absent", 0, -1, 2).unwrap(), 0);

        // expires_count>0 branch: expired key evicted first → 0 removed.
        let mut t = Store::new();
        seed(&mut t, b"exp");
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert!(t.expires_count >= 1);
        assert_eq!(
            t.zremrangebyrank(b"exp", 0, -1, 500).unwrap(),
            0,
            "expired key removes nothing"
        );
        assert!(t.get(b"exp", 600).unwrap().is_none(), "expired key evicted");

        // Timing headline: ZREMRANGEBYRANK on an out-of-range (no-op) existing key, no TTL.
        let mut b = Store::new();
        for i in 0..16u32 {
            b.zadd(
                b"benchzr:key",
                &[(f64::from(i), format!("m{i}").into_bytes())],
                1,
            )
            .unwrap();
        }
        let k: &[u8] = b"benchzr:key";
        for _ in 0..2000 {
            b.zremrangebyrank(std::hint::black_box(k), 100, 200, 2).ok();
        } // empty range → no removal
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            b.zremrangebyrank(std::hint::black_box(k), 100, 200, 2).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "ZREMRANGEBYRANK no-op no-TTL guarded: full={full:.2} ns | elided drop probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) ZADD (zadd_plain_owned) get_mut-first collapse: byte-identical across
    // new-key create (single + multi member), existing-key update, WRONGTYPE, empty-members,
    // and the returned add-count / resulting scores.
    #[test]
    fn zadd_plain_owned_get_mut_first_matches() {
        // New key, single member.
        let mut s = Store::new();
        assert_eq!(
            s.zadd_plain_owned(b"z1", vec![(1.0, b"a".to_vec())], 1)
                .unwrap(),
            1
        );
        assert_eq!(s.zscore(b"z1", b"a", 1).unwrap(), Some(1.0));
        // New key, multi member (with a dup → dedup keeps last).
        let mut s2 = Store::new();
        assert_eq!(
            s2.zadd_plain_owned(
                b"z2",
                vec![
                    (1.0, b"a".to_vec()),
                    (2.0, b"b".to_vec()),
                    (9.0, b"a".to_vec())
                ],
                1
            )
            .unwrap(),
            2
        );
        assert_eq!(s2.zscore(b"z2", b"a", 1).unwrap(), Some(9.0));
        assert_eq!(s2.zscore(b"z2", b"b", 1).unwrap(), Some(2.0));
        // Existing key: add new + update existing.
        assert_eq!(
            s2.zadd_plain_owned(b"z2", vec![(5.0, b"b".to_vec()), (3.0, b"c".to_vec())], 1)
                .unwrap(),
            1
        ); // c new; b updated (not counted)
        assert_eq!(s2.zscore(b"z2", b"b", 1).unwrap(), Some(5.0));
        assert_eq!(s2.zscore(b"z2", b"c", 1).unwrap(), Some(3.0));
        assert_eq!(s2.zcard(b"z2", 1).unwrap(), 3);
        // Empty members: 0, on both new and existing key.
        let mut s3 = Store::new();
        assert_eq!(s3.zadd_plain_owned(b"new", vec![], 1).unwrap(), 0);
        assert!(s3.zscore(b"new", b"x", 1).unwrap().is_none());
        s3.zadd_plain_owned(b"exist", vec![(1.0, b"m".to_vec())], 1)
            .unwrap();
        assert_eq!(s3.zadd_plain_owned(b"exist", vec![], 1).unwrap(), 0);
        // WRONGTYPE on existing string key.
        s3.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        assert!(matches!(
            s3.zadd_plain_owned(b"str", vec![(1.0, b"a".to_vec())], 1),
            Err(StoreError::WrongType)
        ));
        // Lazy-expiry: expired zset key → fresh set.
        let mut t = Store::new();
        t.zadd_plain_owned(b"exp", vec![(9.0, b"old".to_vec())], 1)
            .unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert_eq!(
            t.zadd_plain_owned(b"exp", vec![(1.0, b"new".to_vec())], 500)
                .unwrap(),
            1
        );
        assert!(t.zscore(b"exp", b"old", 500).unwrap().is_none());

        // Timing: ZADD update-existing (no TTL, LFU off) — the path that drops contains_key.
        let mut b = Store::new();
        b.zadd_plain_owned(b"benchz:key", vec![(1.0, b"m".to_vec())], 1)
            .unwrap();
        let k: &[u8] = b"benchz:key";
        for _ in 0..2000 {
            b.zadd_plain_owned(std::hint::black_box(k), vec![(2.0, b"m".to_vec())], 2)
                .ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            b.zadd_plain_owned(std::hint::black_box(k), vec![(2.0, b"m".to_vec())], 2)
                .ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "ZADD update-existing no-TTL get_mut-first: full={full:.2} ns | dropped contains_key ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) PFADD bare-drop guard: byte-identical add/estimate behavior + the
    // expires_count>0 branch still evicting an expired HLL before the add.
    #[test]
    fn pfadd_drop_guard_matches_and_evicts_expired() {
        // No-TTL: create + add.
        let mut s = Store::new();
        assert_eq!(s.expires_count, 0);
        assert!(
            s.pfadd(b"hll", &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec()], 1)
                .unwrap()
        ); // new → changed
        assert!(!s.pfadd(b"hll", &[b"a".to_vec()], 1).unwrap()); // dup → no change
        assert!(s.pfadd(b"hll", &[b"d".to_vec()], 1).unwrap()); // new elem → changed
        let n = s.pfcount(&[b"hll"], 1).unwrap();
        assert!((3..=5).contains(&n), "≈4 distinct, got {n}");

        // WRONGTYPE on a non-HLL string.
        s.set(b"str".to_vec(), b"notanhll".to_vec(), None, 1);
        assert!(s.pfadd(b"str", &[b"x".to_vec()], 1).is_err());

        // expires_count>0 branch: an expired HLL is evicted, then PFADD makes a fresh one.
        let mut t = Store::new();
        t.pfadd(b"exp", &[b"x".to_vec(), b"y".to_vec(), b"z".to_vec()], 1)
            .unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1); // due by t=500
        assert!(t.expires_count >= 1);
        assert!(t.pfadd(b"exp", &[b"only".to_vec()], 500).unwrap()); // fresh HLL
        assert_eq!(
            t.pfcount(&[&b"exp"[..]], 500).unwrap(),
            1,
            "only the post-expiry element counts"
        );

        // Timing: PFADD an already-present element on an existing HLL (no TTL, no change).
        let mut b = Store::new();
        for i in 0..16u32 {
            b.pfadd(b"benchhll:key", &[format!("e{i}").into_bytes()], 1)
                .unwrap();
        }
        let k: &[u8] = b"benchhll:key";
        let e = &[b"e3".to_vec()];
        for _ in 0..2000 {
            b.pfadd(std::hint::black_box(k), e, 2).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            b.pfadd(std::hint::black_box(k), e, 2).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "PFADD present-elem no-TTL guarded: full={full:.2} ns | elided drop probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) HMGET key-lookup collapse (field-TTL-gated): byte-identical values,
    // WRONGTYPE, hit/miss, owned vs borrowed parity, AND the non-empty-map fallback still
    // reaping an expired field.
    #[test]
    fn hmget_key_lookup_collapse_and_field_ttl_fallback() {
        let mut s = Store::new();
        s.hset(b"h", b"a".to_vec(), b"1".to_vec(), 1).unwrap();
        s.hset(b"h", b"b".to_vec(), b"2".to_vec(), 1).unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        assert!(s.hash_field_expires.is_empty());
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let req: &[&[u8]] = &[b"a", b"missing", b"b"];
        assert_eq!(
            s.hmget(b"h", req, 2).unwrap(),
            vec![Some(b"1".to_vec()), None, Some(b"2".to_vec())]
        );
        // borrowed parity.
        let mut borrowed = Vec::new();
        s.hmget_for_each(b"h", req, 2, |v| borrowed.push(v.map(<[u8]>::to_vec)))
            .unwrap();
        assert_eq!(
            borrowed,
            vec![Some(b"1".to_vec()), None, Some(b"2".to_vec())]
        );
        // Missing key → all None.
        assert_eq!(s.hmget(b"absent", req, 2).unwrap(), vec![None, None, None]);
        // WRONGTYPE.
        assert!(matches!(
            s.hmget(b"str", req, 2),
            Err(StoreError::WrongType)
        ));
        // hits: hmget(h), hmget_for_each(h), hmget(str wrongtype) = 3; misses: hmget(absent) = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 3);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);

        // Key lazy-expiry via HMGET.
        let mut t = Store::new();
        t.hset(b"hexp", b"a".to_vec(), b"1".to_vec(), 1).unwrap();
        t.expire_at_milliseconds(b"hexp", 50, 1);
        assert_eq!(t.hmget(b"hexp", &[b"a"], 500).unwrap(), vec![None]);
        assert!(t.get(b"hexp", 600).unwrap().is_none());

        // FIELD-TTL fallback (non-empty map → original path): expired field reads None,
        // live field reads its value.
        let mut u = Store::new();
        u.hset(b"h2", b"live".to_vec(), b"L".to_vec(), 1).unwrap();
        u.hset(b"h2", b"dead".to_vec(), b"D".to_vec(), 1).unwrap();
        u.hash_field_expires
            .insert((b"h2".to_vec(), b"dead".to_vec()), 50);
        assert!(!u.hash_field_expires.is_empty());
        assert_eq!(
            u.hmget(b"h2", &[b"live", b"dead"], 500).unwrap(),
            vec![Some(b"L".to_vec()), None]
        );

        // Timing headline HMGET@8 fields (no field TTL, LFU off).
        let mut b = Store::new();
        for i in 0..8u32 {
            b.hset(
                b"benchhash:key",
                format!("f{i}").into_bytes(),
                b"v".to_vec(),
                1,
            )
            .unwrap();
        }
        let k: &[u8] = b"benchhash:key";
        let q: Vec<Vec<u8>> = (0..8u32).map(|i| format!("f{i}").into_bytes()).collect();
        let qr: Vec<&[u8]> = q.iter().map(Vec::as_slice).collect();
        for _ in 0..2000 {
            std::hint::black_box(b.hmget(std::hint::black_box(k), &qr, 2)).ok();
        }
        let reps = 1_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.hmget(std::hint::black_box(k), &qr, 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "HMGET@8 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) GETDEL non-LFU collapse (triple→double probe): byte-identical value +
    // removal, WRONGTYPE without removal, missing→None, integer value, key lazy-expiry, stats.
    #[test]
    fn getdel_collapse_matches_full_path() {
        let mut s = Store::new();
        s.set(b"k".to_vec(), b"v".to_vec(), None, 1);
        s.set(b"n".to_vec(), b"12345".to_vec(), None, 1); // may be int-encoded
        s.rpush(b"lst", &[b"a".to_vec()], 1).unwrap();
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        // Do all four getdels FIRST (only these count toward the stat window), capturing
        // results — the removal-verification reads below record their own stats.
        let r_k = s.getdel(b"k", 2);
        let r_n = s.getdel(b"n", 2);
        let r_absent = s.getdel(b"absent", 2);
        let r_lst = s.getdel(b"lst", 2);
        // hits: getdel(k), getdel(n), getdel(lst wrongtype) = 3; misses: getdel(absent) = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 3);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        // Results.
        assert_eq!(r_k.unwrap(), Some(b"v".to_vec()));
        assert_eq!(r_n.unwrap(), Some(b"12345".to_vec())); // int-encoded → decimal bytes
        assert_eq!(r_absent.unwrap(), None);
        assert!(matches!(r_lst, Err(StoreError::WrongType)));
        // Removal / non-removal (these reads happen AFTER the stat assertion).
        assert!(
            s.get(b"k", 2).unwrap().is_none(),
            "GETDEL removed the string key"
        );
        assert!(s.get(b"n", 2).unwrap().is_none());
        assert_eq!(
            s.llen(b"lst", 2).unwrap(),
            1,
            "WRONGTYPE GETDEL must not delete"
        );

        // Lazy-expiry: expired key → None + evicted.
        let mut t = Store::new();
        t.set(b"exp".to_vec(), b"v".to_vec(), Some(50), 1);
        assert!(t.expires_count >= 1);
        assert_eq!(t.getdel(b"exp", 500).unwrap(), None, "expired key → None");
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing: GETDEL collapse removes ONE of the former THREE keyspace probes
        // (record_keyspace_lookup + get + remove → lookup_live + remove). Measure that
        // removed probe (a keyspace hash+lookup) in isolation; GETDEL's own baseline
        // (get + remove + value extract) is ~40-50 ns, so this is a ~1.2x-class win.
        let mut b = Store::new();
        let k: &[u8] = b"getdel:bench:key";
        b.set(k.to_vec(), b"v".to_vec(), None, 2);
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t2 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t2.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!("GETDEL collapse: removed 1 of 3 keyspace probes ≈ {probe:.2} ns/probe");
    }

    // (CrimsonHawk) getrange_with non-LFU single-lookup collapse: byte-identical resolved
    // slice for positive/negative/out-of-range bounds, empty for missing/miss, WRONGTYPE,
    // keyspace hit/miss, and key lazy-expiry.
    #[test]
    fn getrange_with_collapse_matches_full_path() {
        let get = |s: &mut Store, k: &[u8], a: i64, b: i64| -> Result<Vec<u8>, StoreError> {
            s.getrange_with(k, a, b, 2, <[u8]>::to_vec)
        };
        let mut s = Store::new();
        s.set(b"str".to_vec(), b"Hello World".to_vec(), None, 1);
        s.rpush(b"lst", &[b"x".to_vec()], 1).unwrap();
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let r_full = get(&mut s, b"str", 0, -1);
        let r_sub = get(&mut s, b"str", 0, 4);
        let r_neg = get(&mut s, b"str", -5, -1);
        let r_oob = get(&mut s, b"str", 100, 200);
        let r_absent = get(&mut s, b"absent", 0, -1);
        let r_wrong = get(&mut s, b"lst", 0, -1);
        // hits: str×4 + lst(wrongtype) = 5; misses: absent = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 5);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_full.unwrap(), b"Hello World".to_vec());
        assert_eq!(r_sub.unwrap(), b"Hello".to_vec());
        assert_eq!(r_neg.unwrap(), b"World".to_vec());
        assert_eq!(r_oob.unwrap(), Vec::<u8>::new());
        assert_eq!(r_absent.unwrap(), Vec::<u8>::new());
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));

        // Lazy-expiry: at now=500 the key (deadline 1+50=51) is due → empty + evicted.
        let mut t = Store::new();
        t.set(b"exp".to_vec(), b"data".to_vec(), Some(50), 1);
        assert_eq!(
            t.getrange_with(b"exp", 0, -1, 500, <[u8]>::to_vec).unwrap(),
            Vec::<u8>::new()
        );
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing headline (present string, no TTL, LFU off).
        let mut b = Store::new();
        b.set(b"gr:bench:key".to_vec(), vec![b'x'; 32], None, 2);
        let k: &[u8] = b"gr:bench:key";
        for _ in 0..2000 {
            std::hint::black_box(b.getrange_with(k, 0, 31, 2, |v| v.len())).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.getrange_with(std::hint::black_box(k), 0, 31, 2, |v| v.len()))
                .ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "GETRANGE@32 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) GETSET non-LFU collapse: byte-identical old-value return + overwrite,
    // WRONGTYPE-without-overwrite, missing→None+set, TTL cleared on overwrite, stats, eviction.
    #[test]
    fn getset_collapse_matches_full_path() {
        let mut s = Store::new();
        s.set(b"k".to_vec(), b"old".to_vec(), None, 1);
        s.rpush(b"lst", &[b"x".to_vec()], 1).unwrap();
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        // GETSET on present key → old value returned, new value set.
        let r_present = s.getset(b"k".to_vec(), b"new", 2);
        // GETSET on missing key → None, new value set.
        let r_missing = s.getset(b"fresh".to_vec(), b"v", 2);
        // GETSET on wrong type → Err (no overwrite).
        let r_wrong = s.getset(b"lst".to_vec(), b"z", 2);
        // hits: k (present), lst (wrongtype) = 2; misses: fresh = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 2);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_present.unwrap(), Some(b"old".to_vec()));
        assert_eq!(r_missing.unwrap(), None);
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));
        // Overwrites / non-overwrite (verification reads AFTER stat assertion).
        assert_eq!(s.get(b"k", 2).unwrap(), Some(b"new".to_vec()));
        assert_eq!(s.get(b"fresh", 2).unwrap(), Some(b"v".to_vec()));
        assert_eq!(
            s.llen(b"lst", 2).unwrap(),
            1,
            "WRONGTYPE GETSET must not overwrite"
        );

        let mut z = Store::new();
        z.set(b"k".to_vec(), vec![b'x'; 4096], None, 1);
        z.rpush(b"lst", &[b"x".to_vec()], 1).unwrap();
        let mut borrowed_old = None;
        z.getset_with(b"k", b"new", 2, |old| {
            borrowed_old = old.map(<[u8]>::to_vec)
        })
        .unwrap();
        assert_eq!(borrowed_old, Some(vec![b'x'; 4096]));
        assert_eq!(z.get(b"k", 2).unwrap(), Some(b"new".to_vec()));
        let mut missing_old = Some(Vec::new());
        z.getset_with(b"fresh", b"v", 2, |old| {
            missing_old = old.map(<[u8]>::to_vec)
        })
        .unwrap();
        assert_eq!(missing_old, None);
        assert!(matches!(
            z.getset_with(b"lst", b"z", 2, |_| ()),
            Err(StoreError::WrongType)
        ));
        assert_eq!(z.llen(b"lst", 2).unwrap(), 1);

        let mut lfu = Store::new();
        lfu.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        lfu.set(b"lfu".to_vec(), b"old".to_vec(), None, 1);
        assert_eq!(lfu.object_freq(b"lfu", 1), Some(LFU_INIT_VAL));
        let mut lfu_old = None;
        lfu.getset_with(b"lfu", b"new", 2, |old| lfu_old = old.map(<[u8]>::to_vec))
            .unwrap();
        assert_eq!(lfu_old, Some(b"old".to_vec()));
        assert_eq!(lfu.get(b"lfu", 2).unwrap(), Some(b"new".to_vec()));
        assert!(
            lfu.object_freq(b"lfu", 2).unwrap() >= LFU_INIT_VAL,
            "GETSET under LFU must preserve the access-bumped counter"
        );

        // TTL is cleared on overwrite: key with a TTL, GETSET, then it must NOT expire.
        let mut u = Store::new();
        u.set(b"t".to_vec(), b"a".to_vec(), Some(50), 1); // deadline 51
        assert!(u.expires_count >= 1);
        assert_eq!(
            u.getset(b"t".to_vec(), b"b", 10).unwrap(),
            Some(b"a".to_vec())
        ); // at t=10, live
        assert_eq!(u.expires_count, 0, "GETSET cleared the TTL");
        assert_eq!(
            u.get(b"t", 1000).unwrap(),
            Some(b"b".to_vec()),
            "no expiry after GETSET"
        );

        // Lazy-expiry: GETSET on an expired key → old None, new set.
        let mut w = Store::new();
        w.set(b"e".to_vec(), b"gone".to_vec(), Some(50), 1);
        assert_eq!(
            w.getset(b"e".to_vec(), b"fresh", 500).unwrap(),
            None,
            "expired old → None"
        );
        assert_eq!(w.get(b"e", 600).unwrap(), Some(b"fresh".to_vec()));

        // Timing: GETSET overwriting a present key (no TTL, LFU off).
        let mut b = Store::new();
        b.set(b"gs:bench:key".to_vec(), b"v".to_vec(), None, 2);
        let k: &[u8] = b"gs:bench:key";
        for _ in 0..2000 {
            std::hint::black_box(b.getset(k.to_vec(), b"v", 2)).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.getset(std::hint::black_box(k).to_vec(), b"v", 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "GETSET overwrite no-TTL collapsed: full={full:.2} ns (incl key.to_vec alloc) | \
             removed 1 keyspace probe ≈ {probe:.2} ns",
        );
    }

    // (CrimsonHawk) ZCOUNT non-LFU collapse: byte-identical count, inverted-bounds→0 (incl the
    // redis quirk that inverted-range on a WRONG-TYPE key returns 0, NOT WrongType), missing→0,
    // WRONGTYPE (valid range), keyspace hit/miss, key lazy-expiry.
    #[test]
    fn zcount_collapse_matches_full_path() {
        use crate::ScoreBound::Inclusive;
        let mut s = Store::new();
        s.zadd(
            b"z",
            &[
                (1.0, b"a".to_vec()),
                (2.0, b"b".to_vec()),
                (3.0, b"c".to_vec()),
                (4.0, b"d".to_vec()),
            ],
            1,
        )
        .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let r_range = s.zcount(b"z", Inclusive(1.0), Inclusive(3.0), 2); // a,b,c = 3
        let r_inv = s.zcount(b"z", Inclusive(5.0), Inclusive(1.0), 2); // inverted → 0
        let r_absent = s.zcount(b"absent", Inclusive(0.0), Inclusive(9.0), 2); // 0
        let r_wrong = s.zcount(b"str", Inclusive(0.0), Inclusive(9.0), 2); // valid range → WrongType
        let r_wrong_inv = s.zcount(b"str", Inclusive(9.0), Inclusive(0.0), 2); // inverted on string → 0 (quirk)
        // hits: z(range), z(inv), str(wrongtype), str(inv-quirk) = 4; misses: absent = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 4);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_range.unwrap(), 3);
        assert_eq!(r_inv.unwrap(), 0);
        assert_eq!(r_absent.unwrap(), 0);
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));
        assert_eq!(
            r_wrong_inv.unwrap(),
            0,
            "inverted range on wrong-type key returns 0, not WrongType"
        );

        // Exclusive bounds.
        assert_eq!(
            s.zcount(
                b"z",
                crate::ScoreBound::Exclusive(1.0),
                crate::ScoreBound::Exclusive(4.0),
                2
            )
            .unwrap(),
            2
        ); // b,c

        // Lazy-expiry: expired zset key → 0 + evicted.
        let mut t = Store::new();
        t.zadd(b"exp", &[(1.0, b"m".to_vec())], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert_eq!(
            t.zcount(b"exp", Inclusive(0.0), Inclusive(9.0), 500)
                .unwrap(),
            0
        );
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing (present zset, no TTL, LFU off).
        let mut b = Store::new();
        for i in 0..16u32 {
            b.zadd(
                b"zc:bench",
                &[(f64::from(i), format!("m{i}").into_bytes())],
                1,
            )
            .unwrap();
        }
        let k: &[u8] = b"zc:bench";
        for _ in 0..2000 {
            std::hint::black_box(b.zcount(k, Inclusive(0.0), Inclusive(15.0), 2)).ok();
        }
        let reps = 2_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.zcount(
                std::hint::black_box(k),
                Inclusive(0.0),
                Inclusive(15.0),
                2,
            ))
            .ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "ZCOUNT@16 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) LPOS non-LFU collapse + ZLEXCOUNT bare-drop guard: byte-identical.
    #[test]
    fn lpos_zlexcount_collapse_and_guard_match() {
        let mut s = Store::new();
        s.rpush(
            b"lst",
            &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec(), b"b".to_vec()],
            1,
        )
        .unwrap();
        s.zadd(
            b"z",
            &[
                (0.0, b"a".to_vec()),
                (0.0, b"b".to_vec()),
                (0.0, b"c".to_vec()),
            ],
            1,
        )
        .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        // LPOS (records keyspace stat).
        let r_found = s.lpos(b"lst", b"b", 2); // first at index 1
        let r_none = s.lpos(b"lst", b"zzz", 2);
        let r_absent = s.lpos(b"absent", b"b", 2);
        let r_wrong = s.lpos(b"str", b"b", 2);
        // hits: found, none, wrong = 3; misses: absent = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 3);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_found.unwrap(), Some(1));
        assert_eq!(r_none.unwrap(), None);
        assert_eq!(r_absent.unwrap(), None);
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));

        // ZLEXCOUNT (NO keyspace stat — records nothing).
        let (h1, m1) = (s.stat_keyspace_hits, s.stat_keyspace_misses);
        assert_eq!(s.zlexcount(b"z", b"[a", b"[c", 2).unwrap(), 3);
        assert_eq!(s.zlexcount(b"z", b"[a", b"[b", 2).unwrap(), 2);
        assert_eq!(s.zlexcount(b"z", b"-", b"+", 2).unwrap(), 3);
        assert_eq!(s.zlexcount(b"absent", b"-", b"+", 2).unwrap(), 0);
        assert!(matches!(
            s.zlexcount(b"str", b"-", b"+", 2),
            Err(StoreError::WrongType)
        ));
        assert_eq!(
            s.stat_keyspace_hits, h1,
            "ZLEXCOUNT records no keyspace hit"
        );
        assert_eq!(
            s.stat_keyspace_misses, m1,
            "ZLEXCOUNT records no keyspace miss"
        );

        // Lazy-expiry: LPOS + ZLEXCOUNT on expired keys.
        let mut t = Store::new();
        t.rpush(b"lexp", &[b"a".to_vec()], 1).unwrap();
        t.expire_at_milliseconds(b"lexp", 50, 1);
        assert_eq!(t.lpos(b"lexp", b"a", 500).unwrap(), None);
        assert!(t.get(b"lexp", 600).unwrap().is_none());
        let mut u = Store::new();
        u.zadd(b"zexp", &[(0.0, b"m".to_vec())], 1).unwrap();
        u.expire_at_milliseconds(b"zexp", 50, 1);
        assert_eq!(u.zlexcount(b"zexp", b"-", b"+", 500).unwrap(), 0);
        assert!(u.get(b"zexp", 600).unwrap().is_none());

        // Timing headline LPOS (present list, no TTL, LFU off).
        let mut b = Store::new();
        let members: Vec<Vec<u8>> = (0..16u32).map(|i| format!("m{i}").into_bytes()).collect();
        b.rpush(b"lpos:bench", &members, 1).unwrap();
        let k: &[u8] = b"lpos:bench";
        for _ in 0..2000 {
            std::hint::black_box(b.lpos(k, b"m8", 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.lpos(std::hint::black_box(k), b"m8", 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "LPOS@16 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) lpos_full unified-acquire collapse: byte-identical across RANK (fwd/rev),
    // COUNT (single/all/limited), MAXLEN, WRONGTYPE, missing, stats, and key lazy-expiry.
    #[test]
    fn lpos_full_unified_collapse_matches() {
        let mut s = Store::new();
        // list: a b a c a b  (indices 0..5)
        s.rpush(
            b"l",
            &[
                b"a".to_vec(),
                b"b".to_vec(),
                b"a".to_vec(),
                b"c".to_vec(),
                b"a".to_vec(),
                b"b".to_vec(),
            ],
            1,
        )
        .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let r_first = s.lpos_full(b"l", b"a", 1, None, 0, 2); // first "a" → [0]
        let r_all = s.lpos_full(b"l", b"a", 1, Some(0), 0, 2); // all "a" → [0,2,4]
        let r_rank2 = s.lpos_full(b"l", b"a", 2, None, 0, 2); // 2nd "a" → [2]
        let r_rev = s.lpos_full(b"l", b"a", -1, None, 0, 2); // last "a" → [4]
        let r_rev_all = s.lpos_full(b"l", b"a", -1, Some(0), 0, 2); // rev all → [4,2,0]
        let r_count2 = s.lpos_full(b"l", b"a", 1, Some(2), 0, 2); // first 2 → [0,2]
        let r_maxlen = s.lpos_full(b"l", b"a", 1, Some(0), 2, 2); // scan only first 2 → [0]
        let r_absent = s.lpos_full(b"absent", b"a", 1, None, 0, 2); // empty
        let r_wrong = s.lpos_full(b"str", b"a", 1, None, 0, 2); // WrongType
        // hits: l×7 + str(wrongtype) = 8; misses: absent = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 8);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_first.unwrap(), vec![0]);
        assert_eq!(r_all.unwrap(), vec![0, 2, 4]);
        assert_eq!(r_rank2.unwrap(), vec![2]);
        assert_eq!(r_rev.unwrap(), vec![4]);
        assert_eq!(r_rev_all.unwrap(), vec![4, 2, 0]);
        assert_eq!(r_count2.unwrap(), vec![0, 2]);
        assert_eq!(r_maxlen.unwrap(), vec![0]);
        assert_eq!(r_absent.unwrap(), Vec::<usize>::new());
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));

        // Lazy-expiry.
        let mut t = Store::new();
        t.rpush(b"exp", &[b"a".to_vec()], 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert_eq!(
            t.lpos_full(b"exp", b"a", 1, None, 0, 500).unwrap(),
            Vec::<usize>::new()
        );
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing (LPOS COUNT all on a present 16-elem list, no TTL, LFU off).
        let mut b = Store::new();
        let members: Vec<Vec<u8>> = (0..16u32).map(|i| format!("m{i}").into_bytes()).collect();
        b.rpush(b"lpf:bench", &members, 1).unwrap();
        let k: &[u8] = b"lpf:bench";
        for _ in 0..2000 {
            std::hint::black_box(b.lpos_full(k, b"m8", 1, Some(0), 0, 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.lpos_full(std::hint::black_box(k), b"m8", 1, Some(0), 0, 2))
                .ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "LPOS_FULL@16 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) XLEN/XRANGE/XREVRANGE single-lookup collapse: byte-identical count,
    // range results (fwd/rev + COUNT), empty-range, WRONGTYPE, missing, stats, lazy-expiry.
    #[test]
    fn xstream_read_collapse_matches_full_path() {
        let mut s = Store::new();
        s.xadd(b"st", (1, 0), &[(b"f".to_vec(), b"a".to_vec())], 1)
            .unwrap();
        s.xadd(b"st", (2, 0), &[(b"f".to_vec(), b"b".to_vec())], 1)
            .unwrap();
        s.xadd(b"st", (3, 0), &[(b"f".to_vec(), b"c".to_vec())], 1)
            .unwrap();
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let ids = |v: &[crate::StreamRecord]| -> Vec<(u64, u64)> {
            v.iter().map(|(id, _)| (id.0, id.1)).collect()
        };
        let r_len = s.xlen(b"st", 2);
        let r_range = s.xrange(b"st", (0, 0), (u64::MAX, u64::MAX), None, 2);
        let r_rev = s.xrevrange(b"st", (u64::MAX, u64::MAX), (0, 0), None, 2);
        let r_count = s.xrange(b"st", (0, 0), (u64::MAX, u64::MAX), Some(2), 2);
        let r_absent_len = s.xlen(b"absent", 2);
        let r_absent_range = s.xrange(b"absent", (0, 0), (u64::MAX, u64::MAX), None, 2);
        let r_wrong = s.xlen(b"str", 2);
        // hits: xlen(st), xrange(st), xrevrange(st), xrange-count(st), xlen(str wrongtype) = 5;
        // misses: xlen(absent), xrange(absent) = 2.
        assert_eq!(s.stat_keyspace_hits, h0 + 5);
        assert_eq!(s.stat_keyspace_misses, m0 + 2);
        assert_eq!(r_len.unwrap(), 3);
        assert_eq!(ids(&r_range.unwrap()), vec![(1, 0), (2, 0), (3, 0)]);
        assert_eq!(ids(&r_rev.unwrap()), vec![(3, 0), (2, 0), (1, 0)]);
        assert_eq!(ids(&r_count.unwrap()), vec![(1, 0), (2, 0)]);
        assert_eq!(r_absent_len.unwrap(), 0);
        assert_eq!(r_absent_range.unwrap(), Vec::new());
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));

        // Lazy-expiry.
        let mut t = Store::new();
        t.xadd(b"exp", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 1)
            .unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert_eq!(t.xlen(b"exp", 500).unwrap(), 0);
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing headline XLEN (present stream, no TTL, LFU off).
        let mut b = Store::new();
        for i in 1..=16u64 {
            b.xadd(b"xl:bench", (i, 0), &[(b"f".to_vec(), b"v".to_vec())], 1)
                .unwrap();
        }
        let k: &[u8] = b"xl:bench";
        for _ in 0..2000 {
            std::hint::black_box(b.xlen(k, 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.xlen(std::hint::black_box(k), 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "XLEN@16 no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

    // (CrimsonHawk) COPY / copy_no_stat (MOVE) bare-drop guards: byte-identical copy
    // success/REPLACE/no-overwrite/missing + the expires_count>0 branch still evicting
    // expired source (→ fail) and destination (→ REPLACE copies over it).
    #[test]
    fn copy_drop_guard_matches_and_evicts_expired() {
        // No-TTL path.
        let mut s = Store::new();
        s.set(b"src".to_vec(), b"v".to_vec(), None, 1);
        assert_eq!(s.expires_count, 0);
        assert!(s.copy(b"src", b"dst", false, 2).unwrap()); // copied
        assert_eq!(s.get(b"dst", 2).unwrap(), Some(b"v".to_vec()));
        assert!(!s.copy(b"src", b"dst", false, 2).unwrap()); // dst exists, no replace → false
        s.set(b"src".to_vec(), b"v2".to_vec(), None, 2);
        assert!(s.copy(b"src", b"dst", true, 2).unwrap()); // replace
        assert_eq!(s.get(b"dst", 2).unwrap(), Some(b"v2".to_vec()));
        assert!(!s.copy(b"absent", b"d2", false, 2).unwrap()); // missing source → false
        // copy_no_stat (MOVE backend).
        let mut m = Store::new();
        m.set(b"a".to_vec(), b"x".to_vec(), None, 1);
        assert!(m.copy_no_stat(b"a", b"b", false, 2).unwrap());
        assert_eq!(m.get(b"b", 2).unwrap(), Some(b"x".to_vec()));

        // expires_count>0 branch: expired SOURCE → copy fails (source evicted).
        let mut t = Store::new();
        t.set(b"src".to_vec(), b"v".to_vec(), Some(50), 1); // deadline 51
        assert!(t.expires_count >= 1);
        assert!(
            !t.copy(b"src", b"dst", false, 500).unwrap(),
            "expired source → no copy"
        );
        assert!(
            t.get(b"src", 600).unwrap().is_none(),
            "expired source evicted"
        );

        // expires_count>0: expired DESTINATION with REPLACE → dst evicted, copy over it.
        let mut u = Store::new();
        u.set(b"src".to_vec(), b"new".to_vec(), None, 1);
        u.set(b"dst".to_vec(), b"old".to_vec(), Some(50), 1); // dst deadline 51
        assert!(u.copy(b"src", b"dst", true, 500).unwrap());
        assert_eq!(u.get(b"dst", 600).unwrap(), Some(b"new".to_vec()));

        // Timing: the guard elides 2 keyspace probes on the no-TTL COPY path.
        let mut b = Store::new();
        b.set(b"cp:bench:src".to_vec(), b"v".to_vec(), None, 2);
        let k: &[u8] = b"cp:bench:src";
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t0 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t0.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "COPY/MOVE guard: elided 2 keyspace probes ≈ {:.2} ns total (2 × {probe:.2} ns)",
            2.0 * probe
        );
    }

    // (CrimsonHawk) XPENDING summary/entries is_stream collapse: byte-identical key-lookup
    // behavior (hit/miss, WRONGTYPE, missing→None) + unchanged group-state access.
    #[test]
    fn xpending_is_stream_collapse_matches() {
        let mut s = Store::new();
        s.xadd(b"st", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 1)
            .unwrap();
        assert!(s.xgroup_create(b"st", b"g1", (0, 0), false, 1).unwrap());
        s.set(b"str".to_vec(), b"v".to_vec(), None, 1);
        let (h0, m0) = (s.stat_keyspace_hits, s.stat_keyspace_misses);

        let r_group = s.xpending_summary(b"st", b"g1", 2); // group exists, 0 pending
        let r_nogroup = s.xpending_summary(b"st", b"nope", 2); // group absent → None
        let r_absent = s.xpending_summary(b"absent", b"g1", 2); // key absent → None (miss)
        let r_wrong = s.xpending_summary(b"str", b"g1", 2); // wrong type → WrongType
        let r_ent =
            s.xpending_entries(b"st", b"g1", ((0, 0), (u64::MAX, u64::MAX)), 10, None, 2, 0);
        let r_ent_wrong = s.xpending_entries(
            b"str",
            b"g1",
            ((0, 0), (u64::MAX, u64::MAX)),
            10,
            None,
            2,
            0,
        );
        // hits: summary(st), summary(st-nogroup), summary(str-wrong), entries(st), entries(str-wrong) = 5;
        // misses: summary(absent) = 1.
        assert_eq!(s.stat_keyspace_hits, h0 + 5);
        assert_eq!(s.stat_keyspace_misses, m0 + 1);
        assert_eq!(r_group.unwrap().map(|(n, _, _, _)| n), Some(0)); // 0 pending
        assert_eq!(r_nogroup.unwrap(), None);
        assert_eq!(r_absent.unwrap(), None);
        assert!(matches!(r_wrong, Err(StoreError::WrongType)));
        assert_eq!(r_ent.unwrap(), Some(Vec::new())); // group exists, no pending
        assert!(matches!(r_ent_wrong, Err(StoreError::WrongType)));

        // Lazy-expiry: expired stream → summary None + evicted.
        let mut t = Store::new();
        t.xadd(b"exp", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 1)
            .unwrap();
        t.xgroup_create(b"exp", b"g", (0, 0), false, 1).unwrap();
        t.expire_at_milliseconds(b"exp", 50, 1);
        assert_eq!(t.xpending_summary(b"exp", b"g", 500).unwrap(), None);
        assert!(t.get(b"exp", 600).unwrap().is_none());

        // Timing: xpending_summary on a present stream+group (no TTL, LFU off).
        let mut b = Store::new();
        b.xadd(b"xp:bench", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 1)
            .unwrap();
        b.xgroup_create(b"xp:bench", b"g", (0, 0), false, 1)
            .unwrap();
        let k: &[u8] = b"xp:bench";
        for _ in 0..2000 {
            std::hint::black_box(b.xpending_summary(k, b"g", 2)).ok();
        }
        let reps = 3_000_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(b.xpending_summary(std::hint::black_box(k), b"g", 2)).ok();
        }
        let full = t0.elapsed().as_nanos() as f64 / reps as f64;
        let inner = 20_000_000u64;
        let mut acc = 0u64;
        let t1 = std::time::Instant::now();
        for _ in 0..inner {
            acc += u64::from(b.entries.contains_key(std::hint::black_box(k)));
        }
        let probe = t1.elapsed().as_nanos() as f64 / inner as f64;
        std::hint::black_box(acc);
        println!(
            "XPENDING summary no-TTL collapsed: full={full:.2} ns | removed 2nd probe ≈ {probe:.2} ns \
             ⇒ old ≈ {:.2} ns = {:.2}x",
            full + probe,
            (full + probe) / full
        );
    }

