    #[test]
    fn dbsize_counts_live_keys() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"b".to_vec(), b"2".to_vec(), Some(100), 0);
        assert_eq!(store.dbsize_in_db(0), 2);

        // dbsize is O(1) and does not actively reap expired keys.
        // It should still return 2 even if 'b' is logically expired,
        // until 'b' is actively or lazily reaped.
        assert_eq!(store.dbsize_in_db(0), 2);

        // Lazy reap
        store.get(b"b", 200).unwrap();
        assert_eq!(store.dbsize_in_db(0), 1);
    }

    #[test]
    fn flushdb_clears_all() {
        let mut store = Store::new();
        store.set(b"a".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"b".to_vec(), b"2".to_vec(), None, 0);
        store.flushdb();
        assert!(store.is_empty());
    }

    #[test]
    fn flushdb_releases_keyspace_index_capacity_nf1er() {
        let mut store = Store::new();
        for i in 0..4096_u32 {
            let key = format!("key:{i:04}").into_bytes();
            let expires_at = if i % 2 == 0 { Some(60_000) } else { None };
            store.set(key, b"value".to_vec(), expires_at, 0);
        }

        let (_cursor, _batch) = store.scan(0, None, 10, 0);
        assert!(store.randomkey(0).is_some());
        let before_entries = store.entries.capacity();
        let before_expiry_deadlines = store.expiry_deadlines.capacity();
        let before_random_slots = store.random_key_slots[0].keys.capacity();
        let before_scan_cache = store.scan_cache.capacity();
        assert!(before_entries > 0);
        assert!(before_expiry_deadlines > 0);
        assert!(before_random_slots > 0);
        assert!(before_scan_cache > 0);

        store.flushdb();

        assert!(store.is_empty());
        assert_eq!(store.entries.capacity(), 0);
        assert_eq!(store.expiry_deadlines.capacity(), 0);
        assert_eq!(store.random_key_slots[0].keys.capacity(), 0);
        assert_eq!(store.scan_cache.capacity(), 0);
    }

    #[test]
    fn flush_database_releases_keyspace_index_capacity_when_empty_nf1er() {
        let mut store = Store::new();
        for i in 0..4096_u32 {
            let key = encode_db_key(3, format!("key:{i:04}").as_bytes());
            store.set(key, b"value".to_vec(), Some(60_000), 0);
        }

        assert!(store.randomkey_in_db(3, 0).is_some());
        let before_entries = store.entries.capacity();
        let before_expiry_deadlines = store.expiry_deadlines.capacity();
        let before_random_slots = store.random_key_slots[3].keys.capacity();
        assert!(before_entries > 0);
        assert!(before_expiry_deadlines > 0);
        assert!(before_random_slots > 0);

        assert_eq!(store.flush_database(3), 4096);

        assert!(store.is_empty());
        assert_eq!(store.entries.capacity(), 0);
        assert_eq!(store.expiry_deadlines.capacity(), 0);
        assert_eq!(store.random_key_slots[3].keys.capacity(), 0);
    }

    #[test]
    fn flushdb_clears_ordered_keys_and_hash_field_expires() {
        // (frankenredis-ss2k0) Real bug: flushdb cleared `entries` but
        // not `ordered_keys`, so KEYS/SCAN/RANDOMKEY surfaced ghost
        // key names after FLUSHALL — clients saw "the database is
        // empty (DBSIZE=0) but RANDOMKEY returned a name". hash_field_
        // expires was similarly orphaned, breaking HTTL on hashes
        // re-created with the same key after a flush.
        let mut store = Store::new();
        store.set(b"alpha".to_vec(), b"1".to_vec(), None, 0);
        store.set(b"beta".to_vec(), b"2".to_vec(), None, 0);
        store
            .hset(b"h", b"f".to_vec(), b"v".to_vec(), 0)
            .expect("hset");
        // Set a per-field TTL so hash_field_expires is non-empty.
        store
            .hash_field_expires
            .insert((b"h".to_vec(), b"f".to_vec()), 10_000);

        store.flushdb();

        // All visible state is empty.
        assert!(store.is_empty());
        assert!(store.ordered_keys.is_empty(), "ordered_keys must be empty");
        assert!(
            store.hash_field_expires.is_empty(),
            "hash_field_expires must be empty after flush"
        );

        // KEYS/SCAN/RANDOMKEY surface contracts: nothing to enumerate.
        assert_eq!(
            store.keys_matching(b"*", 0),
            Vec::<Vec<u8>>::new(),
            "KEYS * after flush must be empty"
        );
    }

    #[test]
    fn write_hot_keyspace_defers_ordered_key_index_until_ordered_read_uhthd() {
        let mut store = Store::new();
        for i in 0..128_u32 {
            store.set(format!("k:{i:03}").into_bytes(), b"v".to_vec(), None, 0);
        }

        assert!(
            store.ordered_keys.is_empty(),
            "SET-only keyspaces must not keep the sorted side index resident"
        );
        assert!(store.ordered_keys_dirty);
        assert_eq!(store.all_keys().len(), 128);
        assert!(
            store.ordered_keys.is_empty(),
            "snapshot-style all_keys must stay non-resident when the index is dirty"
        );

        let keys = store.keys_matching_in_db(0, b"k:*", 0);
        assert_eq!(keys.len(), 128);
        assert_eq!(
            store.ordered_keys.len(),
            store.entries.len(),
            "ordered commands must rebuild the sorted index exactly once"
        );
        assert!(!store.ordered_keys_dirty);

        store.set(b"k:new".to_vec(), b"v".to_vec(), None, 0);
        assert!(
            store.ordered_keys.is_empty(),
            "the next structural write drops the ordered side index again"
        );
        assert!(store.ordered_keys_dirty);
    }

    #[test]
    fn swap_prefixes_preserves_hash_field_ttls() {
        // (frankenredis-sdmwz) SWAPDB silently dropped per-field hash
        // TTLs because internal_entries_remove cleared
        // hash_field_expires for the source key but the swap loop
        // never re-inserted them at the destination prefix. Pin the
        // round-trip: a hash with field TTLs swapped from the "db0:"
        // prefix to "db1:" must surface the same TTLs at the new key.
        let mut store = Store::new();
        store
            .hset(b"db0:h", b"f".to_vec(), b"v".to_vec(), 0)
            .expect("hset");
        store
            .hash_field_expires
            .insert((b"db0:h".to_vec(), b"f".to_vec()), 99_999);
        // Also seed an unrelated key in the right prefix to ensure we
        // don't migrate ttls across keys that should stay in place.
        store
            .hset(b"db1:other", b"x".to_vec(), b"y".to_vec(), 0)
            .expect("hset other");

        let touched = store.swap_prefixes(b"db0:", b"db1:");
        assert!(touched >= 2, "swap should touch both source + dst keys");

        // Field TTL must follow the hash to its new key.
        assert_eq!(
            store
                .hash_field_expires
                .get(&(b"db1:h".to_vec(), b"f".to_vec())),
            Some(&99_999),
            "field TTL must follow the hash through SWAPDB"
        );
        assert!(
            !store
                .hash_field_expires
                .contains_key(&(b"db0:h".to_vec(), b"f".to_vec())),
            "old (db0:h, f) row must be gone"
        );
    }

    // (frankenredis-x8kef) SWAPDB now enumerates each DB's keys via the ordered
    // index instead of scanning the whole keyspace twice. The enumerated set must
    // be byte-identical to the old `entries.keys().filter(db)` set, and finding a
    // small DB in a large keyspace must be O(log n + db_size), not O(total).
    #[test]
    fn swapdb_db_enumeration_isomorphic_and_faster_swapdb() {
        use super::{Store, encode_db_key};

        // Old reference: full-keyspace scan + db-membership filter.
        fn old_enum(store: &Store, db: usize) -> Vec<Vec<u8>> {
            let mut v: Vec<Vec<u8>> = store
                .entries
                .keys()
                .filter(|key| {
                    super::decode_db_key(key)
                        .map(|(d, _)| d == db)
                        .unwrap_or(db == 0)
                })
                .map(|k| k.to_vec())
                .collect();
            v.sort();
            v
        }

        // Isomorphism across DBs 0,1,2,3 on a mixed keyspace.
        let mut store = Store::new();
        for i in 0..600u32 {
            let db = (i % 4) as usize;
            store.set(
                encode_db_key(db, format!("k{i:04}").as_bytes()),
                b"v".to_vec(),
                None,
                0,
            );
        }
        for db in 0..4usize {
            let mut got = store.ordered_physical_keys_in_db(db);
            got.sort();
            assert_eq!(got, old_enum(&store, db), "db {db} enumeration mismatch");
        }

        // A/B: 200k keys in DB 0, ~50 in DB 3. Old scans all 200_050 keys; new
        // walks only DB 3's prefix range.
        let mut store = Store::new();
        for i in 0..200_000u32 {
            store.set(format!("k{i:08}").into_bytes(), b"v".to_vec(), None, 0);
        }
        for i in 0..50u32 {
            store.set(
                encode_db_key(3, format!("d{i:04}").as_bytes()),
                b"v".to_vec(),
                None,
                0,
            );
        }
        let reps = 2000;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc += old_enum(&store, 3).len();
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 += store.ordered_physical_keys_in_db(3).len();
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2);
        println!(
            "SWAPDB db-enumeration A/B (200050 keys, find 50 in DB3, x{reps}): old(full scan)={old_ns}ns new(prefix range)={new_ns}ns ratio={:.0}x",
            old_ns as f64 / new_ns as f64
        );
        assert!(
            old_ns as f64 / new_ns as f64 > 2.0 || cfg!(debug_assertions),
            "expected >2x"
        );
    }

    #[test]
    fn command_histogram_record_canonicalizes_and_reports_ab_ratio() {
        use super::{CommandHistogramTracker, CommandRecordKind};
        // Case-insensitive canonicalization: SET/set/Set all land on "set", and
        // the count aggregates (byte-identical to the to_ascii_lowercase path).
        // (frankenredis-igx7w)
        let mut t = CommandHistogramTracker::default();
        t.record_with_kind("SET", 10, CommandRecordKind::Success);
        t.record_with_kind("set", 20, CommandRecordKind::Success);
        t.record_with_kind("Set", 30, CommandRecordKind::Success);
        t.record_with_kind("GET", 5, CommandRecordKind::Success);
        let all = t.all();
        let keys: Vec<&str> = all.iter().map(|(k, _)| *k).collect();
        assert_eq!(keys, vec!["get", "set"], "canonical lowercase keys");
        // Long-name (>40 bytes) fallback path stays correct.
        let long = "x".repeat(60);
        let long_upper = long.to_uppercase();
        t.record_with_kind(&long_upper, 1, CommandRecordKind::Success);
        assert!(t.get(&long).is_some(), "long-name fallback canonicalizes");
        // Container subcommand fullnames ("config|get") canonicalize too.
        t.record_with_kind("CONFIG|GET", 1, CommandRecordKind::Success);
        assert!(t.get("config|get").is_some());

        // A/B: per-command record() — stack-buffer probe vs the old
        // entry(to_ascii_lowercase()) heap-allocating path.
        fn old_record(t: &mut CommandHistogramTracker, command: &str) {
            // mirror the prior implementation (allocates every call)
            t.record_with_kind(&command.to_ascii_lowercase(), 1, CommandRecordKind::Success);
        }
        let cmds = [
            "SET", "GET", "HSET", "INCR", "LPUSH", "ZADD", "EXPIRE", "MGET",
        ];
        let reps = 2_000_000usize;
        let mut t1 = CommandHistogramTracker::default();
        let t0 = std::time::Instant::now();
        for i in 0..reps {
            old_record(&mut t1, std::hint::black_box(cmds[i & 7]));
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t1);
        let mut t2 = CommandHistogramTracker::default();
        let s0 = std::time::Instant::now();
        for i in 0..reps {
            t2.record_with_kind(
                std::hint::black_box(cmds[i & 7]),
                1,
                CommandRecordKind::Success,
            );
        }
        let new_ns = s0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t2);
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "command-stats record A/B (x{reps}): old(alloc)={old_ns}ns new(stackbuf)={new_ns}ns ratio={ratio:.2}x"
        );
    }

    // (frankenredis-par0e) The borrowed-write fast path records commandstats via
    // record_canonical_with_kind (skips per-command lowercase+utf8) and the new
    // lpush/rpush/sadd direct fields. Prove byte-identical histogram state vs the
    // canonicalizing record_with_kind path for every relevant command, plus the
    // record A/B ratio for the lpush hot path.
    #[test]
    fn command_histogram_canonical_fastpath_matches_record_with_kind_and_reports_ab_ratio() {
        use super::{CommandHistogram, CommandHistogramTracker, CommandRecordKind};

        fn snapshot(t: &CommandHistogramTracker) -> Vec<(String, CommandHistogram)> {
            t.all()
                .into_iter()
                .map(|(k, h)| (k.to_string(), h.clone()))
                .collect()
        }

        // Same (canonical-lowercase) names + latencies + kinds through both paths.
        let samples: &[(&str, u64, CommandRecordKind)] = &[
            ("lpush", 3, CommandRecordKind::Success),
            ("lpush", 7, CommandRecordKind::Failed),
            ("rpush", 11, CommandRecordKind::Success),
            ("sadd", 1, CommandRecordKind::Rejected),
            ("sadd", 99, CommandRecordKind::Success),
            ("get", 2, CommandRecordKind::Success),
            ("set", 5, CommandRecordKind::Success),
            ("hset", 4, CommandRecordKind::Success),
            ("zadd", 8, CommandRecordKind::Failed),
        ];

        let mut canonical = CommandHistogramTracker::default();
        let mut classic = CommandHistogramTracker::default();
        for &(name, lat, kind) in samples {
            canonical.record_canonical_with_kind(name, lat, kind);
            classic.record_with_kind(name, lat, kind);
        }
        assert_eq!(
            snapshot(&canonical),
            snapshot(&classic),
            "canonical fast-path histogram state must equal record_with_kind"
        );
        // The hot-write direct fields are reachable via get(), case-insensitively.
        for name in ["lpush", "rpush", "sadd"] {
            assert_eq!(
                canonical.get(name).map(|h| h.calls),
                classic.get(&name.to_uppercase()).map(|h| h.calls),
                "{name} direct-field lookup must match (case-insensitive)"
            );
            assert!(canonical.get(name).is_some(), "{name} must be recorded");
        }
        // reset() accounts for the new fields too.
        assert_eq!(canonical.reset(&[]), classic.reset(&[]));

        // A/B: record the lpush hot path — old canonicalizing path
        // (lowercase + from_utf8 + HashMap probe) vs new direct-field canonical.
        let reps = 3_000_000usize;
        let mut t1 = CommandHistogramTracker::default();
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            t1.record_with_kind(std::hint::black_box("lpush"), 1, CommandRecordKind::Success);
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t1);
        let mut t2 = CommandHistogramTracker::default();
        let s0 = std::time::Instant::now();
        for _ in 0..reps {
            t2.record_canonical_with_kind(
                std::hint::black_box("lpush"),
                1,
                CommandRecordKind::Success,
            );
        }
        let new_ns = s0.elapsed().as_nanos().max(1);
        std::hint::black_box(&t2);
        println!(
            "lpush commandstats record A/B (x{reps}): old(lowercase+utf8+hashmap)={old_ns}ns new(direct field)={new_ns}ns ratio={:.2}x",
            old_ns as f64 / new_ns as f64
        );
    }

    #[test]
    fn prepared_glob_matches_glob_match_for_every_pattern_and_string() {
        use super::{glob_match, glob_prepare};
        // The prepared matcher (classify once) MUST agree with glob_match (classify per call) for
        // EVERY (pattern, string) — a divergence would change SCAN/KEYS output. Covers the literal
        // fast-path shapes (exact/prefix/suffix/contains), the general backtracker, empty strings,
        // and metachars.
        let patterns: &[&[u8]] = &[
            b"", b"*", b"**", b"?", b"a", b"abc", b"key:0001*", b"*.tmp", b"*mid*", b"user:*:tag",
            b"h?llo", b"h[ae]llo", b"foo*bar", b"\\*lit", b"[!a]", b"a?c*e", b"", b"prefix",
        ];
        let strings: &[&[u8]] = &[
            b"", b"a", b"abc", b"key:00012:tag", b"key:9:x", b"file.tmp", b".tmp", b"XmidY",
            b"user:42:tag", b"hello", b"hallo", b"fooXYZbar", b"foobar", b"*lit", b"!", b"prefix",
            b"prefixed", b"h\0llo",
        ];
        for p in patterns {
            let prepared = glob_prepare(p);
            for s in strings {
                assert_eq!(
                    prepared.matches(s),
                    glob_match(p, s),
                    "pattern={p:?} string={s:?}"
                );
            }
        }
    }

    #[test]
    fn scan_filter_matches_scan_pattern_matches_for_every_pattern_and_string() {
        use super::{scan_pattern_matches, ScanFilter};
        // The hoisted SSCAN filter (classify once) MUST agree with `scan_pattern_matches`
        // (classify per member) for EVERY (pattern, member) — a divergence would change
        // SSCAN output. Beyond the glob shapes this pins the two allkeys shortcuts
        // (`None` and a lone `*`, which match the EMPTY member — where `glob_match` alone
        // would drop it) and that `**`/`?` do NOT match the empty member.
        let patterns: &[Option<&[u8]>] = &[
            None,
            Some(b"*"),
            Some(b"**"),
            Some(b"?"),
            Some(b""),
            Some(b"a"),
            Some(b"member:0001*"),
            Some(b"*:tag"),
            Some(b"*mid*"),
            Some(b"m[ae]mber"),
            Some(b"foo*bar"),
            Some(b"\\*lit"),
        ];
        let members: &[&[u8]] = &[
            b"",
            b"a",
            b"member:00012:tag",
            b"member:9",
            b"XmidY",
            b"mamber",
            b"fooXYZbar",
            b"*lit",
            b"tag",
            b":tag",
        ];
        for p in patterns {
            let filter = ScanFilter::prepare(*p);
            for s in members {
                assert_eq!(
                    filter.matches(s),
                    scan_pattern_matches(*p, s),
                    "pattern={p:?} member={s:?}"
                );
            }
        }
    }

    #[test]
    fn glob_match_patterns() {
        use super::glob_match;
        assert!(glob_match(b"*", b"anything"));
        assert!(glob_match(b"h?llo", b"hello"));
        assert!(glob_match(b"h?llo", b"hallo"));
        assert!(!glob_match(b"h?llo", b"hllo"));
        assert!(glob_match(b"h[ae]llo", b"hello"));
        assert!(glob_match(b"h[ae]llo", b"hallo"));
        assert!(!glob_match(b"h[ae]llo", b"hillo"));
        assert!(glob_match(b"h[^e]llo", b"hallo"));
        assert!(!glob_match(b"h[^e]llo", b"hello"));
        assert!(glob_match(b"h[a-e]llo", b"hcllo"));
        assert!(!glob_match(b"h[a-e]llo", b"hzllo"));
        assert!(glob_match(b"foo*bar", b"fooXYZbar"));
        assert!(glob_match(b"foo*bar", b"foobar"));
        assert!(glob_match(b"\\*literal", b"*literal"));
        assert!(glob_match(b"[z-a]", b"m"));
        assert!(glob_match(b"[\\-]", b"-"));
        assert!(glob_match(b"[a-]", b"]"));
        assert!(glob_match(b"[a-]", b"a"));
        assert!(glob_match(b"[abc", b"a"));
        assert!(glob_match(b"[abc", b"c"));
        assert!(!glob_match(b"[abc", b"["));
        assert!(glob_match(b"[!a]", b"!"));
        assert!(glob_match(b"[!a]", b"a"));
        assert!(!glob_match(b"[!a]", b"b"));
        assert!(!glob_match(b"[literal", b"[literal"));
        assert!(!glob_match(b"[a-", b"[a-"));
        assert!(!glob_match(b"[literal", b"literal"));
        // (frankenredis-z9dc3) empty string matches ONLY the empty pattern; a single
        // `*` matches the empty key via the KEYS/SCAN allkeys shortcut, not here, so
        // `*`/`**`/`?` must all be non-matches against "" (mirrors stringmatchlen).
        assert!(glob_match(b"", b""));
        assert!(!glob_match(b"*", b""));
        assert!(!glob_match(b"**", b""));
        assert!(!glob_match(b"***", b""));
        assert!(!glob_match(b"?", b""));
        assert!(!glob_match(b"a*", b""));
        // mid-match exhaustion is unaffected: trailing stars still match.
        assert!(glob_match(b"a**", b"a"));
        assert!(glob_match(b"a*", b"a"));
    }

