    #[test]
    fn hset_and_hget() {
        let mut store = Store::new();
        assert!(store.hset(b"h", b"f1".to_vec(), b"v1".to_vec(), 0).unwrap());
        assert!(!store.hset(b"h", b"f1".to_vec(), b"v2".to_vec(), 0).unwrap());
        assert_eq!(store.hget(b"h", b"f1", 0).unwrap(), Some(b"v2".to_vec()));
        assert_eq!(store.hget(b"h", b"missing", 0).unwrap(), None);
        assert_eq!(store.hget(b"nokey", b"f1", 0).unwrap(), None);
    }

    #[test]
    fn hset_existing_hash_bumps_lfu_frequency() -> Result<(), String> {
        let mut store = Store::new();
        store.maxmemory_policy = MaxmemoryPolicy::AllkeysLfu;
        store.lfu_decay_time = 0;
        store
            .hset(b"h", b"f".to_vec(), b"v1".to_vec(), 0)
            .map_err(|err| format!("seed hash failed: {err:?}"))?;

        match store.object_freq(b"h", 0) {
            Some(LFU_INIT_VAL) => {}
            other => return Err(format!("new hash LFU frequency mismatch: {other:?}")),
        }
        match store
            .hset(b"h", b"f".to_vec(), b"v2".to_vec(), 1)
            .map_err(|err| format!("hset update failed: {err:?}"))?
        {
            false => {}
            true => return Err("HSET update incorrectly reported a new field".to_string()),
        }
        match store.object_freq(b"h", 1) {
            Some(6) => {}
            other => return Err(format!("HSET should bump LFU frequency, got {other:?}")),
        }
        Ok(())
    }

