    // (frankenredis-zkkn4) Frozen fingerprint of the full-ZSCAN sequence.
    const ZSCANRT_GOLDEN: u64 = 0xbc1a_8d4b_00ab_b681;

    // (frankenredis e3y73) ZSCAN must honour Redis's SCAN guarantee: a member
    // present for the WHOLE iteration is returned at least once, even if OTHER
    // members are deleted mid-scan (the canonical ZSCAN + ZREM loop). Before the
    // fix the cursor was a positional rank index, so deleting an already-returned
    // member shifted later members down a rank and the next batch stepped over a
    // present-throughout member. This drives that pattern and asserts nothing is
    // missed. (Sibling of the keyspace-SCAN fix 55cfc0966.)
    #[test]
    fn zscan_returns_present_throughout_member_after_mid_scan_deletion() {
        use super::Store;

        let mut store = Store::new();
        // >128 members => skiplist/hashtable (Full) encoding, so ZSCAN paginates
        // (the listpack encoding one-shots at cursor 0 and is not affected).
        let n = 500usize;
        for i in 0..n {
            store
                .zadd(b"z", &[(i as f64, format!("m{i:04}").into_bytes())], 0)
                .unwrap();
        }

        let mut seen: std::collections::HashSet<Vec<u8>> = std::collections::HashSet::new();
        let mut deleted: std::collections::HashSet<Vec<u8>> = std::collections::HashSet::new();
        let mut cursor = 0u64;
        let mut batches = 0usize;
        loop {
            let (next, batch) = store.zscan(b"z", cursor, None, 10, 0).unwrap();
            for (m, _) in &batch {
                seen.insert(m.clone());
            }
            batches += 1;
            // After the first batch, ZREM two members we already returned (the
            // lowest ones) — the "scan then delete what you saw" loop.
            if batches == 1 {
                let mut lows: Vec<Vec<u8>> = batch.iter().map(|(m, _)| m.clone()).collect();
                lows.sort();
                for m in lows.into_iter().take(2) {
                    let removed = store.zrem(b"z", &[m.as_slice()], 0).unwrap();
                    assert_eq!(removed, 1, "victim member must exist");
                    deleted.insert(m);
                }
            }
            if next == 0 {
                break;
            }
            cursor = next;
            assert!(batches < 1_000_000, "zscan did not terminate");
        }

        let mut missing = Vec::new();
        for i in 0..n {
            let m = format!("m{i:04}").into_bytes();
            if !deleted.contains(&m) && !seen.contains(&m) {
                missing.push(String::from_utf8_lossy(&m).into_owned());
            }
        }
        assert!(
            missing.is_empty(),
            "ZSCAN guarantee violated: present-throughout members never returned: {missing:?}"
        );
    }

    // (frankenredis-zkkn4) ZSCAN treap-resume: a full ZSCAN returns exactly the
    // zset's members in iter_asc order filtered by pattern (the old skip walk's
    // output) — identical whether or not the order-statistic treap is built —
    // across COUNT sizes and patterns; pinned by a golden. Plus a Score microbench
    // of a full ZSCAN with the treap built (O(log N + batch) resume via
    // index_slice_asc) vs not built (the O(start) skip fallback = old behavior).
    #[test]
    fn zscan_treap_resume_isomorphic_and_faster_zscanrt() {
        use super::{Store, encode_db_key};

        fn full_zscan(
            store: &mut Store,
            key: &[u8],
            pat: Option<&[u8]>,
            count: usize,
        ) -> Vec<(Vec<u8>, f64)> {
            let mut all = Vec::new();
            let mut cursor = 0u64;
            for _ in 0..1_000_000 {
                let (next, batch) = store.zscan(key, cursor, pat, count, 0).unwrap();
                all.extend(batch);
                if next == 0 {
                    break;
                }
                cursor = next;
            }
            all
        }

        let mut st: u64 = 0xA5A5_5A5A_1234_9876;
        let mut next = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };

        for _ in 0..60 {
            // >128 members forces the skiplist/hashtable encoding (this path).
            let n = 130 + (next() % 140) as usize;
            // Distinct ascending scores => iter_asc order == insertion (i) order.
            let members: Vec<(Vec<u8>, f64)> = (0..n)
                .map(|i| (format!("m{i:05}_{}", next() % 7).into_bytes(), i as f64))
                .collect();
            let pat: Option<&[u8]> = match next() % 3 {
                0 => None,
                1 => Some(b"*_4"),
                _ => Some(b"m000*"),
            };
            let count = 1 + (next() % 16) as usize;
            let reference: Vec<(Vec<u8>, f64)> = members
                .iter()
                .filter(|(m, _)| pat.is_none_or(|p| super::glob_match(p, m)))
                .cloned()
                .collect();

            // Without the treap (fresh zset -> index_slice_asc falls back to skip).
            let mut s_cold = Store::new();
            for (m, sc) in &members {
                s_cold.zadd(b"z", &[(*sc, m.clone())], 0).unwrap();
            }
            assert_eq!(
                full_zscan(&mut s_cold, b"z", pat, count),
                reference,
                "ZSCAN cold diverged n={n} count={count}"
            );

            // With the treap built (zrank triggers the build -> O(log N) resume).
            let mut s_hot = Store::new();
            for (m, sc) in &members {
                s_hot.zadd(b"z", &[(*sc, m.clone())], 0).unwrap();
            }
            s_hot.zrank(b"z", &members[0].0, 0).unwrap();
            assert_eq!(
                full_zscan(&mut s_hot, b"z", pat, count),
                reference,
                "ZSCAN hot diverged n={n} count={count}"
            );

            for (m, sc) in &reference {
                fnv(&mut golden, m);
                fnv(&mut golden, &sc.to_bits().to_le_bytes());
            }
            fnv(&mut golden, &[0xFF]);
            let _ = encode_db_key;
        }
        assert_eq!(
            golden, ZSCANRT_GOLDEN,
            "ZSCAN sequence fingerprint changed: {golden:#018x} (golden {ZSCANRT_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: ONE deep-cursor ZSCAN batch. (frankenredis-5l66d) index_slice_asc
        // is now adaptive, so a *full* cold ZSCAN self-warms partway through and no
        // longer has a slow baseline to compare against. A *single* deep-cursor
        // batch is exactly one warm-hit — below the 2-hit warm threshold — so the
        // cold store still takes the O(start) skip (old behavior), while a store
        // whose treap is already built resumes in O(log N + batch). This isolates
        // the per-call treap-resume win the adaptive path delivers once warm. Only
        // the zscan call is timed; the cold rebuild is excluded.
        let build = || {
            let mut s = Store::new();
            for i in 0..20_000u32 {
                s.zadd(b"z", &[(i as f64, format!("m{i:06}").into_bytes())], 0)
                    .unwrap();
            }
            s
        };
        let deep_cursor = 19_500u64;
        let reps = 20;
        let mut cold_ns = 0u128;
        for _ in 0..reps {
            let mut s = build(); // fresh -> cold (1 hit < 2-hit warm threshold)
            let t = std::time::Instant::now();
            let (_c, batch) = s.zscan(b"z", deep_cursor, None, 10, 0).unwrap();
            cold_ns += t.elapsed().as_nanos();
            std::hint::black_box(batch.len());
        }
        let cold_ns = (cold_ns / reps as u128).max(1);
        let mut s_warm = build();
        s_warm.zrank(b"z", b"m000000", 0).unwrap(); // build the order-statistic treap
        std::hint::black_box(
            s_warm
                .zscan(b"z", deep_cursor, None, 10, 0)
                .unwrap()
                .1
                .len(),
        );
        let mut warm_ns = 0u128;
        for _ in 0..reps {
            let t = std::time::Instant::now();
            let (_c, batch) = s_warm.zscan(b"z", deep_cursor, None, 10, 0).unwrap();
            warm_ns += t.elapsed().as_nanos();
            std::hint::black_box(batch.len());
        }
        let warm_ns = (warm_ns / reps as u128).max(1);
        let score = cold_ns as f64 / warm_ns as f64;
        eprintln!(
            "ZSCANRT deep ZSCAN @{deep_cursor}: cold(skip)={cold_ns}ns warm(treap)={warm_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "treap-resume deep ZSCAN must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-3e92e) Frozen fingerprint of the full-SCAN key sequence.
    const SCANLIN_GOLDEN: u64 = 0x1c26_adeb_28a1_0c87;

    // (frankenredis-3e92e) SCAN resume fast-path: a full scan with the resume
    // cache enabled must return the EXACT same key sequence as with the cache
    // disabled (the old O(N²/batch) skip walk) — across COUNT sizes and patterns,
    // and it must stay correct across an intervening keyspace mutation (the
    // generation guard forces a fallback). Pinned by a golden fingerprint; plus a
    // Score microbench of full-scan-to-completion old (cache off) vs new.
    #[test]
    fn scan_resume_cache_isomorphic_and_faster_scanlin() {
        use super::{Store, encode_db_key};

        // Drive a full SCAN to completion; `disable_cache` clears the resume
        // cache before each call to reproduce the old skip-only behavior.
        fn full_scan(
            store: &mut Store,
            pattern: Option<&[u8]>,
            count: usize,
            disable_cache: bool,
        ) -> Vec<Vec<u8>> {
            let mut all = Vec::new();
            let mut cursor = 0u64;
            for _ in 0..1_000_000 {
                if disable_cache {
                    store.scan_cache.clear();
                }
                let (next, batch) = store.scan(cursor, pattern, count, 0);
                all.extend(batch);
                if next == 0 {
                    break;
                }
                cursor = next;
            }
            all
        }

        let mut st: u64 = 0x1234_5678_9ABC_DEF0;
        let mut next = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };

        for _ in 0..120 {
            let nkeys = (next() % 400) as usize;
            let mut store = Store::new();
            for _ in 0..nkeys {
                let klen = 1 + (next() % 8) as usize;
                let key: Vec<u8> = (0..klen)
                    .map(|_| b"abc:xyz_0123"[(next() % 12) as usize])
                    .collect();
                store.set(encode_db_key(0, &key), b"v".to_vec(), None, 0);
            }
            let pat: Option<&[u8]> = match next() % 3 {
                0 => None,
                1 => Some(b"a*"),
                _ => Some(b"*1*"),
            };
            let count = 1 + (next() % 20) as usize;
            // Cache-on (new) and cache-off (old) full scans must be identical.
            let with_cache = full_scan(&mut store, pat, count, false);
            let without_cache = full_scan(&mut store, pat, count, true);
            assert_eq!(
                with_cache, without_cache,
                "SCAN cache-on vs cache-off diverged (nkeys={nkeys} count={count} pat={pat:?})"
            );
            for k in &with_cache {
                fnv(&mut golden, k);
            }
            fnv(&mut golden, &[0xFF]);
        }

        // Mutation mid-scan: the generation guard forces the fast path to fall
        // back, so cache-on reproduces cache-off EXACTLY even when the keyspace
        // changes between calls (fr's position cursor is intentionally not
        // mutation-stable — the point is that the cache changes nothing).
        {
            let build = || {
                let mut s = Store::new();
                for i in 0..500u32 {
                    s.set(
                        encode_db_key(0, format!("k{i:04}").as_bytes()),
                        b"v".to_vec(),
                        None,
                        0,
                    );
                }
                s
            };
            let run = |store: &mut Store, disable_cache: bool| -> Vec<Vec<u8>> {
                let mut out = Vec::new();
                let mut cursor = 0u64;
                let mut step = 0;
                loop {
                    if disable_cache {
                        store.scan_cache.clear();
                    }
                    let (nextc, batch) = store.scan(cursor, None, 7, 0);
                    out.extend(batch);
                    step += 1;
                    if step == 3 {
                        store.set(encode_db_key(0, b"zzz_new"), b"v".to_vec(), None, 0);
                        store.del(&[encode_db_key(0, b"k0001")], 0);
                    }
                    if nextc == 0 || step > 100_000 {
                        break;
                    }
                    cursor = nextc;
                }
                out
            };
            let mut s_on = build();
            let mut s_off = build();
            assert_eq!(
                run(&mut s_on, false),
                run(&mut s_off, true),
                "scan-under-mutation: cache-on diverged from cache-off"
            );
        }

        assert_eq!(
            golden, SCANLIN_GOLDEN,
            "SCAN sequence fingerprint changed: {golden:#018x} (golden {SCANLIN_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: full SCAN to completion of a 20k keyspace at COUNT 10 — the
        // O(N²/batch) skip walk vs the O(N) resume cache.
        let mut store = Store::new();
        for i in 0..20_000u32 {
            store.set(
                encode_db_key(0, format!("key:{i:06}").as_bytes()),
                b"v".to_vec(),
                None,
                0,
            );
        }
        let reps = 6;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(full_scan(&mut store, None, 10, true).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(full_scan(&mut store, None, 10, false).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new returned different totals");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "SCANLIN full scan 20k @ COUNT 10: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "resume-cache SCAN must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-n9am7) scan_in_db drives the real SCAN command. A full
    // iteration must equal the ground-truth (all live, glob+TYPE-matched logical
    // keys in the DB, sorted) for every db / pattern / type / count, and a deep
    // resumed call must be O(log n + count) vs the old materialise-all-and-sort.
    #[test]
    fn scan_in_db_isomorphic_and_faster_scandb() {
        use super::{Store, ValueType, encode_db_key, glob_match};

        fn drive(
            store: &mut Store,
            db: usize,
            pat: Option<&[u8]>,
            tf: Option<&[u8]>,
            count: usize,
        ) -> Vec<Vec<u8>> {
            let mut all = Vec::new();
            let mut cursor = 0u64;
            loop {
                let (next, batch) = store.scan_in_db(db, cursor, pat, tf, count, 0);
                all.extend(batch);
                if next == 0 {
                    break;
                }
                cursor = next;
            }
            all
        }

        // Ground truth: live keys in `db` matching glob+type, in sorted logical order.
        fn ground_truth(
            store: &Store,
            db: usize,
            pat: Option<&[u8]>,
            tf: Option<&[u8]>,
        ) -> Vec<Vec<u8>> {
            let mut v: Vec<Vec<u8>> = store
                .all_keys()
                .into_iter()
                .filter_map(|physical| {
                    let physical: &[u8] = physical.as_slice();
                    let (kdb, logical) = match super::decode_db_key(physical) {
                        Some((d, l)) => (d, l.to_vec()),
                        None => (0, physical.to_vec()),
                    };
                    if kdb != db {
                        return None;
                    }
                    if let Some(p) = pat
                        && p != b"*"
                        && !glob_match(p, &logical)
                    {
                        return None;
                    }
                    if let Some(t) = tf
                        && !store
                            .peek_value_type(physical, 0)
                            .is_some_and(|vt| vt.as_str().as_bytes().eq_ignore_ascii_case(t))
                    {
                        return None;
                    }
                    Some(logical)
                })
                .collect();
            v.sort();
            v
        }

        let mut st: u64 = 0x0bad_c0de_1234_5678;
        let mut rng = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        for _ in 0..50 {
            let mut store = Store::new();
            let n = (rng() % 400) as usize;
            for _ in 0..n {
                let db = (rng() % 3) as usize; // dbs 0,1,2
                let klen = 1 + (rng() % 7) as usize;
                let key: Vec<u8> = (0..klen)
                    .map(|_| b"ab:_019xyz"[(rng() % 10) as usize])
                    .collect();
                let phys = encode_db_key(db, &key);
                match rng() % 3 {
                    0 => store.set(phys, b"v".to_vec(), None, 0),
                    1 => {
                        store.rpush(&phys, &[b"e".to_vec()], 0).ok();
                    }
                    _ => {
                        store.sadd(&phys, &[b"m".to_vec()], 0).ok();
                    }
                }
            }
            for db in 0..3usize {
                for pat in [
                    None,
                    Some(&b"a*"[..]),
                    Some(&b"*1*"[..]),
                    Some(&b"ab:*"[..]),
                ] {
                    for tf in [None, Some(&b"string"[..]), Some(&b"list"[..])] {
                        let count = 1 + (rng() % 11) as usize;
                        let mut got = drive(&mut store, db, pat, tf, count);
                        got.sort();
                        let want = ground_truth(&store, db, pat, tf);
                        assert_eq!(
                            got, want,
                            "scan_in_db diverged db={db} pat={pat:?} tf={tf:?} count={count}"
                        );
                    }
                }
            }
        }

        // A/B: 200k keys in db 0. A deep resumed scan_in_db call is O(log n+count);
        // the old behaviour re-materialised + sorted ALL keys every call.
        let mut store = Store::new();
        for i in 0..200_000u32 {
            store.set(format!("k{i:08}").into_bytes(), b"v".to_vec(), None, 0);
        }
        // Warm the resume cache up to a deep cursor.
        let mut cursor = 0u64;
        for _ in 0..1000 {
            let (next, _) = store.scan_in_db(0, cursor, None, None, 10, 0);
            cursor = next;
        }
        let t0 = std::time::Instant::now();
        let (_n2, _b2) = store.scan_in_db(0, cursor, None, None, 10, 0);
        let new_ns = t0.elapsed().as_nanos().max(1);

        // Old: materialise every logical key + sort + page (one SCAN call's cost).
        let t1 = std::time::Instant::now();
        let mut allk = store.all_keys();
        allk.sort();
        let _page: Vec<Vec<u8>> = allk
            .iter()
            .skip(cursor as usize)
            .take(10)
            .cloned()
            .collect();
        let old_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box((&allk, _page, _n2, _b2));
        println!(
            "scan_in_db deep-call A/B (200k keys, cursor={cursor}): old(materialize+sort all)={old_ns}ns new(resume)={new_ns}ns ratio={:.0}x",
            old_ns as f64 / new_ns as f64
        );
        let _ = ValueType::String;
        assert!(
            old_ns as f64 / new_ns as f64 > 2.0 || cfg!(debug_assertions),
            "expected >2x"
        );
    }

    // (frankenredis SCAN-guarantee) Redis guarantees a full SCAN iteration returns
    // every key present from start to end AT LEAST once, even if OTHER keys are
    // deleted mid-scan. The canonical use — SCAN a batch, DEL keys in it, repeat —
    // deletes already-returned keys between calls. Before the fix `scan_in_db`
    // gated its resume-by-last-key cache on `keyspace_generation`, so any DEL
    // (which bumps the generation) forced the positional `skip(start)` fallback;
    // deleting an already-returned key then shifted every later key down one slot,
    // and `skip(start)` stepped over a present-throughout key. This drives exactly
    // that pattern and asserts nothing is missed.
    #[test]
    fn scan_in_db_returns_present_throughout_key_after_mid_scan_deletion() {
        use super::Store;

        let mut store = Store::new();
        // Zero-padded so sorted byte order == numeric order (deterministic).
        for i in 0..500u32 {
            store.set(format!("k{i:04}").into_bytes(), b"v".to_vec(), None, 0);
        }

        let mut seen: std::collections::HashSet<Vec<u8>> = std::collections::HashSet::new();
        let mut deleted: std::collections::HashSet<Vec<u8>> = std::collections::HashSet::new();
        let mut cursor = 0u64;
        let mut batches = 0usize;
        loop {
            let (next, batch) = store.scan_in_db(0, cursor, None, None, 10, 0);
            for k in &batch {
                seen.insert(k.clone());
            }
            batches += 1;
            // After the first batch, DEL two keys we already returned (the lowest
            // ones) — the exact "SCAN then delete what you saw" loop. Each DEL bumps
            // keyspace_generation, which previously broke the resume.
            if batches == 1 {
                let mut lows: Vec<Vec<u8>> = batch.clone();
                lows.sort();
                for k in lows.into_iter().take(2) {
                    assert_eq!(
                        store.del(std::slice::from_ref(&k), 0),
                        1,
                        "victim key must exist"
                    );
                    deleted.insert(k);
                }
            }
            if next == 0 {
                break;
            }
            cursor = next;
            assert!(batches < 1_000_000, "scan did not terminate");
        }

        // Every key that existed for the WHOLE iteration (all 500 minus the 2 we
        // deleted) must have been returned at least once.
        let mut missing = Vec::new();
        for i in 0..500u32 {
            let k = format!("k{i:04}").into_bytes();
            if !deleted.contains(&k) && !seen.contains(&k) {
                missing.push(String::from_utf8_lossy(&k).into_owned());
            }
        }
        assert!(
            missing.is_empty(),
            "SCAN guarantee violated: present-throughout keys never returned: {missing:?}"
        );
    }

    // (frankenredis-9cg1c) SCAN MATCH <literal-prefix>* prunes the walk to the
    // prefix's key range. The full-iteration result must equal a ground-truth
    // glob filter over the whole sorted keyspace (byte-identical SET + order),
    // and driving it to completion must examine only O(matches) keys even when
    // the matching prefix sits at the END of a large keyspace — A/B vs the
    // number of keys a full (unpruned) walk would examine.
    #[test]
    fn scan_match_prefix_prune_isomorphic_and_faster_scanpfx() {
        use super::Store;

        fn drive(store: &mut Store, pattern: &[u8], count: usize) -> (Vec<Vec<u8>>, usize) {
            let mut all = Vec::new();
            let mut cursor = 0u64;
            let mut calls = 0usize;
            loop {
                let (next, batch) = store.scan(cursor, Some(pattern), count, 0);
                calls += 1;
                all.extend(batch);
                if next == 0 || calls > 10_000_000 {
                    break;
                }
                cursor = next;
            }
            all.sort();
            (all, calls)
        }

        // Correctness across prefix shapes + a non-prefix control, random keyspaces.
        let mut st: u64 = 0xfeed_face_dead_beef;
        let mut rng = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        for _ in 0..60 {
            let mut store = Store::new();
            let n = (rng() % 500) as usize;
            for _ in 0..n {
                let klen = 1 + (rng() % 8) as usize;
                let key: Vec<u8> = (0..klen)
                    .map(|_| b"ab:_0129xyz"[(rng() % 11) as usize])
                    .collect();
                store.set(key, b"v".to_vec(), None, 0);
            }
            for pat in [&b"a*"[..], b"ab:*", b"*9", b"a?:*", b"z*"] {
                let count = 1 + (rng() % 16) as usize;
                let (got, _) = drive(&mut store, pat, count);
                // Ground truth: every live key matching the glob, sorted.
                let mut want: Vec<Vec<u8>> = store
                    .all_keys()
                    .into_iter()
                    .filter(|k| super::glob_match(pat, k))
                    .collect();
                want.sort();
                assert_eq!(
                    got, want,
                    "SCAN MATCH {pat:?} prune diverged from glob ground truth"
                );
            }
        }

        // A/B: 200k keys under prefix "k", only ~50 under the LATE prefix "zz:".
        // A pruned full-SCAN examines only the ~50-key range; an unpruned walk
        // would examine all 200k. Compare wall time of driving each to completion.
        let mut store = Store::new();
        for i in 0..200_000u32 {
            store.set(format!("k{i:08}").into_bytes(), b"v".to_vec(), None, 0);
        }
        for i in 0..50u32 {
            store.set(format!("zz:{i:04}").into_bytes(), b"v".to_vec(), None, 0);
        }
        // Warm BOTH paths once before timing. Without this the pruned scan — run
        // first, immediately after inserting 200k keys — eats the cold btree-seek /
        // first-touch cost while the reference walk runs second on warm caches, so
        // the wall-time ratio inverts (pruned measured slower than the full walk)
        // and the >2x assert flakes/fails regardless of the lever. Measuring both
        // warm reflects the real invariant: pruning examines ~50 keys, not 200k.
        // (CrimsonHawk)
        let _ = drive(&mut store, b"zz:*", 100);
        let _ = store
            .all_keys()
            .iter()
            .filter(|k| super::glob_match(b"zz:*", k))
            .count();
        let t0 = std::time::Instant::now();
        let (pruned, pruned_calls) = drive(&mut store, b"zz:*", 100);
        let pruned_ns = t0.elapsed().as_nanos().max(1);
        assert_eq!(pruned.len(), 50, "must find all 50 zz: keys");

        // Reference: an unpruned full walk glob-filtering every key (what SCAN did
        // before this lever — examine all 200_050 keys).
        let t1 = std::time::Instant::now();
        let mut ref_matches = 0usize;
        for k in store.all_keys() {
            if super::glob_match(b"zz:*", &k) {
                ref_matches += 1;
            }
        }
        let ref_ns = t1.elapsed().as_nanos().max(1);
        assert_eq!(ref_matches, 50);
        println!(
            "SCAN MATCH prefix-prune A/B (200050 keys, 50 match late prefix): pruned full-scan {pruned_calls} calls {pruned_ns}ns vs unpruned full walk {ref_ns}ns ratio={:.1}x",
            ref_ns as f64 / pruned_ns as f64
        );
        assert!(
            ref_ns as f64 / pruned_ns as f64 > 2.0 || cfg!(debug_assertions),
            "expected >2x"
        );
    }

    // (frankenredis-3e92e) Correctness gate for the SCAN resume cache's
    // generation guard: it must bump on every STRUCTURAL keyspace mutation
    // (insert / remove / flushdb) but NOT on a value-only update (so the cache
    // survives non-structural writes), and a flush+readd mid-scan must leave
    // cache-on byte-identical to cache-off.
    #[test]
    fn scan_cache_generation_guard_correct_scanlin2() {
        use super::{Store, encode_db_key};

        // (a) generation bumps only on structural keyspace changes.
        let mut s = Store::new();
        let g0 = s.keyspace_generation;
        s.set(encode_db_key(0, b"k1"), b"v".to_vec(), None, 0);
        assert_ne!(
            s.keyspace_generation, g0,
            "new-key insert must bump generation"
        );
        let g1 = s.keyspace_generation;
        // Value-only overwrite of an existing key: key membership is unchanged, so
        // the resume cache stays valid — the generation must NOT bump.
        s.set(encode_db_key(0, b"k1"), b"v2".to_vec(), None, 0);
        assert_eq!(
            s.keyspace_generation, g1,
            "in-place value update must NOT bump generation"
        );
        s.del(&[encode_db_key(0, b"k1")], 0);
        assert_ne!(s.keyspace_generation, g1, "remove must bump generation");
        let g2 = s.keyspace_generation;
        s.set(encode_db_key(0, b"k2"), b"v".to_vec(), None, 0);
        s.flushdb();
        assert_ne!(s.keyspace_generation, g2, "flushdb must bump generation");

        // (b) flush + readd of a DIFFERENT keyspace mid-scan: the stale cached
        // last-key would mis-resume if the generation guard failed; cache-on must
        // reproduce cache-off exactly.
        let run = |disable_cache: bool| -> Vec<Vec<u8>> {
            let mut store = Store::new();
            for i in 0..200u32 {
                store.set(
                    encode_db_key(0, format!("a{i:04}").as_bytes()),
                    b"v".to_vec(),
                    None,
                    0,
                );
            }
            let mut out = Vec::new();
            let mut cursor = 0u64;
            let mut step = 0;
            loop {
                if disable_cache {
                    store.scan_cache.clear();
                }
                let (next, batch) = store.scan(cursor, None, 7, 0);
                out.extend(batch);
                step += 1;
                if step == 4 {
                    store.flushdb();
                    for i in 0..150u32 {
                        store.set(
                            encode_db_key(0, format!("b{i:04}").as_bytes()),
                            b"v".to_vec(),
                            None,
                            0,
                        );
                    }
                }
                if next == 0 || step > 100_000 {
                    break;
                }
                cursor = next;
            }
            out
        };
        assert_eq!(
            run(false),
            run(true),
            "flush+readd mid-scan: cache-on diverged from cache-off"
        );
    }

    // (frankenredis-4kuqc) The SCAN resume cache is a small LRU, not a single
    // slot, so several CONCURRENT (interleaved) scans each keep their own resume
    // point and stay O(N). Correctness gate: K interleaved full scans return the
    // exact same keys under the LRU, a single-slot, and no cache. Plus a Score
    // microbench: K interleaved full scans with the LRU vs a single slot (which
    // thrashes back to the O(N^2/batch) skip when scans interleave).
    #[test]
    fn scan_cache_lru_concurrent_isomorphic_and_faster_scanlru() {
        use super::Store;
        use super::encode_db_key;

        // mode: 0 = LRU (cap 8), 1 = single-slot (cap 1), 2 = no cache.
        fn interleaved(store: &mut Store, k: usize, count: usize, mode: u8) -> Vec<Vec<Vec<u8>>> {
            let mut cursors = vec![0u64; k];
            let mut done = vec![false; k];
            let mut results = vec![Vec::new(); k];
            let mut guard = 0;
            loop {
                let mut all_done = true;
                for i in 0..k {
                    if done[i] {
                        continue;
                    }
                    all_done = false;
                    match mode {
                        2 => store.scan_cache.clear(),
                        1 => {
                            while store.scan_cache.len() > 1 {
                                store.scan_cache.remove(0);
                            }
                        }
                        _ => {}
                    }
                    let (next, batch) = store.scan(cursors[i], None, count, 0);
                    results[i].extend(batch);
                    if next == 0 {
                        done[i] = true;
                    } else {
                        cursors[i] = next;
                    }
                }
                guard += 1;
                if all_done || guard > 10_000_000 {
                    break;
                }
            }
            results
        }

        // Correctness: every mode returns identical per-scan results, and each
        // scan returns the full keyspace exactly once (sorted order).
        {
            let mut store = Store::new();
            for i in 0..500u32 {
                store.set(
                    encode_db_key(0, format!("k{i:04}").as_bytes()),
                    b"v".to_vec(),
                    None,
                    0,
                );
            }
            let all = store.all_keys();
            for &count in &[1usize, 3, 7, 16] {
                let lru = interleaved(&mut store, 5, count, 0);
                let single = interleaved(&mut store, 5, count, 1);
                let off = interleaved(&mut store, 5, count, 2);
                for i in 0..5 {
                    assert_eq!(
                        lru[i], single[i],
                        "LRU vs single-slot diverged scan={i} count={count}"
                    );
                    assert_eq!(
                        lru[i], off[i],
                        "LRU vs no-cache diverged scan={i} count={count}"
                    );
                    assert_eq!(
                        lru[i], all,
                        "scan {i} did not return the full keyspace count={count}"
                    );
                }
            }
        }

        if cfg!(debug_assertions) {
            return;
        }
        // Score: 4 interleaved full scans of a 12k keyspace at COUNT 10 — a single
        // slot thrashes (every interleaved call mismatches, falling back to the
        // O(N^2/batch) skip), the LRU keeps all four O(N).
        let mut store = Store::new();
        for i in 0..12_000u32 {
            store.set(
                encode_db_key(0, format!("key:{i:06}").as_bytes()),
                b"v".to_vec(),
                None,
                0,
            );
        }
        let reps = 4;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(
                interleaved(&mut store, 4, 10, 1)
                    .iter()
                    .map(Vec::len)
                    .sum::<usize>(),
            );
        }
        let single_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(
                interleaved(&mut store, 4, 10, 0)
                    .iter()
                    .map(Vec::len)
                    .sum::<usize>(),
            );
        }
        let lru_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "single-slot vs LRU returned different totals");
        let score = single_ns as f64 / lru_ns as f64;
        eprintln!(
            "SCANLRU 4 interleaved scans of 12k @ COUNT 10: single-slot={single_ns}ns lru={lru_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "LRU must be >=2.0x vs single-slot for concurrent scans; got {score:.2}x"
        );
    }

    // (frankenredis-377jl) Frozen fingerprint of the grouped PEL AOF corpus.
    const AOFPEL_GOLDEN: u64 = 0xa82a_4b22_ca56_1dc1;

    // (frankenredis-377jl) Stream consumer-group PEL AOF serialization: the
    // O(P+C) grouped emit must be byte-for-byte identical to the old O(C·P)
    // per-consumer rescan, across randomized consumer/pending assignments and
    // edge shapes; plus a Score microbench on a many-consumer / large-PEL group.
    #[test]
    fn append_group_consumer_aof_commands_isomorphic_and_faster_aofpel() {
        use super::{
            StreamConsumerState, StreamGroup, StreamPendingEntry,
            append_group_consumer_aof_commands,
        };
        use std::collections::{BTreeMap, BTreeSet};

        // Old behavior: nested per-consumer filter over the whole PEL.
        fn old_ref(
            group: &StreamGroup,
            logical_key: &[u8],
            group_name: &[u8],
        ) -> Vec<Vec<Vec<u8>>> {
            let mut commands = Vec::new();
            for consumer in &group.consumers {
                let mut emitted = false;
                for ((ms, seq), p) in group
                    .pending
                    .iter()
                    .filter(|(_, p)| p.consumer.as_slice() == consumer.as_slice())
                {
                    emitted = true;
                    commands.push(vec![
                        b"XCLAIM".to_vec(),
                        logical_key.to_vec(),
                        group_name.to_vec(),
                        p.consumer.clone(),
                        b"0".to_vec(),
                        format!("{ms}-{seq}").into_bytes(),
                        b"TIME".to_vec(),
                        p.last_delivered_ms.to_string().into_bytes(),
                        b"RETRYCOUNT".to_vec(),
                        p.deliveries.to_string().into_bytes(),
                        b"JUSTID".to_vec(),
                        b"FORCE".to_vec(),
                    ]);
                }
                if !emitted {
                    commands.push(vec![
                        b"XGROUP".to_vec(),
                        b"CREATECONSUMER".to_vec(),
                        logical_key.to_vec(),
                        group_name.to_vec(),
                        consumer.clone(),
                    ]);
                }
            }
            commands
        }

        let mut st: u64 = 0x9E3779B97F4A7C15;
        let mut next = || {
            st ^= st << 13;
            st ^= st >> 7;
            st ^= st << 17;
            st
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };

        for _ in 0..600 {
            let nc = (next() % 8) as usize; // consumers (incl. 0)
            let consumers: Vec<Vec<u8>> = (0..nc)
                .map(|i| format!("c{}", i % 6).into_bytes())
                .collect();
            let mut cset: BTreeSet<Vec<u8>> = BTreeSet::new();
            for c in &consumers {
                cset.insert(c.clone());
            }
            let mut pending: BTreeMap<(u64, u64), StreamPendingEntry> = BTreeMap::new();
            let np = (next() % 30) as usize;
            for _ in 0..np {
                // Owner is a consumer (when any exist) OR an orphan name (covers
                // pending whose consumer is not in the consumer set).
                let owner = if !cset.is_empty() && next() % 5 != 0 {
                    let v: Vec<_> = cset.iter().cloned().collect();
                    v[(next() as usize) % v.len()].clone()
                } else {
                    format!("orphan{}", next() % 3).into_bytes()
                };
                let id = (next() % 50, next() % 4);
                pending.insert(
                    id,
                    StreamPendingEntry {
                        consumer: owner,
                        deliveries: 1 + next() % 5,
                        last_delivered_ms: next() % 1_000_000,
                    },
                );
            }
            let consumer_states = cset
                .iter()
                .map(|consumer| (consumer.clone(), StreamConsumerState::default()))
                .collect();
            let group = StreamGroup {
                last_delivered_id: (0, 0),
                entries_read: None,
                consumers: cset,
                consumer_metadata: BTreeMap::new(),
                consumer_states,
                pending,
            };
            let mut got = Vec::new();
            append_group_consumer_aof_commands(&group, b"mystream", b"g1", &mut got);
            assert_eq!(got, old_ref(&group, b"mystream", b"g1"), "PEL AOF mismatch");
            for cmd in &got {
                for arg in cmd {
                    fnv(&mut golden, arg);
                }
                fnv(&mut golden, &[0xFE]);
            }
            fnv(&mut golden, &[0xFF]);
        }
        assert_eq!(
            golden, AOFPEL_GOLDEN,
            "PEL AOF fingerprint changed: {golden:#018x} (golden {AOFPEL_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: a large fan-out group — 1000 consumers, 5000 pending entries.
        // The win scales with consumer count (old re-scans all P per consumer);
        // at small C it's construction-dominated, this exercises the quadratic.
        let mut cset: BTreeSet<Vec<u8>> = BTreeSet::new();
        for i in 0..1000u32 {
            cset.insert(format!("consumer-{i:04}").into_bytes());
        }
        let cvec: Vec<Vec<u8>> = cset.iter().cloned().collect();
        let mut pending: BTreeMap<(u64, u64), StreamPendingEntry> = BTreeMap::new();
        for i in 0..5000u64 {
            pending.insert(
                (i, 0),
                StreamPendingEntry {
                    consumer: cvec[(i as usize) % cvec.len()].clone(),
                    deliveries: 1,
                    last_delivered_ms: i,
                },
            );
        }
        let consumer_states =
            StreamGroup::consumer_states_from_parts(&cset, &BTreeMap::new(), &pending);
        let group = StreamGroup {
            last_delivered_id: (0, 0),
            entries_read: None,
            consumers: cset,
            consumer_metadata: BTreeMap::new(),
            consumer_states,
            pending,
        };
        let reps = 200;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(old_ref(&group, b"s", b"g").len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            let mut c = Vec::new();
            append_group_consumer_aof_commands(&group, b"s", b"g", &mut c);
            acc2 = acc2.wrapping_add(c.len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on command count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "AOFPEL 1000 consumers x 5000 PEL: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "grouped PEL emit must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-7st86) Frozen fingerprint of the ZLEXCOUNT result corpus.
    const ZLXC_GOLDEN: u64 = 0xd2ae_9203_bf45_8094;

    // (frankenredis-7st86) ZLEXCOUNT single-score range-count: isomorphism of
    // lex_count vs the brute-force iter_asc().filter().count() reference across
    // score-modes and encodings + every bound family, pinned by a golden
    // fingerprint; plus a Score microbench of old full-scan count vs new
    // range-count for a selective lex window over a large single-score zset.
    #[test]
    fn lex_count_single_score_range_count_isomorphic_and_faster_zlxc() {
        use super::{SortedSet, lex_in_range};

        fn brute(zs: &SortedSet, min: &[u8], max: &[u8]) -> usize {
            zs.iter_asc()
                .filter(|(m, _)| lex_in_range(m, min, max))
                .count()
        }

        let mut s: u64 = 0x3243F6A8885A308D;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, n: u64| {
            for byte in n.to_le_bytes() {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };
        let bound = |meta: u64, body: &[u8]| -> Vec<u8> {
            match meta % 4 {
                0 => b"-".to_vec(),
                1 => b"+".to_vec(),
                2 => [b"[".as_slice(), body].concat(),
                _ => [b"(".as_slice(), body].concat(),
            }
        };

        for _ in 0..700 {
            let mode = next() % 3;
            let n = if next() % 2 == 0 {
                1 + (next() % 18) as usize
            } else {
                160 + (next() % 70) as usize
            };
            let mut zs = SortedSet::new();
            for _ in 0..n {
                let klen = 1 + (next() % 4) as usize;
                let member: Vec<u8> = (0..klen).map(|_| b"abcde"[(next() % 5) as usize]).collect();
                let score = match mode {
                    0 => 0.0,
                    1 => 7.0,
                    _ => (next() % 4) as f64,
                };
                zs.insert(member, score);
            }
            for _ in 0..8 {
                let mn = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let mx = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let got = zs.lex_count(&mn, &mx);
                assert_eq!(
                    got,
                    brute(&zs, &mn, &mx),
                    "lex_count mismatch mn={mn:?} mx={mx:?} mode={mode} n={n}"
                );
                fnv(&mut golden, got as u64);
            }
        }
        // Explicit edge bounds on a single-score Full set.
        {
            let mut zs = SortedSet::new();
            for i in 0..300u32 {
                zs.insert(format!("m{i:04}").into_bytes(), 0.0);
            }
            let cases: &[(&[u8], &[u8])] = &[
                (b"-", b"+"),
                (b"+", b"-"),
                (b"[m0100", b"[m0200"),
                (b"(m0100", b"(m0200"),
                (b"[m0100", b"(m0100"),
                (b"[m0100", b"[m0100"),
                (b"(m9999", b"+"),
                (b"-", b"[m0000"),
                (b"[zzzz", b"[aaaa"),
            ];
            for (mn, mx) in cases {
                assert_eq!(
                    zs.lex_count(mn, mx),
                    brute(&zs, mn, mx),
                    "edge mn={mn:?} mx={mx:?}"
                );
            }
        }
        assert_eq!(
            golden, ZLXC_GOLDEN,
            "lex count fingerprint changed: {golden:#018x} (golden {ZLXC_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        let mut big = SortedSet::new();
        for i in 0..100_000u32 {
            big.insert(format!("m{i:06}").into_bytes(), 0.0);
        }
        let (mn, mx): (&[u8], &[u8]) = (b"[m050000", b"[m050050");
        let reps = 2000;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(brute(&big, mn, mx));
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(big.lex_count(mn, mx));
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on lex count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "ZLXC selective ZLEXCOUNT over 100k single-score: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "lex range-count must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-7uonw) The warm-treap O(log n) rank-diff path of `lex_count`
    // must agree byte-for-byte with the cold range scan AND the brute iter_asc
    // reference, across every bound shape and at the empty/whole-set edges.
    #[test]
    fn lex_count_warm_treap_rank_diff_isomorphic_7uonw() {
        use super::{SortedSet, lex_in_range};
        fn brute(zs: &SortedSet, min: &[u8], max: &[u8]) -> usize {
            zs.iter_asc()
                .filter(|(m, _)| lex_in_range(m, min, max))
                .count()
        }
        let mut s: u64 = 0x9E37_79B9_7F4A_7C15;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let bound = |meta: u64, body: &[u8]| -> Vec<u8> {
            match meta % 4 {
                0 => b"-".to_vec(),
                1 => b"+".to_vec(),
                2 => [b"[".as_slice(), body].concat(),
                _ => [b"(".as_slice(), body].concat(),
            }
        };
        for _ in 0..400 {
            // Single-score Full set (the canonical ZLEXCOUNT shape); >128 so it
            // promotes past Packed and the treap is meaningful.
            let n = 160 + (next() % 80) as usize;
            let score = (next() % 3) as f64; // one score for the whole set
            let mut warm = SortedSet::new();
            let mut cold = SortedSet::new();
            for _ in 0..n {
                let klen = 1 + (next() % 4) as usize;
                let member: Vec<u8> = (0..klen).map(|_| b"abcde"[(next() % 5) as usize]).collect();
                warm.insert(member.clone(), score);
                cold.insert(member, score);
            }
            // Warm ONLY `warm`'s treap; `cold` keeps rank_tree == None.
            let probe: Vec<u8> = vec![b"abcde"[(next() % 5) as usize]];
            let _ = warm.rank(&probe);
            for _ in 0..12 {
                let mn = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let mx = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let fast = warm.lex_count(&mn, &mx);
                let slow = cold.lex_count(&mn, &mx);
                let ref_ = brute(&cold, &mn, &mx);
                assert_eq!(fast, ref_, "warm rank-diff != brute mn={mn:?} mx={mx:?}");
                assert_eq!(slow, ref_, "cold scan != brute mn={mn:?} mx={mx:?}");
            }
            // Whole-set / empty edges (members may dedup, so compare to brute).
            for (mn, mx) in [
                (&b"-"[..], &b"+"[..]),
                (b"+", b"-"),
                (b"+", b"+"),
                (b"-", b"-"),
            ] {
                assert_eq!(
                    warm.lex_count(mn, mx),
                    brute(&cold, mn, mx),
                    "warm edge mn={mn:?} mx={mx:?}"
                );
            }
        }
    }

    // (frankenredis-i5896) The warm-treap O(log n) rank-diff path of
    // `score_bound_count` (ZCOUNT) must agree byte-for-byte with the cold range
    // scan and the brute filter across inclusive/exclusive bounds, ±inf, and
    // inverted/empty ranges.
    #[test]
    fn score_bound_count_warm_treap_rank_diff_isomorphic_i5896() {
        use super::{ScoreBound, SortedSet};
        fn brute(zs: &SortedSet, min: ScoreBound, max: ScoreBound) -> usize {
            zs.iter_asc()
                .filter(|(_, score)| min.check_min(*score) && max.check_max(*score))
                .count()
        }
        let mut s: u64 = 0xD1B5_4A32_D192_ED03;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let bnd = |meta: u64, v: f64| -> ScoreBound {
            if meta.is_multiple_of(2) {
                ScoreBound::Inclusive(v)
            } else {
                ScoreBound::Exclusive(v)
            }
        };
        for _ in 0..400 {
            let n = 160 + (next() % 90) as usize; // > Packed threshold → Full
            let mut warm = SortedSet::new();
            let mut cold = SortedSet::new();
            for _ in 0..n {
                let klen = 1 + (next() % 4) as usize;
                let member: Vec<u8> = (0..klen).map(|_| b"abcde"[(next() % 5) as usize]).collect();
                // small integer scores so many members share scores (ties)
                let score = (next() % 7) as f64;
                warm.insert(member.clone(), score);
                cold.insert(member, score);
            }
            // Warm ONLY `warm`'s treap.
            let _ = warm.rank(b"a");
            for _ in 0..14 {
                let a = (next() % 9) as f64 - 1.0; // -1..=7, brackets the score span
                let b = (next() % 9) as f64 - 1.0;
                // The warm rank-diff path handles ANY bounds (incl inverted/
                // equal, which `score_bounds` maps to an empty BTree range that
                // the cold scan would PANIC on — production guards that in
                // Store::zcount). So check warm vs brute on arbitrary bounds...
                let mn = bnd(next(), a);
                let mx = bnd(next(), b);
                assert_eq!(
                    warm.score_bound_count(mn, mx),
                    brute(&cold, mn, mx),
                    "warm rank-diff != brute min={mn:?} max={mx:?}"
                );
                // ...and warm == cold == brute on strictly-ordered bounds, where
                // the cold scan is well-defined.
                let (lo, hi) = if a <= b { (a, b) } else { (b, a) };
                let mn2 = ScoreBound::Inclusive(lo);
                let mx2 = ScoreBound::Inclusive(hi);
                let r = brute(&cold, mn2, mx2);
                assert_eq!(warm.score_bound_count(mn2, mx2), r, "warm incl");
                assert_eq!(cold.score_bound_count(mn2, mx2), r, "cold incl");
            }
            // ±inf whole-set + inverted empties.
            let all = ScoreBound::Inclusive(f64::NEG_INFINITY);
            let allmax = ScoreBound::Inclusive(f64::INFINITY);
            assert_eq!(
                warm.score_bound_count(all, allmax),
                brute(&cold, all, allmax)
            );
            assert_eq!(
                warm.score_bound_count(ScoreBound::Inclusive(5.0), ScoreBound::Inclusive(2.0)),
                0
            );
            assert_eq!(
                warm.score_bound_count(ScoreBound::Exclusive(3.0), ScoreBound::Exclusive(3.0)),
                0
            );
        }
    }

    // (frankenredis-sp1qh) Frozen fingerprint of the windowed lex-range corpus.
    const ZLX2_GOLDEN: u64 = 0xe2fd_e5dc_4e5b_e285;

    // (frankenredis-sp1qh) Windowed lex range (ZREVRANGEBYLEX + ZRANGEBYLEX LIMIT):
    // isomorphism of lex_range_window vs the brute-force iter_*().filter().skip()
    // .take() reference across rev × offset × count × score-modes × encodings,
    // pinned by a golden fingerprint; plus a Score microbench (old full-scan
    // filter vs new range-window) for a deep reverse/limit window over a large
    // single-score zset.
    #[test]
    fn lex_range_window_isomorphic_and_faster_zlx2() {
        use super::{SortedSet, lex_in_range};

        // Reference == the old behavior for any case.
        fn brute(
            zs: &SortedSet,
            min: &[u8],
            max: &[u8],
            rev: bool,
            offset: usize,
            take: usize,
        ) -> Vec<(Vec<u8>, f64)> {
            if rev {
                zs.iter_desc()
                    .filter(|(m, _)| lex_in_range(m, min, max))
                    .skip(offset)
                    .take(take)
                    .map(|(m, s)| (m.to_vec(), s))
                    .collect()
            } else {
                zs.iter_asc()
                    .filter(|(m, _)| lex_in_range(m, min, max))
                    .skip(offset)
                    .take(take)
                    .map(|(m, s)| (m.to_vec(), s))
                    .collect()
            }
        }

        let mut s: u64 = 0x2B7E151628AED2A6;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };
        let bound = |meta: u64, body: &[u8]| -> Vec<u8> {
            match meta % 4 {
                0 => b"-".to_vec(),
                1 => b"+".to_vec(),
                2 => [b"[".as_slice(), body].concat(),
                _ => [b"(".as_slice(), body].concat(),
            }
        };

        for _ in 0..700 {
            let mode = next() % 3;
            let n = if next() % 2 == 0 {
                1 + (next() % 18) as usize
            } else {
                160 + (next() % 70) as usize
            };
            let mut zs = SortedSet::new();
            for _ in 0..n {
                let klen = 1 + (next() % 4) as usize;
                let member: Vec<u8> = (0..klen).map(|_| b"abcde"[(next() % 5) as usize]).collect();
                let score = match mode {
                    0 => 0.0,
                    1 => 3.0,
                    _ => (next() % 4) as f64,
                };
                zs.insert(member, score);
            }
            for _ in 0..8 {
                let mn = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let mx = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let rev = next() % 2 == 0;
                let offset = (next() % 6) as usize;
                let take = match next() % 4 {
                    0 => usize::MAX,
                    k => k as usize,
                };
                let got = zs.lex_range_window(&mn, &mx, rev, offset, take);
                assert_eq!(
                    got,
                    brute(&zs, &mn, &mx, rev, offset, take),
                    "lex_range_window mismatch mn={mn:?} mx={mx:?} rev={rev} off={offset} take={take} mode={mode} n={n}"
                );
                for (m, sc) in &got {
                    fnv(&mut golden, m);
                    fnv(&mut golden, &sc.to_bits().to_le_bytes());
                }
                fnv(&mut golden, &[if rev { 1 } else { 0 }]);
                fnv(&mut golden, &[0xFF]);
            }
        }
        assert_eq!(
            golden, ZLX2_GOLDEN,
            "windowed lex output fingerprint changed: {golden:#018x} (golden {ZLX2_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: deep reverse window over a 100k single-score zset.
        let mut big = SortedSet::new();
        for i in 0..100_000u32 {
            big.insert(format!("m{i:06}").into_bytes(), 0.0);
        }
        // ZREVRANGEBYLEX [m000020 [m000000 LIMIT 0 10 — a small reverse window
        // near the LOW end, which the old descending filter only reaches after
        // scanning the whole set from the high end.
        let (mn, mx): (&[u8], &[u8]) = (b"[m000000", b"[m000020");
        let reps = 2000;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(brute(&big, mn, mx, true, 0, 10).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(big.lex_range_window(mn, mx, true, 0, 10).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on windowed count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "ZLX2 deep reverse BYLEX window over 100k: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "windowed lex range-prune must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-yawte) Frozen fingerprint of the lex-range output corpus.
    const ZLEX1_GOLDEN: u64 = 0x3097_7947_f492_5323;

    // (frankenredis-yawte) ZRANGEBYLEX single-score range-pruning: isomorphism vs
    // the brute-force iter_asc().filter(lex_in_range) reference across single- and
    // multi-score sets, Packed and Full encodings, and every bound family
    // (`-`/`+`/`[x`/`(x`), pinned by a golden fingerprint; plus a Score microbench
    // of old full-scan vs new range-prune for a selective lex window over a large
    // single-score zset.
    #[test]
    fn zrangebylex_single_score_range_prune_isomorphic_and_faster_zlex1() {
        use super::{SortedSet, lex_in_range};

        // Brute-force reference == the old behavior (works for every case).
        fn brute(zs: &SortedSet, min: &[u8], max: &[u8]) -> Vec<(Vec<u8>, f64)> {
            zs.iter_asc()
                .filter(|(m, _)| lex_in_range(m, min, max))
                .map(|(m, s)| (m.to_vec(), s))
                .collect()
        }

        let mut s: u64 = 0xB7E151628AED2A6B;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };
        let bound = |meta: u64, body: &[u8]| -> Vec<u8> {
            match meta % 4 {
                0 => b"-".to_vec(),
                1 => b"+".to_vec(),
                2 => {
                    let mut v = vec![b'['];
                    v.extend_from_slice(body);
                    v
                }
                _ => {
                    let mut v = vec![b'('];
                    v.extend_from_slice(body);
                    v
                }
            }
        };

        for _ in 0..600 {
            // Score mode: 0 => all-zero, 1 => all-five, 2 => varied (multi-score).
            let mode = next() % 3;
            // Size: small (Packed) and large (Full, forces the fast path).
            let n = if next() % 2 == 0 {
                1 + (next() % 20) as usize
            } else {
                160 + (next() % 80) as usize
            };
            let mut zs = SortedSet::new();
            for _ in 0..n {
                let klen = 1 + (next() % 4) as usize;
                let member: Vec<u8> = (0..klen).map(|_| b"abcde"[(next() % 5) as usize]).collect();
                let score = match mode {
                    0 => 0.0,
                    1 => 5.0,
                    _ => (next() % 4) as f64,
                };
                zs.insert(member, score);
            }
            for _ in 0..6 {
                let mn = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let mx = bound(next(), &[b"abcde"[(next() % 5) as usize]]);
                let got = zs.lex_range_asc(&mn, &mx);
                assert_eq!(
                    got,
                    brute(&zs, &mn, &mx),
                    "lex_range mismatch mn={mn:?} mx={mx:?} mode={mode} n={n}"
                );
                for (m, sc) in &got {
                    fnv(&mut golden, m);
                    fnv(&mut golden, &sc.to_bits().to_le_bytes());
                }
                fnv(&mut golden, &[0xFF]);
            }
        }
        // Explicit edge bounds on a single-score Full set.
        {
            let mut zs = SortedSet::new();
            for i in 0..300u32 {
                zs.insert(format!("m{i:04}").into_bytes(), 0.0);
            }
            let cases: &[(&[u8], &[u8])] = &[
                (b"-", b"+"),
                (b"+", b"-"),
                (b"+", b"+"),
                (b"-", b"-"),
                (b"[m0100", b"[m0200"),
                (b"(m0100", b"(m0200"),
                (b"[m0100", b"(m0100"),
                (b"[m0100", b"[m0100"),
                (b"(m9999", b"+"),
                (b"-", b"[m0000"),
                (b"[zzzz", b"[aaaa"),
            ];
            for (mn, mx) in cases {
                assert_eq!(
                    zs.lex_range_asc(mn, mx),
                    brute(&zs, mn, mx),
                    "edge mn={mn:?} mx={mx:?}"
                );
            }
        }
        assert_eq!(
            golden, ZLEX1_GOLDEN,
            "lex range output fingerprint changed: {golden:#018x} (golden {ZLEX1_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // ---- Score: full-scan filter vs range-prune, selective window, 100k ----
        let mut big = SortedSet::new();
        for i in 0..100_000u32 {
            big.insert(format!("m{i:06}").into_bytes(), 0.0);
        }
        let (mn, mx): (&[u8], &[u8]) = (b"[m050000", b"[m050010");
        let reps = 2000;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(brute(&big, mn, mx).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(big.lex_range_asc(mn, mx).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on lex count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "ZLEX1 selective BYLEX over 100k single-score: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "lex range-prune must be >=2.0x; got {score:.2}x"
        );
    }

    // (frankenredis-2wgom) Frozen fingerprint of the KEYS prefix-pruned output
    // corpus; pinned from the first run.
    const KPRFX_GOLDEN: u64 = 0x2516_5b2a_a2f9_9213;

    // (frankenredis-2wgom) KEYS literal-prefix range-pruning: isomorphism vs a
    // brute-force full-keyspace glob reference over randomized key sets +
    // pattern families (exact / prefix-star / prefix-? / leading-metachar /
    // char-class / escaped), pinned by a golden fingerprint; plus a Score
    // microbench of old full-scan glob vs new pruned range for a selective
    // prefix over a large keyspace.
    #[test]
    fn keys_matching_prefix_prune_isomorphic_and_faster_kprfx() {
        use super::{Store, decode_db_key, encode_db_key, glob_match};

        // Brute-force reference: glob every db-0 logical key (the old behavior).
        fn brute(store: &Store, pat: &[u8]) -> Vec<Vec<u8>> {
            let mut r: Vec<Vec<u8>> = store
                .all_keys()
                .into_iter()
                .filter_map(|key| {
                    let logical = decode_db_key(&key)
                        .map(|(_, l)| l)
                        .unwrap_or(key.as_slice());
                    if decode_db_key(&key).is_some() {
                        return None;
                    }
                    if glob_match(pat, logical) {
                        Some(logical.to_vec())
                    } else {
                        None
                    }
                })
                .collect();
            r.sort();
            r
        }

        let mut s: u64 = 0x243F6A8885A308D3;
        let mut next = || {
            s ^= s << 13;
            s ^= s >> 7;
            s ^= s << 17;
            s
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };

        for _ in 0..400 {
            let mut store = Store::new();
            let nkeys = 1 + (next() % 60) as usize;
            for _ in 0..nkeys {
                // Keys over a tiny alphabet so prefixes/classes actually collide.
                let klen = 1 + (next() % 6) as usize;
                let key: Vec<u8> = (0..klen).map(|_| b"ab:cd"[(next() % 5) as usize]).collect();
                store.set(encode_db_key(0, &key), b"v".to_vec(), None, 0);
            }
            // Pattern family drawn from the same alphabet + metacharacters.
            let patterns: [Vec<u8>; 9] = [
                b"*".to_vec(),
                b"a*".to_vec(),
                b"a?".to_vec(),
                b"ab*".to_vec(),
                b"*b".to_vec(),
                b"[ab]*".to_vec(),
                b"a:c*".to_vec(),
                b"\\a*".to_vec(),
                {
                    let l = 1 + (next() % 4) as usize;
                    let mut p: Vec<u8> = (0..l).map(|_| b"ab:cd"[(next() % 5) as usize]).collect();
                    p.push(b'*');
                    p
                },
            ];
            for pat in &patterns {
                let got = store.keys_matching_in_db(0, pat, 0);
                assert_eq!(got, brute(&store, pat), "KEYS prune mismatch pat={pat:?}");
                // keys_matching (db-agnostic) must agree with keys_matching_in_db
                // on a pure db-0 keyspace.
                assert_eq!(
                    store.keys_matching(pat, 0),
                    got,
                    "keys_matching disagrees pat={pat:?}"
                );
                for k in &got {
                    fnv(&mut golden, k);
                }
                fnv(&mut golden, &[0xFF]);
            }
        }
        // Explicit edge patterns: empty, all-0xFF-ish prefix, exact-key lookup.
        {
            let mut store = Store::new();
            for k in [b"user:1".as_slice(), b"user:2", b"user:30", b"v", b"users"] {
                store.set(encode_db_key(0, k), b"v".to_vec(), None, 0);
            }
            for pat in [
                b"user:*".as_slice(),
                b"user:1",
                b"user:?",
                b"user:3*",
                b"nomatch*",
                b"*",
            ] {
                assert_eq!(
                    store.keys_matching_in_db(0, pat, 0),
                    brute(&store, pat),
                    "edge pat={pat:?}"
                );
            }
        }
        assert_eq!(
            golden, KPRFX_GOLDEN,
            "KEYS prune output fingerprint changed: {golden:#018x} (golden {KPRFX_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // ---- Score: old full-scan glob vs new prefix-pruned range ----
        let mut big = Store::new();
        let n = 100_000u32;
        for i in 0..n {
            // Keys spread over many prefixes; only "key:00042:*" is selective.
            let k = format!("key:{:05}:{}", i % 1000, i);
            big.set(encode_db_key(0, k.as_bytes()), b"v".to_vec(), None, 0);
        }
        let pat = b"key:00042:*";
        let reps = 200;
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(brute(&big, pat).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(big.keys_matching_in_db(0, pat, 0).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(acc, acc2, "old/new disagree on match count");
        let score = old_ns as f64 / new_ns as f64;
        eprintln!(
            "KPRFX KEYS selective-prefix over 100k: old={old_ns}ns new={new_ns}ns score={score:.2}x"
        );
        assert!(
            score >= 2.0,
            "prefix prune must be >=2.0x for a selective prefix; got {score:.2}x"
        );
    }

    // (frankenredis-4ywto) Frozen fingerprint of the members_at_indices output
    // corpus; pinned from the first run.
    const ZRND1_GOLDEN: u64 = 0x3f2b_2cc4_0d71_8c60;

    // (frankenredis-4ywto) ZRANDMEMBER-count single-pass member fetch:
    // isomorphism proof (output byte-identical to the old materialise-all-then-
    // index reference over a randomized + edge-case corpus, pinned by a golden
    // fingerprint) + a Score microbench (old full materialise vs new single-pass
    // clone-only-needed) for a small count over a large zset.
    #[test]
    fn members_at_indices_isomorphic_and_faster_zrnd1() {
        use super::SortedSet;

        let build = |n: usize| -> SortedSet {
            let mut zs = SortedSet::new();
            for i in 0..n {
                // Distinct scores + members so iter_asc order is well-defined.
                zs.insert(format!("m{i:08}").into_bytes(), i as f64 * 1.5);
            }
            zs
        };
        // Reference: the old path — materialise EVERY (member,score) then index.
        let reference = |zs: &SortedSet, idxs: &[usize]| -> Vec<(Vec<u8>, f64)> {
            let mat: Vec<(Vec<u8>, f64)> = zs.iter_asc().map(|(m, s)| (m.to_vec(), s)).collect();
            idxs.iter().filter_map(|&i| mat.get(i).cloned()).collect()
        };

        let mut state: u64 = 0x84242F96ECECECEC;
        let mut next = || {
            state ^= state << 13;
            state ^= state >> 7;
            state ^= state << 17;
            state
        };
        let mut golden: u64 = 0xcbf2_9ce4_8422_2325;
        let fnv = |g: &mut u64, b: &[u8]| {
            for &byte in b {
                *g ^= u64::from(byte);
                *g = g.wrapping_mul(0x0000_0100_0000_01b3);
            }
        };

        for _ in 0..4000 {
            let n = 1 + (next() % 200) as usize;
            let mut zs = build(n);
            // A pick list with arbitrary order, repeats, and out-of-range probes.
            let k = (next() % 12) as usize;
            let idxs: Vec<usize> = (0..k).map(|_| (next() as usize) % (n + 2)).collect();
            let expected = reference(&zs, &idxs);
            let got = zs.members_at_indices(&idxs);
            let warm_rank = zs.rank(b"m00000000");
            let warm_got = zs.members_at_indices(&idxs);
            assert_eq!(
                (got.as_slice(), warm_rank, warm_got.as_slice()),
                (expected.as_slice(), Some(0), expected.as_slice()),
                "members_at_indices mismatch n={n} idxs={idxs:?}"
            );
            for (m, s) in &got {
                fnv(&mut golden, m);
                fnv(&mut golden, &s.to_bits().to_le_bytes());
            }
            fnv(&mut golden, &[0xFF]);
        }
        // Edge cases: empty picks, single, all-in-order, reverse, all-dups, OOB.
        let zs = build(8);
        let edge: &[&[usize]] = &[
            &[],
            &[0],
            &[7],
            &[0, 1, 2, 3, 4, 5, 6, 7],
            &[7, 6, 5, 4, 3, 2, 1, 0],
            &[3, 3, 3, 3],
            &[8, 9, 100],
            &[2, 8, 2, 0, 100, 7],
        ];
        for idxs in edge {
            assert_eq!(
                zs.members_at_indices(idxs),
                reference(&zs, idxs),
                "edge idxs={idxs:?}"
            );
        }
        assert_eq!(
            golden, ZRND1_GOLDEN,
            "members_at_indices output fingerprint changed: {golden:#018x} (golden {ZRND1_GOLDEN:#018x})"
        );

        if cfg!(debug_assertions) {
            return;
        }
        // Score: small count over a large zset — the materialise-all anti-pattern.
        let mut big = build(100_000);
        let warm_rank = big.rank(b"m00050000");
        let picks: Vec<usize> = (0..4).map(|_| (next() as usize) % 100_000).collect();
        let reps = 2000;
        let old_index = |zs: &SortedSet, idxs: &[usize]| -> Vec<(Vec<u8>, f64)> {
            let mat: Vec<(Vec<u8>, f64)> = zs.iter_asc().map(|(m, s)| (m.to_vec(), s)).collect();
            idxs.iter().filter_map(|&i| mat.get(i).cloned()).collect()
        };
        let t0 = std::time::Instant::now();
        let mut acc = 0usize;
        for _ in 0..reps {
            acc = acc.wrapping_add(old_index(&big, &picks).len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(acc);
        let t1 = std::time::Instant::now();
        let mut acc2 = 0usize;
        for _ in 0..reps {
            acc2 = acc2.wrapping_add(big.members_at_indices(&picks).len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(acc2);
        assert_eq!(
            (warm_rank, acc),
            (Some(50_000), acc2),
            "rank warmup failed or old/new disagree on pick count"
        );
        let score = old_ns as f64 / new_ns as f64;
        eprintln!("ZRND1 zrandmember 4-of-100k: old={old_ns}ns new={new_ns}ns score={score:.2}x");
        assert!(
            score >= 2.0,
            "single-pass fetch must be >=2.0x for small count; got {score:.2}x"
        );
    }

    #[test]
    fn setvalue_intersect_int_fastpath_matches_generic_and_reports_ab_ratio() {
        use super::SetValue;

        let mut state: u64 = 0x1357_9BDF_2468_ACE0;
        let mut next = || {
            state ^= state << 13;
            state ^= state >> 7;
            state ^= state << 17;
            state
        };

        // Equivalence: retain_intersect / retain_diff agree with the generic
        // contains-based retain, across Int-Int, Int-Generic, and Generic-Generic
        // pairs (a small intset limit forces some promotions).
        for _ in 0..3000 {
            let mix = next() % 3;
            let mut a = SetValue::new();
            let mut b = SetValue::new();
            for _ in 0..(next() % 40) {
                let v = if mix == 1 {
                    format!("s{}", next() % 60).into_bytes()
                } else {
                    ((next() % 120) as i64).to_string().into_bytes()
                };
                a.insert(v, 16);
            }
            for _ in 0..(next() % 40) {
                let v = if mix == 2 {
                    format!("s{}", next() % 60).into_bytes()
                } else {
                    ((next() % 120) as i64).to_string().into_bytes()
                };
                b.insert(v, 16);
            }
            let mut ai = a.clone();
            ai.retain_intersect(&b);
            let mut ag = a.clone();
            ag.retain(|m| b.contains(m));
            assert_eq!(ai, ag, "retain_intersect mismatch");
            let mut ad = a.clone();
            ad.retain_diff(&b);
            let mut agd = a.clone();
            agd.retain(|m| !b.contains(m));
            assert_eq!(ad, agd, "retain_diff mismatch");
        }

        // A/B: intersect two large intsets. Old generic path materialises+reparses
        // each member; the fast path stays on the sorted i64 arrays.
        let n = 100_000i64;
        let mut a = SetValue::new();
        let mut b = SetValue::new();
        for i in 0..n {
            a.insert(i.to_string().into_bytes(), usize::MAX);
        }
        for i in 0..n {
            b.insert((i * 2).to_string().into_bytes(), usize::MAX);
        }
        let reps = 200;
        let t0 = std::time::Instant::now();
        let mut c0 = 0usize;
        for _ in 0..reps {
            let mut r = a.clone();
            r.retain(|m| b.contains(m));
            c0 = c0.wrapping_add(r.len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(c0);
        let t1 = std::time::Instant::now();
        let mut c1 = 0usize;
        for _ in 0..reps {
            let mut r = a.clone();
            r.retain_intersect(&b);
            c1 = c1.wrapping_add(r.len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(c1);
        assert_eq!(c0, c1, "fast path and generic path produce different sizes");
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "SINTER int A/B (n={n}, x{reps}): generic-retain={old_ns}ns i64-fastpath={new_ns}ns ratio={ratio:.2}x"
        );
        assert!(
            ratio > 2.0 || cfg!(debug_assertions),
            "expected >2x, got {ratio:.2}x"
        );
    }

    #[test]
    fn setvalue_union_int_fastpath_matches_generic_and_reports_ab_ratio() {
        use super::SetValue;

        let mut state: u64 = 0x2468_ACE0_1357_9BDF;
        let mut next = || {
            state ^= state << 13;
            state ^= state >> 7;
            state ^= state << 17;
            state
        };

        // Equivalence: union_with agrees with extend (same members AND same final
        // encoding) across Int-Int / Int-Generic / Generic-Generic, with a small
        // intset limit (16) to exercise promotion-on-overflow.
        for _ in 0..3000 {
            let mix = next() % 3;
            let mut a = SetValue::new();
            let mut b = SetValue::new();
            for _ in 0..(next() % 40) {
                let v = if mix == 1 {
                    format!("s{}", next() % 60).into_bytes()
                } else {
                    ((next() % 120) as i64).to_string().into_bytes()
                };
                a.insert(v, 16);
            }
            for _ in 0..(next() % 40) {
                let v = if mix == 2 {
                    format!("s{}", next() % 60).into_bytes()
                } else {
                    ((next() % 120) as i64).to_string().into_bytes()
                };
                b.insert(v, 16);
            }
            let mut au = a.clone();
            au.union_with(&b, 16);
            let mut ag = a.clone();
            ag.extend(b.iter().map(|m| m.into_owned()), 16);
            assert_eq!(au, ag, "union members mismatch");
            assert_eq!(au.is_intset(), ag.is_intset(), "union encoding mismatch");
        }

        // A/B: union two large intsets. The old extend inserts each member into a
        // sorted Vec (binary search + O(n) shift) after a string round-trip; the
        // fast path merges the two sorted i64 arrays once.
        let n = 4000i64;
        let mut a = SetValue::new();
        let mut b = SetValue::new();
        for i in 0..n {
            a.insert((i * 2).to_string().into_bytes(), usize::MAX);
            b.insert((i * 2 + 1).to_string().into_bytes(), usize::MAX);
        }
        let reps = 30;
        let t0 = std::time::Instant::now();
        let mut c0 = 0usize;
        for _ in 0..reps {
            let mut r = a.clone();
            r.extend(b.iter().map(|m| m.into_owned()), usize::MAX);
            c0 = c0.wrapping_add(r.len());
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(c0);
        let t1 = std::time::Instant::now();
        let mut c1 = 0usize;
        for _ in 0..reps {
            let mut r = a.clone();
            r.union_with(&b, usize::MAX);
            c1 = c1.wrapping_add(r.len());
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(c1);
        assert_eq!(c0, c1, "union size mismatch");
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "SUNION int A/B (n={n}, x{reps}): extend-insert={old_ns}ns i64-merge={new_ns}ns ratio={ratio:.2}x"
        );
        assert!(
            ratio > 2.0 || cfg!(debug_assertions),
            "expected >2x, got {ratio:.2}x"
        );
    }

    #[test]
    fn srandmember_count_avoids_materializing_whole_set_and_reports_ab_ratio() {
        let key = b"s";
        let n = 100_000i64;
        let build = || {
            let mut store = Store::new();
            let adds: Vec<(f64, Vec<u8>)> = Vec::new();
            let _ = adds;
            for i in 0..n {
                store
                    .sadd(key, &[format!("m{i:06}").into_bytes()], 0)
                    .unwrap();
            }
            store
        };

        // Behaviour sanity: small positive and negative counts return the right
        // sizes and (for distinct) unique members.
        let mut store = build();
        let pos = store.srandmember_count(key, 10, 0).unwrap();
        assert_eq!(pos.len(), 10);
        let uniq: std::collections::HashSet<_> = pos.iter().collect();
        assert_eq!(uniq.len(), 10, "positive count must be distinct");
        let neg = store.srandmember_count(key, -10, 0).unwrap();
        assert_eq!(neg.len(), 10);
        assert_eq!(
            store.srandmember_count(key, n + 50, 0).unwrap().len(),
            n as usize
        );

        // A/B: small sample over a large set. Old path materialised every member;
        // the new path clones only the sampled ones.
        let old_ref = |store: &mut Store, abs_count: usize| -> usize {
            let members = store.smembers(key, 0).unwrap(); // O(n) materialise (old behaviour)
            let mut r = 0usize;
            for _ in 0..abs_count {
                let idx = (store.next_rand() as usize) % members.len();
                r = r.wrapping_add(members[idx].len());
            }
            r
        };
        let reps = 500;
        let mut a = build();
        let t0 = std::time::Instant::now();
        let mut c0 = 0usize;
        for _ in 0..reps {
            c0 = c0.wrapping_add(old_ref(&mut a, 10));
        }
        let old_ns = t0.elapsed().as_nanos().max(1);
        std::hint::black_box(c0);
        let mut b = build();
        let t1 = std::time::Instant::now();
        let mut c1 = 0usize;
        for _ in 0..reps {
            c1 = c1.wrapping_add(
                b.srandmember_count(key, -10, 0)
                    .unwrap()
                    .iter()
                    .map(Vec::len)
                    .sum::<usize>(),
            );
        }
        let new_ns = t1.elapsed().as_nanos().max(1);
        std::hint::black_box(c1);
        let ratio = old_ns as f64 / new_ns as f64;
        println!(
            "SRANDMEMBER count A/B (n={n}, sample=10, x{reps}): materialise-all={old_ns}ns get_index-sample={new_ns}ns ratio={ratio:.2}x"
        );
        assert!(
            ratio > 2.0 || cfg!(debug_assertions),
            "expected >2x, got {ratio:.2}x"
        );
    }

    #[test]
    fn zadd_and_zscore() {
        let mut store = Store::new();
        let added = store
            .zadd(b"z", &[(1.0, b"a".to_vec()), (2.0, b"b".to_vec())], 0)
            .unwrap();
        assert_eq!(added, 2);
        assert_eq!(store.zscore(b"z", b"a", 0).unwrap(), Some(1.0));
        assert_eq!(store.zscore(b"z", b"b", 0).unwrap(), Some(2.0));
        assert_eq!(store.zscore(b"z", b"c", 0).unwrap(), None);
        // Update existing member score: count stays 0
        let added2 = store.zadd(b"z", &[(3.0, b"a".to_vec())], 0).unwrap();
        assert_eq!(added2, 0);
        assert_eq!(store.zscore(b"z", b"a", 0).unwrap(), Some(3.0));
    }

    #[test]
    fn zadd_canonicalizes_negative_zero_scores() {
        let mut store = Store::new();
        assert_eq!(store.zadd(b"z", &[(-0.0, b"a".to_vec())], 0).unwrap(), 1);

        let score = store.zscore(b"z", b"a", 0).unwrap().unwrap();
        assert_eq!(score, 0.0);
        assert!(!score.is_sign_negative());

        assert_eq!(store.zadd(b"z", &[(0.0, b"a".to_vec())], 0).unwrap(), 0);
        let pairs = store
            .zrangebyscore_withscores(
                b"z",
                ScoreBound::Inclusive(f64::NEG_INFINITY),
                ScoreBound::Inclusive(f64::INFINITY),
                0,
            )
            .unwrap();
        assert_eq!(pairs, vec![(b"a".to_vec(), 0.0)]);
    }

    #[test]
    fn zset_uses_packed_storage_then_promotes_without_order_drift() {
        fn is_packed(store: &Store, key: &[u8]) -> bool {
            match store.entries.get(key).map(|entry| &entry.value) {
                Some(Value::SortedSet(zs)) => zs.is_packed_storage(),
                _ => false,
            }
        }

        fn is_full(store: &Store, key: &[u8]) -> bool {
            match store.entries.get(key).map(|entry| &entry.value) {
                Some(Value::SortedSet(zs)) => zs.is_full_storage(),
                _ => false,
            }
        }

        let mut store = Store::new();
        store.zset_max_listpack_entries = 2;
        store.zset_max_listpack_value = 3;
        store
            .zadd(b"z", &[(2.0, b"b".to_vec()), (1.0, b"a".to_vec())], 0)
            .unwrap();
        assert!(is_packed(&store, b"z"));
        assert_eq!(store.zrank(b"z", b"a", 0).unwrap(), Some(0));
        assert_eq!(
            store.zrange_withscores(b"z", 0, -1, 0).unwrap(),
            vec![(b"a".to_vec(), 1.0), (b"b".to_vec(), 2.0)]
        );

        store.zadd(b"z", &[(1.0, b"c".to_vec())], 0).unwrap();
        assert!(is_full(&store, b"z"));
        assert_eq!(
            store.zrange(b"z", 0, -1, 0).unwrap(),
            vec![b"a".to_vec(), b"c".to_vec(), b"b".to_vec()]
        );
        assert_eq!(store.zrevrank(b"z", b"a", 0).unwrap(), Some(2));

        store.zadd(b"long", &[(1.5, b"wide".to_vec())], 0).unwrap();
        assert!(is_full(&store, b"long"));
        assert_eq!(store.zscore(b"long", b"wide", 0).unwrap(), Some(1.5));
    }

    #[test]
    fn zset_promotes_when_listpack_limits_tighten_on_existing_update() {
        fn is_full(store: &Store, key: &[u8]) -> bool {
            match store.entries.get(key).map(|entry| &entry.value) {
                Some(Value::SortedSet(zs)) => zs.is_full_storage(),
                _ => false,
            }
        }

        let mut store = Store::new();
        store.zset_max_listpack_entries = 8;
        store
            .zadd(b"z", &[(2.0, b"b".to_vec()), (1.0, b"a".to_vec())], 0)
            .unwrap();
        store.zset_max_listpack_entries = 1;
        assert_eq!(store.zadd(b"z", &[(3.0, b"a".to_vec())], 0).unwrap(), 0);
        assert!(is_full(&store, b"z"));
        assert_eq!(
            store.zrange_withscores(b"z", 0, -1, 0).unwrap(),
            vec![(b"b".to_vec(), 2.0), (b"a".to_vec(), 3.0)]
        );

        let mut value_store = Store::new();
        value_store.zset_max_listpack_value = 8;
        value_store
            .zadd(b"wide", &[(1.0, b"wide".to_vec())], 0)
            .unwrap();
        value_store.zset_max_listpack_value = 3;
        assert_eq!(
            value_store
                .zadd(b"wide", &[(2.0, b"wide".to_vec())], 0)
                .unwrap(),
            0
        );
        assert!(is_full(&value_store, b"wide"));
        assert_eq!(
            value_store.zrange(b"wide", 0, -1, 0).unwrap(),
            vec![b"wide".to_vec()]
        );
    }

    /// (frankenredis-xc0ty) Inverted score bounds (min > max) made
    /// BTreeMap::range panic with "range start is greater than range
    /// end in BTreeMap", taking the server down. Upstream
    /// zsetzCount returns 0 for inverted bounds since the range is
    /// empty by definition. Same guard added to
    /// zrevrangebyscore_withscores.
    #[test]
    fn zcount_zrevrangebyscore_inverted_bounds_short_circuit_xc0ty() {
        let mut store = Store::new();
        store
            .zadd(b"z", &[(1.0, b"a".to_vec()), (2.0, b"b".to_vec())], 0)
            .unwrap();

        // ZCOUNT +inf -inf → 0 (was: panic + crash)
        let n = store
            .zcount(
                b"z",
                ScoreBound::Inclusive(f64::INFINITY),
                ScoreBound::Inclusive(f64::NEG_INFINITY),
                0,
            )
            .expect("inverted bounds must not panic");
        assert_eq!(n, 0);

        // ZCOUNT 5 1 → 0
        let n = store
            .zcount(
                b"z",
                ScoreBound::Inclusive(5.0),
                ScoreBound::Inclusive(1.0),
                0,
            )
            .expect("inverted bounds must not panic");
        assert_eq!(n, 0);

        // Exclusive inverted → 0
        let n = store
            .zcount(
                b"z",
                ScoreBound::Exclusive(2.0),
                ScoreBound::Exclusive(1.0),
                0,
            )
            .expect("inverted exclusive bounds must not panic");
        assert_eq!(n, 0);

        // ZREVRANGEBYSCORE with min > max → empty (no panic).
        // Signature is zrevrangebyscore_withscores(max, min) — passing
        // 1.0 max and 5.0 min is the analogue of ZREVRANGEBYSCORE z 1 5
        // (i.e. user wrote them in the natural-rev order but inverted).
        let pairs = store
            .zrevrangebyscore_withscores(b"z", 1.0, 5.0, 0)
            .expect("inverted bounds must not panic");
        assert_eq!(pairs, Vec::<(Vec<u8>, f64)>::new());

        // Normal in-bounds still works after the fix.
        let n = store
            .zcount(
                b"z",
                ScoreBound::Inclusive(1.0),
                ScoreBound::Inclusive(2.0),
                0,
            )
            .expect("normal bounds");
        assert_eq!(n, 2);
    }

