    // (CrimsonHawk) xreadgroup_history_borrow_scan reconstructs BYTE-IDENTICAL records to clone
    // xreadgroup(Id cursor) — live PEL + tombstones (XDEL'd pending → nil). Measures the per-field
    // clone-elimination A/B.
    #[test]
    fn xreadgroup_history_borrow_scan_matches_clone() {
        use crate::{StreamGroupReadCursor, XreadgroupHistEvent};
        type Rec = Vec<(crate::StreamId, Option<Vec<(Vec<u8>, Vec<u8>)>>)>;
        fn build(n: u64) -> Store {
            let mut s = Store::new();
            for i in 1..=n {
                s.xadd(
                    b"s",
                    (1000, i),
                    &[
                        (format!("f{i}").into_bytes(), format!("v{i}").into_bytes()),
                        (b"fb".to_vec(), vec![b'z'; 20]),
                    ],
                    0,
                )
                .unwrap();
            }
            s.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap();
            s.xreadgroup(
                b"s",
                b"g",
                b"c",
                group_read_options(StreamGroupReadCursor::NewEntries, false, None),
                0,
            )
            .unwrap();
            s
        }
        fn clone_hist(s: &mut Store) -> Rec {
            let recs = s
                .xreadgroup(
                    b"s",
                    b"g",
                    b"c",
                    group_read_options(StreamGroupReadCursor::Id((0, 0)), false, None),
                    0,
                )
                .unwrap()
                .unwrap();
            recs.into_iter()
                .map(|(id, f)| (id, if f.is_empty() { None } else { Some(f) }))
                .collect()
        }
        fn borrow_hist(s: &mut Store) -> Rec {
            let mut recs: Rec = Vec::new();
            let mut pending: Option<Vec<u8>> = None;
            s.xreadgroup_history_borrow_scan(b"s", b"g", b"c", (0, 0), None, 0, |ev| match ev {
                XreadgroupHistEvent::RecordCount(_) => {}
                XreadgroupHistEvent::RecordStart(id, _) => recs.push((id, Some(Vec::new()))),
                XreadgroupHistEvent::RecordStartNil(id) => recs.push((id, None)),
                XreadgroupHistEvent::Field(f) => match pending.take() {
                    None => pending = Some(f.to_vec()),
                    Some(name) => recs
                        .last_mut()
                        .unwrap()
                        .1
                        .as_mut()
                        .unwrap()
                        .push((name, f.to_vec())),
                },
            });
            recs
        }
        let mut s = build(5);
        assert_eq!(clone_hist(&mut s), borrow_hist(&mut s), "live history");
        let mut s2 = build(5);
        s2.xdel(b"s", &[(1000, 2), (1000, 4)], 0).unwrap();
        assert_eq!(
            clone_hist(&mut s2),
            borrow_hist(&mut s2),
            "tombstone history"
        );

        // Timing A/B: 400 pending entries x2 fields (borrow side does NOT reconstruct).
        let mut cl = build(400);
        let mut bo = build(400);
        for _ in 0..200 {
            std::hint::black_box(clone_hist(&mut cl));
            bo.xreadgroup_history_borrow_scan(b"s", b"g", b"c", (0, 0), None, 0, |ev| {
                std::hint::black_box(&ev);
            });
        }
        let reps = 20_000u64;
        let t0 = std::time::Instant::now();
        for _ in 0..reps {
            std::hint::black_box(clone_hist(&mut cl));
        }
        let clone_ns = t0.elapsed().as_nanos() as f64 / reps as f64;
        let t1 = std::time::Instant::now();
        for _ in 0..reps {
            bo.xreadgroup_history_borrow_scan(
                std::hint::black_box(b"s"),
                b"g",
                b"c",
                (0, 0),
                None,
                0,
                |ev| {
                    std::hint::black_box(&ev);
                },
            );
        }
        let borrow_ns = t1.elapsed().as_nanos() as f64 / reps as f64;
        println!(
            "XREADGROUP history @400 pending x2 fields: clone={clone_ns:.0} ns | borrow={borrow_ns:.0} ns = {:.2}x",
            clone_ns / borrow_ns
        );
    }

    #[test]
    fn stream_xreadgroup_new_entries_advances_cursor_and_tracks_consumer() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1000, 0), &[(b"f1".to_vec(), b"v1".to_vec())], 0)
            .unwrap();
        store
            .xadd(b"s", (1000, 1), &[(b"f2".to_vec(), b"v2".to_vec())], 0)
            .unwrap();
        assert!(store.xgroup_create(b"s", b"g1", (0, 0), false, 0).unwrap());

        let first = store
            .xreadgroup(
                b"s",
                b"g1",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, None),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(first.len(), 2);
        assert_eq!(first[0].0, (1000, 0));
        assert_eq!(first[1].0, (1000, 1));
        // entries-read is bumped after each XREADGROUP delivery — the
        // counter reflects the number of entries the group has read so
        // far. (frankenredis-ic8v / 6rpn)
        assert_eq!(
            store.xinfo_groups(b"s", 0).unwrap().expect("groups"),
            vec![(b"g1".to_vec(), 1, 2, (1000, 1), Some(2))]
        );

        let second = store
            .xreadgroup(
                b"s",
                b"g1",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, None),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert!(second.is_empty());

        store
            .xadd(b"s", (1001, 0), &[(b"f3".to_vec(), b"v3".to_vec())], 0)
            .unwrap();
        let third = store
            .xreadgroup(
                b"s",
                b"g1",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(1)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(third.len(), 1);
        assert_eq!(third[0].0, (1001, 0));
        // entries-read continues advancing across new XADD + XREADGROUP
        // rounds. (frankenredis-ic8v)
        assert_eq!(
            store.xinfo_groups(b"s", 0).unwrap().expect("groups"),
            vec![(b"g1".to_vec(), 1, 3, (1001, 0), Some(3))]
        );
    }

