    #[test]
    fn stream_xgroup_delconsumer_dirties_on_existing_consumer_only() {
        // (frankenredis-pt04m) DELCONSUMER bumps dirty once whenever the
        // consumer actually existed and was removed — regardless of pending
        // count. Deleting a non-existent consumer is a no-op (no dirty).
        let mut store = Store::new();
        store
            .xadd(b"s", (1000, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .unwrap();
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap());
        store.xgroup_createconsumer(b"s", b"g", b"c", 0).unwrap();

        // Existing consumer with zero pending entries — must still dirty.
        let before = store.dirty;
        assert_eq!(
            store.xgroup_delconsumer(b"s", b"g", b"c", 0).unwrap(),
            Some(0)
        );
        assert_eq!(
            store.dirty,
            before + 1,
            "deleting an existing consumer dirties"
        );

        // Non-existent consumer — no-op, no dirty.
        let before = store.dirty;
        assert_eq!(
            store.xgroup_delconsumer(b"s", b"g", b"nope", 0).unwrap(),
            Some(0)
        );
        assert_eq!(store.dirty, before, "no-op DELCONSUMER must not dirty");
    }

    #[test]
    fn implicit_consumer_creation_dirties_once_per_new_consumer() {
        // (frankenredis-6zb4d) Upstream t_stream.c creates a missing consumer
        // via streamCreateConsumer(SCC_DEFAULT) inside XREADGROUP / XCLAIM /
        // XAUTOCLAIM, doing server.dirty++ on first use. fr's store inserted the
        // consumer without dirtying, so rdb_changes_since_last_save undercounted
        // by 1 every time a new consumer was named. Re-using an existing
        // consumer must NOT add the create dirty again.
        let mut store = Store::new();
        for i in 0..6u64 {
            store
                .xadd(b"s", (1000, i), &[(b"f".to_vec(), b"v".to_vec())], 0)
                .unwrap();
        }
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap());

        // XREADGROUP with a brand-new consumer: +1 for create, +1 for the
        // synchronous new-entry serve = 2.
        let before = store.dirty;
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(2)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(store.dirty, before + 2, "new consumer create + serve = 2");

        // Re-using c1 delivers 2 more new entries: serve only, no create dirty.
        let before = store.dirty;
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(2)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(store.dirty, before + 1, "existing consumer serve = 1");

        // XCLAIM to a brand-new consumer claiming 2 entries: +1 create + 2.
        let before = store.dirty;
        store
            .xclaim(
                b"s",
                b"g",
                b"c2",
                &[(1000, 0), (1000, 1)],
                StreamClaimOptions {
                    min_idle_time_ms: 0,
                    idle_ms: None,
                    time_ms: None,
                    retry_count: None,
                    force: false,
                    justid: false,
                    last_id: None,
                },
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.dirty,
            before + 3,
            "new consumer create + 2 claimed = 3"
        );

        // XCLAIM re-using c2 for one more entry: per-entry only.
        let before = store.dirty;
        store
            .xclaim(
                b"s",
                b"g",
                b"c2",
                &[(1000, 2)],
                StreamClaimOptions {
                    min_idle_time_ms: 0,
                    idle_ms: None,
                    time_ms: None,
                    retry_count: None,
                    force: false,
                    justid: false,
                    last_id: None,
                },
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(store.dirty, before + 1, "existing consumer + 1 claimed = 1");
    }

    #[test]
    fn xreadgroup_history_read_dirties_once_per_synchronous_serve() {
        // (frankenredis-mlpy4) Upstream xreadCommand does `if (groups)
        // server.dirty++` for every synchronous group serve. For an explicit-ID
        // (history) read that is unconditional — even when zero pending entries
        // are returned. A '>' read only bumps when new entries are delivered.
        let mut store = Store::new();
        for i in 0..3u64 {
            store
                .xadd(b"s", (1000, i), &[(b"f".to_vec(), b"v".to_vec())], 0)
                .unwrap();
        }
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap());
        // Seed c1 with 3 pending via a '>' read.
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(3)),
                0,
            )
            .unwrap()
            .expect("group exists");

        // History read returning pending entries → +1.
        let before = store.dirty;
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::Id((0, 0)), false, Some(3)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.dirty,
            before + 1,
            "history read with results dirties +1"
        );

        // History read returning ZERO entries (start past the last pending) → still +1.
        let before = store.dirty;
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::Id((9999, 0)), false, Some(3)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.dirty,
            before + 1,
            "empty history read still dirties +1"
        );

        // '>' read with no new entries → no bump.
        let before = store.dirty;
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(3)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.dirty, before,
            "'>' read with no new entries must not dirty"
        );
    }

    #[test]
    fn xreadgroup_history_read_start_id_is_exclusive() {
        // Upstream xreadCommand `streamIncrID(&start)`s the user-supplied ID
        // before the inclusive range walk, so a history read anchored at a
        // pending entry's own ID skips that entry and returns only later ones
        // (t_stream.c: "only messages with IDs greater than start").
        let mut store = Store::new();
        for i in 0..3u64 {
            store
                .xadd(b"s", (1000, i), &[(b"f".to_vec(), b"v".to_vec())], 0)
                .unwrap();
        }
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap());
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(3)),
                0,
            )
            .unwrap()
            .expect("group exists");

        // Anchored exactly at the middle pending ID → excludes it, yields 1000-2.
        let records = store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::Id((1000, 1)), false, Some(10)),
                0,
            )
            .unwrap()
            .expect("group exists");
        let ids: Vec<(u64, u64)> = records.iter().map(|(id, _)| *id).collect();
        assert_eq!(ids, vec![(1000, 2)], "history start ID must be exclusive");

        // Anchored at 0 → all three pending entries (none excluded).
        let all = store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::Id((0, 0)), false, Some(10)),
                0,
            )
            .unwrap()
            .expect("group exists");
        let all_ids: Vec<(u64, u64)> = all.iter().map(|(id, _)| *id).collect();
        assert_eq!(all_ids, vec![(1000, 0), (1000, 1), (1000, 2)]);
    }

    #[test]
    fn implicit_consumer_creation_fires_xgroup_createconsumer_event() {
        // (frankenredis-hqj0t) Upstream streamCreateConsumer(SCC_DEFAULT) fires
        // the NOTIFY_STREAM "xgroup-createconsumer" keyspace event when a
        // consumer is implicitly created by XREADGROUP / XCLAIM / XAUTOCLAIM —
        // and fires nothing for an existing consumer.
        let mut store = Store::new();
        store.notify_keyspace_events = NOTIFY_KEYEVENT | crate::NOTIFY_STREAM;
        for i in 0..4u64 {
            store
                .xadd(b"s", (1000, i), &[(b"f".to_vec(), b"v".to_vec())], 0)
                .unwrap();
        }
        assert!(store.xgroup_create(b"s", b"g", (0, 0), false, 0).unwrap());
        let _ = store.drain_keyspace_notifications();

        // New consumer via XREADGROUP → one xgroup-createconsumer event.
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(2)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.drain_keyspace_notifications(),
            vec![(
                b"__keyevent@0__:xgroup-createconsumer".to_vec(),
                b"s".to_vec()
            )]
        );

        // Re-using c1 fires nothing.
        store
            .xreadgroup(
                b"s",
                b"g",
                b"c1",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(1)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert!(store.drain_keyspace_notifications().is_empty());

        // New consumer via XCLAIM → one event even though we claim an entry.
        store
            .xclaim(
                b"s",
                b"g",
                b"c2",
                &[(1000, 0)],
                StreamClaimOptions {
                    min_idle_time_ms: 0,
                    idle_ms: None,
                    time_ms: None,
                    retry_count: None,
                    force: false,
                    justid: false,
                    last_id: None,
                },
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(
            store.drain_keyspace_notifications(),
            vec![(
                b"__keyevent@0__:xgroup-createconsumer".to_vec(),
                b"s".to_vec()
            )]
        );
    }

    #[test]
    fn stream_xgroup_delconsumer_returns_pending_count_and_updates_membership() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1000, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .unwrap();
        assert!(store.xgroup_create(b"s", b"g1", (0, 0), false, 0).unwrap());
        assert_eq!(
            store
                .xgroup_createconsumer(b"s", b"g1", b"alice", 0)
                .unwrap(),
            Some(true)
        );
        assert_eq!(
            store.xgroup_createconsumer(b"s", b"g1", b"bob", 0).unwrap(),
            Some(true)
        );
        let pending_read = store
            .xreadgroup(
                b"s",
                b"g1",
                b"alice",
                group_read_options(StreamGroupReadCursor::NewEntries, false, Some(1)),
                0,
            )
            .unwrap()
            .expect("group exists");
        assert_eq!(pending_read.len(), 1);

        assert_eq!(
            store.xgroup_delconsumer(b"s", b"g1", b"alice", 0).unwrap(),
            Some(1)
        );
        let groups = store.xinfo_groups(b"s", 0).unwrap().expect("groups");
        // entries-read persists across XGROUP DELCONSUMER and no-op
        // calls — only the consumer table is mutated. (frankenredis-ic8v)
        assert_eq!(groups, vec![(b"g1".to_vec(), 1, 0, (1000, 0), Some(1))]);

        assert_eq!(
            store
                .xgroup_delconsumer(b"s", b"g1", b"missing_consumer", 0)
                .unwrap(),
            Some(0)
        );
        let groups = store.xinfo_groups(b"s", 0).unwrap().expect("groups");
        // entries-read persists across XGROUP DELCONSUMER and no-op
        // calls — only the consumer table is mutated. (frankenredis-ic8v)
        assert_eq!(groups, vec![(b"g1".to_vec(), 1, 0, (1000, 0), Some(1))]);

        assert_eq!(
            store
                .xgroup_delconsumer(b"s", b"missing", b"alice", 0)
                .unwrap(),
            None
        );
        assert_eq!(
            store
                .xgroup_delconsumer(b"missing", b"g1", b"alice", 0)
                .unwrap(),
            None
        );

        store.set(b"str".to_vec(), b"value".to_vec(), None, 0);
        assert_eq!(
            store.xgroup_delconsumer(b"str", b"g1", b"alice", 0),
            Err(StoreError::WrongType)
        );
    }

    #[test]
    fn stream_xinfo_consumers_returns_membership_and_errors() {
        let mut store = Store::new();
        store
            .xadd(b"s", (1000, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .unwrap();
        assert!(store.xgroup_create(b"s", b"g1", (0, 0), false, 0).unwrap());

        let empty = store
            .xinfo_consumers(b"s", b"g1", 0)
            .unwrap()
            .expect("consumers");
        assert!(empty.is_empty());

        assert_eq!(
            store.xgroup_createconsumer(b"s", b"g1", b"c2", 0).unwrap(),
            Some(true)
        );
        assert_eq!(
            store.xgroup_createconsumer(b"s", b"g1", b"c1", 0).unwrap(),
            Some(true)
        );
        let consumers = store
            .xinfo_consumers(b"s", b"g1", 0)
            .unwrap()
            .expect("consumers");
        assert_eq!(
            consumers
                .into_iter()
                .map(|(name, _pending, _idle, _inactive)| name)
                .collect::<Vec<_>>(),
            vec![b"c1".to_vec(), b"c2".to_vec()]
        );

        assert_eq!(store.xinfo_consumers(b"s", b"missing", 0).unwrap(), None);
        assert_eq!(
            store.xinfo_consumers(b"missing", b"g1", 0),
            Err(StoreError::KeyNotFound)
        );

        store.set(b"str".to_vec(), b"value".to_vec(), None, 0);
        assert_eq!(
            store.xinfo_consumers(b"str", b"g1", 0),
            Err(StoreError::WrongType)
        );
    }

    #[test]
    fn restore_stream_group_preserves_consumer_seen_and_active_times() {
        // (frankenredis-sq4ov) RDB/AOF restore must carry per-consumer
        // seen_time/active_time so XINFO CONSUMERS idle/inactive survive a
        // reload — `reader` was actively consuming (active set, but seen bumped
        // later by an empty read) while `idle_one` was only created (-1).
        let mut store = Store::new();
        store
            .xadd(b"s", (1, 0), &[(b"f".to_vec(), b"v".to_vec())], 0)
            .unwrap();

        let mut consumer_metadata = std::collections::BTreeMap::new();
        consumer_metadata.insert(
            b"reader".to_vec(),
            super::StreamConsumerMetadata {
                seen_time_ms: 1000,
                active_time_ms: Some(900),
            },
        );
        consumer_metadata.insert(
            b"idle_one".to_vec(),
            super::StreamConsumerMetadata {
                seen_time_ms: 950,
                active_time_ms: None,
            },
        );
        store.restore_stream_group(
            b"s",
            b"g".to_vec(),
            (1, 0),
            Some(0),
            consumer_metadata,
            std::collections::BTreeMap::new(),
        );

        let now = 2000;
        let info = store
            .xinfo_consumers(b"s", b"g", now)
            .unwrap()
            .expect("consumers");
        let by_name: std::collections::BTreeMap<Vec<u8>, (u64, i64)> = info
            .into_iter()
            .map(|(name, _pending, idle, inactive)| (name, (idle, inactive)))
            .collect();
        // reader: idle = now - seen(1000) = 1000; inactive = now - active(900) = 1100.
        assert_eq!(by_name[b"reader".as_slice()], (1000, 1100));
        // idle_one: idle = now - seen(950) = 1050; inactive = -1 (never active).
        assert_eq!(by_name[b"idle_one".as_slice()], (1050, -1));
    }

