    #[test]
    fn incrbyfloat_rejects_stored_value_with_whitespace_6h90t() {
        // (frankenredis-6h90t) Vendored util.c::string2ld rejects stored
        // values that have leading or trailing whitespace (or any non-numeric
        // surround). fr previously called `.trim()` inside `parse_f64` which
        // silently accepted these.
        for stored in &[
            b" 1.5".as_slice(),  // leading space
            b"1.5 ".as_slice(),  // trailing space
            b"\t1.5".as_slice(), // leading tab
            b"1.5\t".as_slice(), // trailing tab
            b" 1.5 ".as_slice(), // both
            b"\n1.5".as_slice(), // leading newline
            b"1.5\n".as_slice(), // trailing newline
        ] {
            let mut store = Store::new();
            store.set(b"k".to_vec(), stored.to_vec(), None, 0);
            let result = store.incrbyfloat_text(b"k", b"1.0", 1.0, 0);
            assert_eq!(
                result,
                Err(StoreError::ValueNotFloat),
                "stored={:?} expected ValueNotFloat",
                String::from_utf8_lossy(stored),
            );
        }
        // Sanity: cleanly-formatted values still parse and increment.
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"1.5".to_vec(), None, 0);
        let next = store.incrbyfloat_text(b"k", b"1.0", 1.0, 0).unwrap();
        assert_eq!(next, b"2.5".to_vec());
    }

    #[test]
    fn hincrbyfloat_rejects_stored_value_with_whitespace_6h90t() {
        // (frankenredis-6h90t) Same rule applies to HINCRBYFLOAT.
        for stored in &[b" 1.5".as_slice(), b"1.5 ".as_slice(), b"\t1.5".as_slice()] {
            let mut store = Store::new();
            store.hset(b"h", b"f".to_vec(), stored.to_vec(), 0).unwrap();
            let result = store.hincrbyfloat_text(b"h", b"f", b"1.0", 1.0, 0);
            assert_eq!(
                result,
                Err(StoreError::ValueNotFloat),
                "stored={:?} expected ValueNotFloat for HINCRBYFLOAT",
                String::from_utf8_lossy(stored),
            );
        }
    }

    #[test]
    fn incrbyfloat_accepts_c99_hex_float_operands() {
        // (frankenredis strtold hex parity) redis parses the increment with
        // `strtold`, which accepts C99 hex floats. fr's store parser was
        // decimal-only and used to reject these. Golden results captured from
        // vendored redis 7.2.4 INCRBYFLOAT against a fresh key.
        let cases: &[(&[u8], &[u8])] = &[
            (b"0x10", b"16"),       // 16
            (b"0xff", b"255"),      // 255
            (b"0x1.8p1", b"3"),     // 1.5 * 2 = 3
            (b"0x1.5p3", b"10.5"),  // 1.3125 * 8 = 10.5
            (b"0xa.bp2", b"42.75"), // 10.6875 * 4 = 42.75
            (b"-0x10", b"-16"),     // negative
            (b"0X1P4", b"16"),      // uppercase 0X / P
            (b"0x0p0", b"0"),       // zero
        ];
        for (delta_text, expected) in cases {
            let mut store = Store::new();
            // delta f64 is the command-layer placeholder (0.0); the store uses
            // the text via the faithful f80 parser.
            let next = store
                .incrbyfloat_text(b"k", delta_text, 0.0, 0)
                .unwrap_or_else(|e| panic!("INCRBYFLOAT {delta_text:?} errored: {e:?}"));
            assert_eq!(
                next,
                expected.to_vec(),
                "INCRBYFLOAT 0 + {} expected {}",
                String::from_utf8_lossy(delta_text),
                String::from_utf8_lossy(expected),
            );
        }
        // Chained accumulation (rounding path): 0xff twice => 510.
        let mut store = Store::new();
        store.incrbyfloat_text(b"k", b"0xff", 0.0, 0).unwrap();
        let next = store.incrbyfloat_text(b"k", b"0xff", 0.0, 0).unwrap();
        assert_eq!(next, b"510".to_vec());
        // Invalid hex floats are rejected by the command-layer operand gate
        // (long_double_text_is_valid), exercised end-to-end by
        // scripts/hexfloat_incr_differ.py — the units below lock the validator.
        for bad in &[
            b"0x".as_slice(),
            b"0xg",
            b"0xp4",
            b"0x1.5p",
            b"0x1.2.3",
            b"0x.",
        ] {
            assert!(
                !crate::long_double_text_is_valid(bad),
                "expected {:?} to be an invalid long double",
                String::from_utf8_lossy(bad),
            );
        }
        for good in &[b"0x10".as_slice(), b"0x1.5p3", b"-0xff", b"0X1P4"] {
            assert!(
                crate::long_double_text_is_valid(good),
                "expected {:?} to be a valid long double",
                String::from_utf8_lossy(good),
            );
        }
    }

    #[test]
    #[allow(clippy::approx_constant, clippy::excessive_precision)]
    fn zset_score_int_listpack_fastpath_is_byte_identical_to_string_form() {
        // The DUMP zset-listpack score fast path
        // (zset_score_listpack_entry + encode_listpack_integer_entry) MUST emit
        // byte-IDENTICAL listpack bytes to the prior string form
        // (encode_listpack_entry(redis_score_to_string(score))) for EVERY score —
        // including the negative-zero trap and the int/string boundary.
        // (frankenredis-dump-zset-score-int)
        let mut scores: Vec<f64> = vec![
            0.0,
            -0.0,
            1.0,
            -1.0,
            42.0,
            -42.0,
            127.0,
            128.0,
            -128.0,
            4095.0,
            4096.0,
            -4096.0,
            -4097.0,
            32767.0,
            32768.0,
            8_388_607.0,
            8_388_608.0,
            2_147_483_647.0,
            2_147_483_648.0,
            17179869184.0,
            1e18,
            -1e18,
            1e17,
            -1e17,
            999_999_999_999.0,
            // non-integer / out-of-range → must take the string fallback
            3.14,
            -2.5,
            0.1,
            0.000001,
            -0.0007,
            1.5,
            2.5,
            1e20,
            1.5e300,
            -1.5e300,
            123456789.123456789,
            f64::INFINITY,
            f64::NEG_INFINITY,
            f64::NAN,
            1e18 + 1.0,
            -1e18 - 1.0,
            9.2e18,
            // `double2ll`'s real window is ±(LLONG_MAX/2), which rounds to ±2^62 as a
            // double — NOT ±2^52, and not the ±1e18 the old gate used. Both sides of
            // the inclusive bound must still int-encode.
            4.611686018427387904e18,  // 2^62 exactly
            -4.611686018427387904e18, // -2^62 exactly
            4.611686018427387392e18,  // 2^62 - 512 (one double ulp below)
            // ABOVE the window, but grisu2's shortest form is still a plain canonical
            // decimal inside i64 range, so upstream int-encodes these. These are the
            // cases that make the `Reparse` arm load-bearing: string-encoding them
            // (i.e. skipping the re-parse on any non-`Int` classification) diverges.
            6.917529027641081856e18, // -> "6917529027641082000", int-encoded upstream
            7.2e18,
            // Above the window AND the plain form overflows i64 -> string-encoded.
            9.223372036854775808e18, // 2^63 -> "9223372036854776000"
            5e18,                    // -> "5e+18"
            7e18,                    // -> "7e+18"
            -5e18,
            1e19,
            f64::MAX,
            f64::MIN,
            f64::MIN_POSITIVE,
            -f64::MIN_POSITIVE,
        ];
        // Add every integer in a dense band to exercise all listpack int widths.
        for i in -5000i64..=5000 {
            scores.push(i as f64);
        }
        // Dense fractional band: these take the `Str` arm, which is the one that skips
        // the re-parse, so it must never swallow a value whose render re-parses.
        for i in -500i64..=500 {
            scores.push(i as f64 + 0.5);
            scores.push(i as f64 / 3.0);
        }
        for &score in &scores {
            let mut want = Vec::new();
            super::encode_listpack_entry(&mut want, redis_score_to_string(score).as_bytes());
            let mut got = Vec::new();
            match super::zset_score_listpack_entry(score) {
                super::ZsetScoreListpackEntry::Int(int_score) => {
                    super::encode_listpack_integer_entry(&mut got, int_score);
                }
                super::ZsetScoreListpackEntry::Str => {
                    super::encode_listpack_string_entry(
                        &mut got,
                        redis_score_to_string(score).as_bytes(),
                    );
                }
                super::ZsetScoreListpackEntry::Reparse => {
                    super::encode_listpack_entry(&mut got, redis_score_to_string(score).as_bytes());
                }
            }
            assert_eq!(
                want,
                got,
                "score {score} (d2string={:?}) diverged",
                redis_score_to_string(score)
            );
        }
    }

    /// Pins the counterexample that forces the `Reparse` arm to exist. Upstream renders
    /// this integral double — above `double2ll`'s window, so `d2string` uses grisu2 — as
    /// the plain canonical decimal "6917529027641082000", then int-encodes it. Collapsing
    /// `Reparse` into `Str` (i.e. string-encoding whenever the int fast path misses) would
    /// emit a string entry here and diverge from redis 7.2.4.
    #[test]
    fn zset_score_reparse_arm_is_load_bearing() {
        let score = 6.917529027641081856e18;
        assert!(matches!(
            super::zset_score_listpack_entry(score),
            super::ZsetScoreListpackEntry::Reparse
        ));
        let rendered = redis_score_to_string(score);
        assert_eq!(rendered, "6917529027641082000");
        assert!(super::parse_listpack_integer(rendered.as_bytes()).is_some());

        // The two encodings genuinely differ, so the test above discriminates.
        let mut int_form = Vec::new();
        super::encode_listpack_entry(&mut int_form, rendered.as_bytes());
        let mut str_form = Vec::new();
        super::encode_listpack_string_entry(&mut str_form, rendered.as_bytes());
        assert_ne!(int_form, str_form);
    }

    /// The `Str` arm is the only one that skips `parse_listpack_integer`. Prove the
    /// classifier never routes a score there whose `d2string` render would in fact
    /// re-parse as a canonical i64 — that would silently flip the entry encoding.
    #[test]
    fn zset_score_str_arm_never_hides_a_canonical_integer_render() {
        let mut scores: Vec<f64> = vec![
            0.0,
            -0.0,
            f64::INFINITY,
            f64::NEG_INFINITY,
            f64::NAN,
            3.14,
            -2.5,
            1e20,
            5e18,
            9.223372036854775808e18,
            f64::MAX,
            f64::MIN_POSITIVE,
        ];
        for i in -2000i64..=2000 {
            scores.push(i as f64 + 0.25);
            scores.push(i as f64 * 1.5);
            scores.push(i as f64);
        }
        for &score in &scores {
            if let super::ZsetScoreListpackEntry::Str = super::zset_score_listpack_entry(score) {
                let rendered = redis_score_to_string(score);
                assert!(
                    super::parse_listpack_integer(rendered.as_bytes()).is_none(),
                    "score {score} classified Str but d2string={rendered:?} re-parses as an integer"
                );
            }
        }
    }

    #[test]
    #[allow(clippy::approx_constant, clippy::excessive_precision)]
    fn redis_score_to_string_matches_vendored_d2string() {
        // Golden values captured from vendored redis 7.2.4 ZSCORE (d2string ->
        // fpconv_dtoa). Verified byte-exact against the oracle across 437
        // diverse magnitudes; these lock the representative branches.
        // (frankenredis-sk4ss)
        let cases: &[(f64, &str)] = &[
            // specials
            (0.0, "0"),
            (-0.0, "-0"),
            (f64::INFINITY, "inf"),
            (f64::NEG_INFINITY, "-inf"),
            // exact-integer fast path (double2ll)
            (3.0, "3"),
            (17179869184.0, "17179869184"),
            (-42.0, "-42"),
            // fixed decimal > 1
            (3.14, "3.14"),
            (123.456, "123.456"),
            (2.5, "2.5"),
            (-2.5, "-2.5"),
            // fixed decimal < 1
            (0.1, "0.1"),
            (0.000001, "0.000001"),
            (-0.0007, "-0.0007"),
            // scientific: many significant digits (K <= -7), regression for the
            // old log10_floor heuristic that wrongly emitted fixed here
            (123456789.123456789, "1.2345678912345679e+8"),
            // scientific: large magnitude
            (1.5e300, "1.5e+300"),
            (1e20, "1e+20"),
            (1e308, "1e+308"),
            (-1.5e300, "-1.5e+300"),
            (6.022e23, "6.022e+23"),
            // scientific: small magnitude (K <= -7 and exp >= 4)
            (1e-7, "1e-7"),
            (1e-10, "1e-10"),
            (1.6e-19, "1.6e-19"),
        ];
        for (value, expected) in cases {
            assert_eq!(
                &super::redis_score_to_string(*value),
                expected,
                "redis_score_to_string({value:?})"
            );
        }
        assert_eq!(super::redis_score_to_string(f64::NAN), "nan");
    }

