    #[test]
    fn lrem_count_zero_nomatch_preserves_list_and_dirty() {
        let mut store = Store::new();
        store
            .rpush(b"l", &[b"a".to_vec(), b"b".to_vec(), b"c".to_vec()], 0)
            .unwrap();
        let before_dirty = store.dirty;
        let before = store.lrange(b"l", 0, -1, 0).unwrap();

        let removed = store.lrem(b"l", 0, b"x", 0).unwrap();

        assert_eq!(removed, 0);
        assert_eq!(store.dirty, before_dirty);
        assert_eq!(store.lrange(b"l", 0, -1, 0).unwrap(), before);
    }

    // (frankenredis-387i6) The bounded-count early-stop / index-remove path must
    // produce a removal set byte-identical to the single-pass retain oracle for
    // every count regime (positive small/large, negative small/large, zero) and
    // every match distribution. A naive Vec LREM is the reference.
    #[test]
    fn lrem_index_remove_matches_retain_oracle() {
        fn oracle(list: &[Vec<u8>], count: i64, target: &[u8]) -> Vec<Vec<u8>> {
            let mut out = Vec::with_capacity(list.len());
            if count > 0 {
                let mut left = count as usize;
                for v in list {
                    if left > 0 && v.as_slice() == target {
                        left -= 1;
                    } else {
                        out.push(v.clone());
                    }
                }
            } else if count < 0 {
                // Remove the last |count| matches: walk back-to-front, then
                // restore original order.
                let mut left = count.unsigned_abs() as usize;
                let mut rev: Vec<Vec<u8>> = Vec::with_capacity(list.len());
                for v in list.iter().rev() {
                    if left > 0 && v.as_slice() == target {
                        left -= 1;
                    } else {
                        rev.push(v.clone());
                    }
                }
                rev.reverse();
                out = rev;
            } else {
                for v in list {
                    if v.as_slice() != target {
                        out.push(v.clone());
                    }
                }
            }
            out
        }

        // Deterministic LCG so the proof is reproducible (no Date/rand needed).
        let mut state: u64 = 0x9e37_79b9_7f4a_7c15;
        let mut next = || {
            state = state
                .wrapping_mul(6364136223846793005)
                .wrapping_add(1442695040888963407);
            (state >> 33) as u32
        };
        // Cover both list reprs by exercising small (listpack) and large (deque)
        // lists, and counts straddling LREM_INDEX_REMOVE_MAX (128).
        let counts: [i64; 11] = [1, 2, 3, 5, 64, 128, 129, 200, -1, -5, -130];
        for trial in 0..400u32 {
            let len = (next() % 500 + 1) as usize;
            // Small member alphabet so matches are dense and span the whole list.
            let alphabet = 1 + (next() % 4) as u64; // 1..=4 distinct values
            let list: Vec<Vec<u8>> = (0..len)
                .map(|_| format!("v{}", next() as u64 % alphabet).into_bytes())
                .collect();
            let target = format!("v{}", next() as u64 % (alphabet + 1)).into_bytes();
            let count = counts[(next() as usize) % counts.len()];

            let mut store = Store::new();
            store.rpush(b"l", &list, 0).unwrap();
            let removed = store.lrem(b"l", count, &target, 0).unwrap();
            let got = store.lrange(b"l", 0, -1, 0).unwrap();

            let expected = oracle(&list, count, &target);
            let expected_removed = (list.len() - expected.len()) as u64;
            assert_eq!(
                removed, expected_removed,
                "trial {trial}: count={count} len={len} removed mismatch"
            );
            assert_eq!(
                got, expected,
                "trial {trial}: count={count} len={len} target={target:?} residual list mismatch"
            );
        }
    }

    // (frankenredis-387i6) Concrete before/after timing for the LREM bounded
    // early-stop lever. `cargo test -- --ignored --nocapture lrem_bench`.
    // (frankenredis-zrange-probe) Quantify the member-CLONE cost of the plain
    // ZRANGE reply: `store.zrange` collects `Vec<Vec<u8>>` (clones every member),
    // vs a borrowing `iter_asc()` walk that touches the same bytes with zero
    // per-member allocation. This is a MEASUREMENT probe to decide whether a
    // zero-copy zrange_borrow_scan is worth the fr-store work — NOT a shipped
    // fast path. Run: `cargo test -p fr-store -- --ignored --nocapture
    // zrange_probe_clone_vs_borrow`.
    #[test]
    #[ignore]
    fn zrange_probe_clone_vs_borrow() {
        use std::time::Instant;
        const N: usize = 10_000;
        const MEMBER_LEN: usize = 32;
        const ITERS: usize = 20_000;

        let mut store = Store::new();
        for i in 0..N {
            let mut m = vec![b'm'; MEMBER_LEN];
            m[0..8].copy_from_slice(&(i as u64).to_be_bytes());
            store.zadd(b"z", &[(i as f64, m)], 0).unwrap();
        }

        for &start_idx in &[0usize, N / 2] {
            let count = N - start_idx;

            // CLONE path: what plain ZRANGE does today (owned Vec<Vec<u8>>).
            let mut sink = 0usize;
            let t = Instant::now();
            for _ in 0..ITERS {
                let members = store.zrange(b"z", start_idx as i64, -1, 0).unwrap();
                sink += members.iter().map(|m| m.len()).sum::<usize>();
            }
            let clone_us = t.elapsed().as_secs_f64() * 1e6;

            // BORROW path: iter_asc().skip(start).take(count), zero per-member alloc.
            let t = Instant::now();
            for _ in 0..ITERS {
                if let Some(entry) = store.entries.get(b"z".as_slice())
                    && let Value::SortedSet(zs) = &entry.value
                {
                    for (m, _s) in zs.iter_asc().skip(start_idx).take(count) {
                        sink += m.len();
                    }
                }
            }
            let borrow_us = t.elapsed().as_secs_f64() * 1e6;

            eprintln!(
                "ZRANGE start={start_idx} count={count} x{ITERS}: CLONE(Vec<Vec<u8>>)={clone_us:.0}us  \
                 BORROW(iter_asc walk)={borrow_us:.0}us  speedup={:.2}x  (sink={sink})",
                clone_us / borrow_us
            );
        }
    }

    // (frankenredis-hmgetinto) Concrete before/after timing of the value-copy work
    // HMGET does per reply: owned `hmget` clones every hit value into a fresh
    // `Vec<u8>` inside a `Vec<Option<Vec<u8>>>`; borrowed `hmget_for_each` streams
    // the borrowed slices with zero per-value allocation. This bench isolates the
    // clone/alloc portion (the RESP-frame savings live in fr-runtime). Run with
    // `cargo test -p fr-store -- --ignored --nocapture hmget_bench_borrow_vs_clone`.
    #[test]
    #[ignore]
    fn hmget_bench_borrow_vs_clone() {
        use std::time::Instant;
        const NFIELDS: usize = 32;
        const VALUE_LEN: usize = 64; // wide-ish values where copy cost shows
        const ITERS: usize = 200_000;

        let mut store = Store::new();
        let field_names: Vec<Vec<u8>> = (0..NFIELDS)
            .map(|i| format!("f{i:03}").into_bytes())
            .collect();
        for f in &field_names {
            store
                .hset(b"h", f.clone(), vec![b'v'; VALUE_LEN], 0)
                .unwrap();
        }
        let fields: Vec<&[u8]> = field_names.iter().map(|f| f.as_slice()).collect();

        // OLD path: owned hmget clones every value into Vec<Option<Vec<u8>>>.
        let mut sink = 0usize;
        let t = Instant::now();
        for _ in 0..ITERS {
            let values = store.hmget(b"h", &fields, 0).unwrap();
            sink += values.iter().filter(|v| v.is_some()).count();
        }
        let old_us = t.elapsed().as_secs_f64() * 1e6;

        // NEW path: borrowed hmget_for_each streams slices, no per-value alloc.
        let t = Instant::now();
        for _ in 0..ITERS {
            store
                .hmget_for_each(b"h", &fields, 0, |v| {
                    if let Some(v) = v {
                        sink += v.len() & 1;
                    }
                })
                .unwrap();
        }
        let new_us = t.elapsed().as_secs_f64() * 1e6;

        eprintln!(
            "HMGET {NFIELDS}x{VALUE_LEN}B x{ITERS}: OLD(clone Vec<Option<Vec>>)={old_us:.0}us  \
             NEW(borrow for_each)={new_us:.0}us  speedup={:.2}x  (sink={sink})",
            old_us / new_us
        );
        assert!(new_us < old_us, "borrowed path should not be slower");
    }

    #[test]
    #[ignore]
    fn lrem_bench_index_vs_retain() {
        use std::time::Instant;
        const N: usize = 300_000;
        // Every-other element matches "X" (the bead's workload).
        let build = || -> Vec<Vec<u8>> {
            (0..N)
                .map(|i| {
                    if i % 2 == 0 {
                        b"X".to_vec()
                    } else {
                        b"y".to_vec()
                    }
                })
                .collect()
        };

        // NEW path: Store::lrem with small bounded count (early-stop + index remove).
        let mut store = Store::new();
        store.rpush(b"l", &build(), 0).unwrap();
        let t = Instant::now();
        let removed_new = store.lrem(b"l", 5, b"X", 0).unwrap();
        let new_us = t.elapsed().as_secs_f64() * 1e6;

        // OLD path: single-pass retain over the whole list + O(n) on_remove_bulk
        // rescan (what the bounded branch used to do).
        let mut store2 = Store::new();
        store2.rpush(b"l", &build(), 0).unwrap();
        let mut removed_old = 0u64;
        let t = Instant::now();
        if let Some(entry) = store2.entries.get_mut(b"l".as_slice())
            && let Value::List(l) = &mut entry.value
        {
            let limit = 5u64;
            l.retain(|v| {
                if removed_old < limit && v == b"X" {
                    removed_old += 1;
                    false
                } else {
                    true
                }
            });
        }
        let old_us = t.elapsed().as_secs_f64() * 1e6;

        assert_eq!(removed_new, 5);
        assert_eq!(removed_old, 5);
        eprintln!(
            "LREM 5 X over {N}-elem list: OLD(retain+bulk-rescan)={old_us:.0}us  NEW(early-stop+index)={new_us:.0}us  speedup={:.1}x",
            old_us / new_us
        );
        assert!(
            new_us * 5.0 < old_us,
            "expected >=5x speedup, got {:.1}x",
            old_us / new_us
        );
    }

    // (frankenredis-k681u) Single ZRANDMEMBER must return the SAME member as the
    // old `iter_asc().nth(idx)` linear skip for every index — the treap-select
    // jump only changes the access path, not which element is chosen. Verify
    // across both encodings (small Packed + large promoted Full), warm and cold
    // treap, for every index in the set.
    #[test]
    fn zrandmember_single_index_select_matches_linear_nth() {
        for n in [8usize, 200, 5000] {
            let mut store = Store::new();
            for i in 0..n {
                // Distinct scores so the ascending order is unambiguous; member
                // bytes deliberately NOT in score order so sorted-position differs
                // from insertion/hash position.
                store
                    .zadd(
                        b"z",
                        &[(
                            i as f64,
                            format!("m{:08x}", (i * 2654435761) % n).into_bytes(),
                        )],
                        0,
                    )
                    .unwrap();
            }
            // Reference: idx-th member in ascending (score, member) order.
            let reference: Vec<Vec<u8>> = {
                let entry = store.entries.get(b"z".as_slice()).unwrap();
                match &entry.value {
                    Value::SortedSet(zs) => zs.iter_asc().map(|(m, _)| m.to_vec()).collect(),
                    _ => unreachable!(),
                }
            };
            let len = reference.len();
            // Exercise both a cold path (low idx) and warmed path (repeated deep
            // draws warm the treap), every index covered.
            for (idx, ref_member) in reference.iter().enumerate().take(len) {
                let entry = store.entries.get_mut(b"z".as_slice()).unwrap();
                let got = match &mut entry.value {
                    Value::SortedSet(zs) => zs
                        .index_slice_asc_adaptive(idx, 1)
                        .into_iter()
                        .next()
                        .map(|(m, _)| m),
                    _ => unreachable!(),
                };
                assert_eq!(
                    got.as_ref(),
                    Some(ref_member),
                    "n={n} idx={idx}: select jump diverged from linear nth"
                );
            }
        }
    }

    // (frankenredis-k681u) Concrete before/after timing.
    // `cargo test -- --ignored --nocapture zrandmember_bench`.
    #[test]
    #[ignore]
    fn zrandmember_bench_select_vs_nth() {
        use std::time::Instant;
        const N: usize = 200_000;
        let mut store = Store::new();
        let items: Vec<(f64, Vec<u8>)> = (0..N)
            .map(|i| (i as f64, format!("m{i:08}").into_bytes()))
            .collect();
        store.zadd(b"z", &items, 0).unwrap();

        // Deep index near the end so the O(idx) skip is maximally expensive.
        let idx = N - 3;

        // OLD: linear iter_asc().nth(idx).
        let entry = store.entries.get(b"z".as_slice()).unwrap();
        let (old_us, old_m) = match &entry.value {
            Value::SortedSet(zs) => {
                let t = Instant::now();
                let m = zs.iter_asc().nth(idx).map(|(m, _)| m.to_vec());
                (t.elapsed().as_secs_f64() * 1e6, m)
            }
            _ => unreachable!(),
        };

        // NEW: warm treap then select jump.
        let entry = store.entries.get_mut(b"z".as_slice()).unwrap();
        let (new_us, new_m) = match &mut entry.value {
            Value::SortedSet(zs) => {
                // Warm the treap (one-time O(n), amortized over many draws).
                let _ = zs.index_slice_asc_adaptive(idx, 1);
                let _ = zs.index_slice_asc_adaptive(idx, 1);
                let _ = zs.index_slice_asc_adaptive(idx, 1);
                let t = Instant::now();
                let m = zs
                    .index_slice_asc_adaptive(idx, 1)
                    .into_iter()
                    .next()
                    .map(|(m, _)| m);
                (t.elapsed().as_secs_f64() * 1e6, m)
            }
            _ => unreachable!(),
        };
        assert_eq!(old_m, new_m, "bench picked different member");
        eprintln!(
            "ZRANDMEMBER single idx={idx} over {N}-elem zset: OLD(iter.nth)={old_us:.1}us  NEW(treap select)={new_us:.3}us  speedup={:.0}x",
            old_us / new_us
        );
        assert!(
            new_us * 5.0 < old_us,
            "expected >=5x, got {:.0}x",
            old_us / new_us
        );
    }

