    #[test]
    fn dump_payload_uses_redis_dump_footer() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"hello".to_vec(), Some(1_100), 100);
        let payload = store.dump_key(b"k", 100).unwrap();

        let version_offset = payload.len() - DUMP_TRAILER_LEN;
        let crc_offset = payload.len() - DUMP_CRC64_LEN;
        assert_eq!(payload[0], 0);
        assert_eq!(payload[1], 5);
        assert_eq!(&payload[2..version_offset], b"hello");
        assert_eq!(
            &payload[version_offset..crc_offset],
            &RDB_DUMP_VERSION.to_le_bytes()
        );
        let stored_crc = u64::from_le_bytes(payload[crc_offset..].try_into().expect("crc bytes"));
        assert_eq!(stored_crc, fr_persist::crc64_redis(&payload[..crc_offset]));
    }

    #[test]
    fn restore_rejects_unsupported_dump_version() {
        let mut store = Store::new();
        store.set(b"k".to_vec(), b"hello".to_vec(), None, 100);
        let mut payload = store.dump_key(b"k", 100).unwrap();

        let version_offset = payload.len() - DUMP_TRAILER_LEN;
        payload[version_offset..version_offset + DUMP_VERSION_LEN]
            .copy_from_slice(&(RDB_DUMP_VERSION + 1).to_le_bytes());
        let crc_offset = payload.len() - DUMP_CRC64_LEN;
        let crc = fr_persist::crc64_redis(&payload[..crc_offset]);
        payload[crc_offset..].copy_from_slice(&crc.to_le_bytes());

        let mut store2 = Store::new();
        assert_eq!(
            store2.restore_key(b"k", 0, &payload, false, 100),
            Err(StoreError::InvalidDumpPayload)
        );
    }

    fn append_dump_footer(mut body: Vec<u8>) -> Vec<u8> {
        body.extend_from_slice(&RDB_DUMP_VERSION.to_le_bytes());
        let crc = fr_persist::crc64_redis(&body);
        body.extend_from_slice(&crc.to_le_bytes());
        body
    }

    #[test]
    fn dump_string_uses_upstream_integer_string_encoding() {
        let mut store = Store::new();
        store.set(b"i8".to_vec(), b"123".to_vec(), None, 100);
        store.set(b"i16".to_vec(), b"-129".to_vec(), None, 100);
        store.set(b"i32".to_vec(), b"2147483647".to_vec(), None, 100);
        store.set(b"raw".to_vec(), b"00123".to_vec(), None, 100);

        let i8_payload = store.dump_key(b"i8", 100).unwrap();
        assert_eq!(&i8_payload[..3], &[RDB_TYPE_STRING, 0xC0, 123]);

        let i16_payload = store.dump_key(b"i16", 100).unwrap();
        assert_eq!(i16_payload[0], RDB_TYPE_STRING);
        assert_eq!(i16_payload[1], 0xC1);
        assert_eq!(
            &i16_payload[2..4],
            &i16::try_from(-129).unwrap().to_le_bytes()
        );

        let i32_payload = store.dump_key(b"i32", 100).unwrap();
        assert_eq!(i32_payload[0], RDB_TYPE_STRING);
        assert_eq!(i32_payload[1], 0xC2);
        assert_eq!(&i32_payload[2..6], &2147483647i32.to_le_bytes());

        let raw_payload = store.dump_key(b"raw", 100).unwrap();
        assert_eq!(
            &raw_payload[..7],
            &[RDB_TYPE_STRING, 5, b'0', b'0', b'1', b'2', b'3']
        );
    }

    #[test]
    fn dump_hashtable_collection_elements_lzf_and_integer_encode() {
        // The hashtable-set / hashtable-hash / skiplist-zset DUMP element loops
        // must serialize each element through the same encoder as top-level
        // strings (integer encoding + LZF for long compressible values), matching
        // upstream rdbSaveStringObject — not a raw length+bytes copy. Regression
        // for the encode_dump_bulk bypass that left collection elements
        // uncompressed and never integer-encoded.
        let mut store = Store::new();
        store.hash_max_listpack_entries = 0; // force RDB_TYPE_HASH (hashtable)
        store.set_max_intset_entries = 0;
        store.set_max_listpack_entries = 0; // force RDB_TYPE_SET (hashtable)

        // Long, highly compressible hash value -> LZF (0xC3), payload << raw 200B.
        store.hset(b"h", b"f".to_vec(), vec![b'x'; 200], 0).unwrap();
        let h = store.dump_key(b"h", 0).unwrap();
        assert_eq!(h[0], RDB_TYPE_HASH);
        assert!(
            h.contains(&0xC3),
            "long hashtable hash value must be LZF-encoded (0xC3 missing): {h:?}"
        );
        assert!(
            h.len() < 100,
            "LZF must shrink the 200B value, got {} bytes",
            h.len()
        );

        // Integer member in a hashtable set -> integer string encoding (0xC1),
        // not a raw "12345" string.
        store.sadd(b"s", &[b"12345".to_vec()], 0).unwrap();
        let s = store.dump_key(b"s", 0).unwrap();
        assert_eq!(s[0], RDB_TYPE_SET);
        assert_eq!(s[1], 1, "set member count");
        assert_eq!(s[2], 0xC1, "integer set member must use integer encoding");
        assert_eq!(&s[3..5], &12345i16.to_le_bytes());
    }

    #[test]
    fn dump_set_listpack_direct_emit_matches_flat_reference_lbmk6() {
        let mut generic = SetValue::new();
        for member in [
            b"alpha".as_slice(),
            b"127".as_slice(),
            b"-2".as_slice(),
            b"hello\0world".as_slice(),
        ] {
            generic.insert_borrowed(member, 512);
        }
        let direct = encode_set_listpack_dump(&generic).expect("generic set listpack");
        let owned: Vec<Vec<u8>> = generic.iter().map(|member| member.into_owned()).collect();
        let refs: Vec<&[u8]> = owned.iter().map(Vec::as_slice).collect();
        assert_eq!(direct, encode_listpack_strings(&refs).unwrap());
        assert_eq!(decode_listpack_strings(&direct).unwrap(), owned);

        let intset = SetValue::Int(vec![-2, 0, 127, 4095]);
        let direct = encode_set_listpack_dump(&intset).expect("intset listpack");
        let owned: Vec<Vec<u8>> = intset.iter().map(|member| member.into_owned()).collect();
        let refs: Vec<&[u8]> = owned.iter().map(Vec::as_slice).collect();
        assert_eq!(direct, encode_listpack_strings(&refs).unwrap());
        assert_eq!(decode_listpack_strings(&direct).unwrap(), owned);
    }

