    #[test]
    fn dump_quicklist2_uses_redis_size_estimate_for_node_boundaries() {
        let mut store = Store::new();
        let first = vec![b'a'; 8_174];
        let second = b"b".to_vec();
        let items = vec![first.clone(), second.clone()];
        store.rpush(b"l", &items, 100).unwrap();

        let payload = store.dump_key(b"l", 100).unwrap();
        let data_end = payload.len() - DUMP_TRAILER_LEN;
        assert_eq!(payload[0], RDB_TYPE_LIST_QUICKLIST_2);
        let mut cursor = 1;
        let (node_count, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(node_count, 2);

        let (container, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(container, 2);
        let (listpack, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
        cursor += consumed;
        assert_eq!(decode_listpack_strings(&listpack).unwrap(), vec![first]);

        let (container, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(container, 2);
        let (listpack, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
        cursor += consumed;
        assert_eq!(decode_listpack_strings(&listpack).unwrap(), vec![second]);
        assert_eq!(cursor, data_end);

        let mut restored = Store::new();
        restored.restore_key(b"l", 0, &payload, false, 100).unwrap();
        assert_eq!(restored.lrange(b"l", 0, -1, 100).unwrap(), items);
    }

    #[test]
    fn dump_big_list_item_uses_packed_lzf_quicklist_node() {
        let mut store = Store::new();
        let big = vec![b'x'; 9_000];
        store.rpush(b"l", std::slice::from_ref(&big), 100).unwrap();

        let payload = store.dump_key(b"l", 100).unwrap();
        assert_eq!(payload[0], RDB_TYPE_LIST_QUICKLIST_2);
        assert_eq!(payload[1], 1); // one quicklist node
        // container=PACKED (0x02): an element over the per-node budget but < 1 GiB
        // is its OWN 1-element PACKED listpack node, NOT a PLAIN node — byte-identical
        // to redis 7.2.4 DUMP (verified via DUMP md5 parity). (frankenredis-1z4ba)
        assert_eq!(payload[2], 2);
        assert_eq!(payload[3], 0xC3); // LZF-encoded RDB string payload
        assert!(
            payload.len() < 200,
            "packed LZF node should be compact, got {} bytes",
            payload.len()
        );

        let data_end = payload.len() - DUMP_TRAILER_LEN;
        let (listpack, consumed) = decode_rdb_string(&payload, 3, data_end).unwrap();
        assert_eq!(
            decode_listpack_strings(&listpack).unwrap(),
            vec![big.clone()]
        );
        assert_eq!(3 + consumed, data_end);

        let mut restored = Store::new();
        restored.restore_key(b"l", 0, &payload, false, 100).unwrap();
        assert_eq!(restored.lrange(b"l", 0, -1, 100).unwrap(), vec![big]);
    }

    #[test]
    fn dump_mixed_list_keeps_small_items_packed_around_packed_big_item() {
        let mut store = Store::new();
        let big = vec![b'x'; 9_000];
        let items = vec![b"a".to_vec(), b"b".to_vec(), big.clone(), b"c".to_vec()];
        store.rpush(b"l", &items, 100).unwrap();

        let payload = store.dump_key(b"l", 100).unwrap();
        let data_end = payload.len() - DUMP_TRAILER_LEN;
        assert_eq!(payload[0], RDB_TYPE_LIST_QUICKLIST_2);
        let mut cursor = 1;
        let (node_count, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(node_count, 3);

        let (container, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(container, 2);
        let (listpack, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
        cursor += consumed;
        let first_reference = encode_listpack_strings(&[b"a".as_slice(), b"b".as_slice()])
            .expect("first reference listpack");
        assert_eq!(listpack, first_reference);
        assert_eq!(
            decode_listpack_strings(&listpack).unwrap(),
            vec![b"a".to_vec(), b"b".to_vec()]
        );

        let (container, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        // The over-budget element is its OWN 1-element PACKED listpack node
        // (container 0x02), not a PLAIN node — byte-identical to redis 7.2.4.
        assert_eq!(container, 2);
        let (big_listpack, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
        cursor += consumed;
        assert_eq!(
            decode_listpack_strings(&big_listpack).unwrap(),
            vec![big.clone()]
        );

        let (container, consumed) = decode_length(&payload, cursor).unwrap();
        cursor += consumed;
        assert_eq!(container, 2);
        let (listpack, consumed) = decode_rdb_string(&payload, cursor, data_end).unwrap();
        cursor += consumed;
        let last_reference =
            encode_listpack_strings(&[b"c".as_slice()]).expect("last reference listpack");
        assert_eq!(listpack, last_reference);
        assert_eq!(
            decode_listpack_strings(&listpack).unwrap(),
            vec![b"c".to_vec()]
        );
        assert_eq!(cursor, data_end);

        let mut restored = Store::new();
        restored.restore_key(b"l", 0, &payload, false, 100).unwrap();
        assert_eq!(restored.lrange(b"l", 0, -1, 100).unwrap(), items);
    }

