        // set with px_ttl_ms=5000 at now_ms=100 → expires_at_ms=5100
        store.set(b"k".to_vec(), b"v".to_vec(), Some(5000), 100);
        let cmds = store.to_aof_commands(100);
        assert_eq!(cmds.len(), 3);
