    #[test]
    fn function_dump_body_uses_upstream_function2_records() {
        let mut original = Store::new();
        let library = sample_function_library("seedlib", "alpha", "beta");
        original
            .function_load(&library, false)
            .expect("seed library must load");

        let dumped = original.function_dump();
        let body_end = dumped.len() - 10;
        let body = &dumped[..body_end];

        assert_eq!(
            body[0], RDB_OPCODE_FUNCTION2,
            "FUNCTION DUMP body must start with upstream FUNCTION2 opcode"
        );
        let (code, consumed) =
            decode_rdb_string(body, 1, body.len()).expect("decode function library code");
        assert_eq!(1 + consumed, body.len());
        assert_eq!(code, library);
    }

    #[test]
    fn function_load_rejects_invalid_library_name_chars_with_upstream_wording() {
        // Upstream functions.c::functionsVerifyName restricts
        // library names to [A-Za-z0-9_] and rejects everything
        // else with the documented wording. (br-frankenredis-r85v)
        let mut store = Store::new();
        // Note: shebang names with whitespace get truncated at the
        // first space by the split_whitespace tokenizer (so
        // "lib bad" parses as "lib" which is valid). The cases
        // below all contain forbidden chars in a single token.
        for bad in [
            "lib-with-dashes",
            "lib.with.dots",
            "lib!",
            "café",
            "lib/slash",
        ] {
            let code =
                format!("#!lua name={bad}\nredis.register_function('fn', function() return 1 end)");
            let err = store
                .function_load(code.as_bytes(), false)
                .expect_err("invalid name must be rejected");
            assert_eq!(
                err,
                StoreError::GenericError(
                    "ERR Library names can only contain letters, numbers, or underscores(_) and must be at least one character long"
                        .to_string()
                ),
                "name {bad:?} should hit the verify-name gate"
            );
        }
        // Valid names still pass.
        let code = b"#!lua name=lib_123_OK\nredis.register_function('fn', function() return 1 end)";
        store
            .function_load(code, false)
            .expect("valid library name must load");
    }

    #[test]
    fn function_load_rejects_unregistered_engine_with_upstream_wording() {
        // Upstream functions.c::functionsCreateWithLibraryCtx emits
        // "Engine '<name>' not found" when the meta header refers
        // to an engine that wasn't registered. We only model LUA;
        // any other engine name must hit the same gate, not silently
        // load. (br-frankenredis-r85v)
        let mut store = Store::new();
        // (frankenredis-fneng) Engine name is reported with the
        // user-typed casing from the shebang, not uppercased.
        let code = b"#!python name=lib\nprint('not lua')";
        let err = store
            .function_load(code, false)
            .expect_err("non-lua engine must be rejected");
        assert_eq!(
            err,
            StoreError::GenericError("ERR Engine 'python' not found".to_string())
        );

        // Plain LUA still loads.
        let lua_code = b"#!lua name=ok\nredis.register_function('fn', function() return 1 end)";
        store
            .function_load(lua_code, false)
            .expect("lua engine must load");
    }

    #[test]
    fn function_load_rejects_invalid_function_name_chars() {
        // Upstream functions.c::functionLibCreateFunction (line 249)
        // applies functionsVerifyName to per-function names. A
        // forged register_function call with a hyphen must fail
        // loudly, not record an invalid function entry.
        // (br-frankenredis-r85v)
        //
        // The per-function name path additionally wraps the wording
        // with `ERR Error registering functions: ` before bubbling
        // back to the client, distinguishing it from the header
        // (`name=...`) charset-failure path which reports the same
        // underlying wording without the prefix. Differential probe
        // vs vendored 7.2.4 confirmed this divergence; the un-
        // prefixed wording was previously pinned. (frankenredis-fnreg)
        let mut store = Store::new();
        let code =
            b"#!lua name=lib_fnv\nredis.register_function('bad-name', function() return 1 end)";
        let err = store
            .function_load(code, false)
            .expect_err("invalid function name must be rejected");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR Library names can only contain letters, numbers, or underscores(_) and must be at least one character long"
                    .to_string()
            )
        );
        assert!(
            !store.function_libraries.contains_key("lib_fnv"),
            "library must not be registered when a function name is invalid"
        );
    }

    #[test]
    fn function_load_meta_header_validation_order_matches_upstream() {
        // Upstream functions.c validates the meta header as
        // engine-present → engine-registered → name-present →
        // name-charset. Confirm our gates fire in the same order
        // so a script with multiple defects surfaces the upstream-
        // expected error first. (br-frankenredis-r85v)
        let mut store = Store::new();

        // No engine, no name → "Missing library metadata".
        let err = store
            .function_load(b"#!\nx", false)
            .expect_err("missing engine must error");
        assert_eq!(
            err,
            StoreError::GenericError("ERR Missing library metadata".to_string())
        );

        // Bad engine + bad name → engine error fires first.
        // (frankenredis-fneng) Engine name preserves user casing.
        let err = store
            .function_load(b"#!python name=lib-bad\nx", false)
            .expect_err("bad engine must error first");
        assert_eq!(
            err,
            StoreError::GenericError("ERR Engine 'python' not found".to_string())
        );

        // Good engine + missing name → name-not-given fires.
        let err = store
            .function_load(b"#!lua\nx", false)
            .expect_err("missing name must error");
        assert_eq!(
            err,
            StoreError::GenericError("ERR Library name was not given".to_string())
        );

        // Good engine + bad-charset name → charset error fires.
        let err = store
            .function_load(b"#!lua name=lib-bad\nx", false)
            .expect_err("bad name charset must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Library names can only contain letters, numbers, or underscores(_) and must be at least one character long"
                    .to_string()
            )
        );
    }

    #[test]
    fn function_load_present_but_empty_name_is_charset_error_not_missing() {
        // (frankenredis-fnemptyname) Differential vs vendored redis 7.2.4:
        // a `name=` token present with an EMPTY value is NOT "name was not
        // given" (that wording is reserved for a wholly ABSENT name token) —
        // upstream functionsVerifyName rejects the empty string with the same
        // charset+length wording as any invalid name. fr previously collapsed
        // present-but-empty into the missing-name wording.
        let mut store = Store::new();
        let charset_err = StoreError::GenericError(
            "ERR Library names can only contain letters, numbers, or underscores(_) and must be at least one character long"
                .to_string(),
        );
        // `name=` with empty value.
        assert_eq!(
            store
                .function_load(
                    b"#!lua name=\nredis.register_function('f', function() return 1 end)",
                    false
                )
                .expect_err("empty name= must error"),
            charset_err
        );
        // `name=` followed by only whitespace (split_whitespace yields the bare
        // `name=` token → empty value).
        assert_eq!(
            store
                .function_load(
                    b"#!lua name= \nredis.register_function('f', function() return 1 end)",
                    false
                )
                .expect_err("whitespace-only name= must error"),
            charset_err
        );
        // A wholly absent name token still yields the missing-name wording.
        assert_eq!(
            store
                .function_load(
                    b"#!lua\nredis.register_function('f', function() return 1 end)",
                    false
                )
                .expect_err("absent name must error"),
            StoreError::GenericError("ERR Library name was not given".to_string())
        );
    }

    #[test]
    fn function_load_no_newline_payload_returns_invalid_library_metadata() {
        // Upstream functions.c::functionExtractLibMetaData splits on
        // the first '\n'; a single-line payload with no terminator
        // surfaces 'Invalid library metadata' (distinct from the
        // empty-body 'No functions registered'). Differential probe
        // vs vendored 7.2.4 confirmed the wording. fr previously
        // returned 'No functions registered' here. (frankenredis-fnhdr)
        let mut store = Store::new();
        let err = store
            .function_load(b"#!lua name=l1", false)
            .expect_err("no-newline payload must error");
        assert_eq!(
            err,
            StoreError::GenericError("ERR Invalid library metadata".to_string())
        );
        // A trailing newline is enough to flip to the body-empty path.
        let err = store
            .function_load(b"#!lua name=l1\n", false)
            .expect_err("empty-body payload must error");
        assert_eq!(
            err,
            StoreError::GenericError("ERR No functions registered".to_string())
        );
    }

    #[test]
    fn function_load_positional_form_rejects_third_argument() {
        // Upstream function_lua.c::luaRegisterFunction rejects 3+
        // positional arguments with 'ERR wrong number of arguments
        // to redis.register_function'. fr previously walked past
        // the function expression and silently ignored any trailing
        // arg(s), pushing a FunctionEntry as if the call were
        // well-formed. (frankenredis-fnpos3)
        let mut s = Store::new();

        let err = s
            .function_load(
                b"#!lua name=lib1\nredis.register_function('f', function() return 1 end, 'extra')",
                false,
            )
            .expect_err("third positional arg must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR wrong number of arguments to redis.register_function"
                    .to_string()
            )
        );

        // Sanity: two-arg positional still loads.
        s.function_load(
            b"#!lua name=lib_ok\nredis.register_function('f', function() return 1 end)",
            false,
        )
        .expect("two-arg positional must load");
        assert!(s.function_libraries.contains_key("lib_ok"));
    }

    #[test]
    fn function_load_positional_form_arity_wordings() {
        // Upstream function_lua.c::luaRegisterFunction surfaces
        // dedicated arity wordings:
        //   - 0 args → 'ERR wrong number of arguments to
        //     redis.register_function'
        //   - 1 arg (single string) → 'ERR calling
        //     redis.register_function with a single argument is only
        //     applicable to Lua table (representing named arguments).'
        // fr previously fell through to extract_function_metadata
        // for these cases, surfacing the wrong 'No functions
        // registered' wording (zero-arg) or silently loading a
        // body-less function entry (single-arg). (frankenredis-fnposary)
        let mut s = Store::new();

        let err = s
            .function_load(b"#!lua name=lib1\nredis.register_function()", false)
            .expect_err("zero args must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR wrong number of arguments to redis.register_function"
                    .to_string()
            )
        );

        let err = s
            .function_load(b"#!lua name=lib2\nredis.register_function('f')", false)
            .expect_err("single string arg must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR calling redis.register_function with a single argument is only applicable to Lua table (representing named arguments).".to_string()
            )
        );

        assert!(s.function_libraries.is_empty());
    }

    #[test]
    fn function_load_positional_form_type_checks_callback_and_first_arg() {
        // Upstream function_lua.c::luaRegisterFunction rejects
        // positional register_function calls whose second argument
        // is not a function ('ERR second argument to
        // redis.register_function must be a function') and whose
        // first argument is not a string ('ERR first argument to
        // redis.register_function must be a string'). fr previously
        // extracted only the first quoted arg and silently pushed a
        // FunctionEntry whose body was missing from the wrapper
        // script. (frankenredis-fnposcb)
        let mut s = Store::new();

        // callback as a quoted string
        let err = s
            .function_load(
                b"#!lua name=lib1\nredis.register_function('f', 'not_fn')",
                false,
            )
            .expect_err("string callback must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR second argument to redis.register_function must be a function"
                    .to_string()
            )
        );

        // callback as a number
        let err = s
            .function_load(b"#!lua name=lib2\nredis.register_function('f', 42)", false)
            .expect_err("numeric callback must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR second argument to redis.register_function must be a function"
                    .to_string()
            )
        );

        // first arg is a Lua bool literal — non-string.
        let err = s
            .function_load(
                b"#!lua name=lib3\nredis.register_function(true, function() return 1 end)",
                false,
            )
            .expect_err("non-string first arg must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR first argument to redis.register_function must be a string"
                    .to_string()
            )
        );

        // Sanity: positional form with valid types still loads.
        s.function_load(
            b"#!lua name=lib_ok\nredis.register_function('f', function() return 1 end)",
            false,
        )
        .expect("valid positional form must load");
        assert!(s.function_libraries.contains_key("lib_ok"));
    }

    #[test]
    fn function_load_table_form_type_checks_string_and_callback_fields() {
        // Upstream function_lua.c::luaRegisterFunction type-checks
        // the three string-typed fields (function_name, description)
        // and the callback. Differential probe vs vendored 7.2.4
        // confirmed the wordings. fr previously accepted these
        // silently. (frankenredis-fntype)
        let mut s = Store::new();

        // function_name as a Lua table (e.g. `{'a'}`) → must be a string.
        let err = s
            .function_load(
                b"#!lua name=lib1\n\
                  redis.register_function{function_name={'a'}, callback=function() return 1 end}",
                false,
            )
            .expect_err("function_name as table must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR function_name argument given to redis.register_function must be a string"
                    .to_string()
            )
        );

        // description as a Lua table → must be a string.
        let err = s
            .function_load(
                b"#!lua name=lib2\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, description={'x'}}",
                false,
            )
            .expect_err("description as table must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR description argument given to redis.register_function must be a string"
                    .to_string()
            )
        );

        // callback as a string → must be a function.
        let err = s
            .function_load(
                b"#!lua name=lib3\n\
                  redis.register_function{function_name='f', callback='not_fn'}",
                false,
            )
            .expect_err("callback as string must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR callback argument given to redis.register_function must be a function"
                    .to_string()
            )
        );

        assert!(s.function_libraries.is_empty());
    }

    #[test]
    fn function_load_table_form_captures_flags_into_function_entry() {
        // FCALL_RO dispatch and FUNCTION LIST output both depend on
        // the flags array on FunctionEntry. fr previously validated
        // table-form flags but always pushed an empty Vec, so
        // FCALL_RO could never succeed against a function declared
        // with flags={'no-writes'} — the no-writes lookup at the
        // FCALL_RO gate always returned false. (frankenredis-fnflagstore)
        let mut store = Store::new();
        let code = b"#!lua name=lib_nw\n\
                     redis.register_function{function_name='nw_get', callback=function() return 1 end, flags={'no-writes'}}";
        store.function_load(code, false).expect("library must load");
        let lib = store
            .function_libraries
            .get("lib_nw")
            .expect("library present");
        assert_eq!(lib.functions.len(), 1);
        assert_eq!(lib.functions[0].name, "nw_get");
        assert_eq!(lib.functions[0].flags, vec!["no-writes".to_string()]);

        // Multi-flag table preserves order and content.
        let mut s2 = Store::new();
        let code2 = b"#!lua name=lib_multi\n\
                      redis.register_function{function_name='f', callback=function() return 1 end, flags={'no-writes', 'allow-stale'}}";
        s2.function_load(code2, false)
            .expect("multi-flag library must load");
        let lib2 = s2
            .function_libraries
            .get("lib_multi")
            .expect("multi-flag library present");
        assert_eq!(
            lib2.functions[0].flags,
            vec!["no-writes".to_string(), "allow-stale".to_string()]
        );

        // No flags field → flags vec is empty.
        let mut s3 = Store::new();
        let code3 = b"#!lua name=lib_none\n\
                      redis.register_function{function_name='f', callback=function() return 1 end}";
        s3.function_load(code3, false)
            .expect("flagless library must load");
        let lib3 = s3
            .function_libraries
            .get("lib_none")
            .expect("flagless library present");
        assert!(lib3.functions[0].flags.is_empty());
    }

    #[test]
    fn function_load_table_form_validates_flags() {
        // Upstream function_lua.c::luaRegisterFunction validates the
        // flags field in two passes: it must be a table, and every
        // entry must be a registered flag name. The five accepted
        // flags in vendored 7.2.4 are no-writes, allow-oom,
        // allow-stale, no-cluster, allow-cross-slot-keys.
        // Differential probe vs vendored 7.2.4 confirmed the
        // wordings. (frankenredis-fnflags)
        let mut store = Store::new();

        // Non-table flags → must-be-a-table wording.
        let err = store
            .function_load(
                b"#!lua name=lib1\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, flags='x'}",
                false,
            )
            .expect_err("scalar flags must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR flags argument to redis.register_function must be a table representing function flags"
                    .to_string()
            )
        );

        // Unknown flag in a flags table → unknown-flag wording.
        let err = store
            .function_load(
                b"#!lua name=lib2\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, flags={'bogus-flag'}}",
                false,
            )
            .expect_err("unknown flag must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR unknown flag given".to_string()
            )
        );

        // Valid flag mixed with unknown → unknown-flag wording fires.
        let err = store
            .function_load(
                b"#!lua name=lib3\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, flags={'no-writes', 'bogus'}}",
                false,
            )
            .expect_err("mixed valid/unknown must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR unknown flag given".to_string()
            )
        );

        // Sanity: each individual valid flag still loads.
        for flag in [
            "no-writes",
            "allow-oom",
            "allow-stale",
            "no-cluster",
            "allow-cross-slot-keys",
        ] {
            let mut s = Store::new();
            let code = format!(
                "#!lua name=lib_ok\nredis.register_function{{function_name='f', callback=function() return 1 end, flags={{'{flag}'}}}}"
            );
            s.function_load(code.as_bytes(), false)
                .unwrap_or_else(|_| panic!("flag {flag} must load"));
        }

        // Empty flags table is valid (no-op).
        let mut s = Store::new();
        s.function_load(
            b"#!lua name=lib_empty\nredis.register_function{function_name='f', callback=function() return 1 end, flags={}}",
            false,
        )
        .expect("empty flags table must load");
        assert!(store.function_libraries.is_empty());
    }

    #[test]
    fn function_load_table_form_rejects_unknown_field() {
        // Upstream function_lua.c::luaRegisterFunction rejects any
        // table key beyond function_name / callback / description /
        // flags with 'ERR unknown argument given to
        // redis.register_function'. fr previously accepted unknown
        // fields silently. Differential probe vs vendored 7.2.4
        // confirmed the wording. (frankenredis-fnukn)
        let mut store = Store::new();

        // Unknown field 'bogus' AFTER callback=function() ... end —
        // exercises the function-body-skipping logic in
        // find_unknown_table_key.
        let err = store
            .function_load(
                b"#!lua name=lib1\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, bogus='x'}",
                false,
            )
            .expect_err("unknown field after callback must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR unknown argument given to redis.register_function"
                    .to_string()
            )
        );

        // Unknown field BEFORE callback.
        let err = store
            .function_load(
                b"#!lua name=lib2\n\
                  redis.register_function{function_name='f', foo=1, callback=function() return 1 end}",
                false,
            )
            .expect_err("unknown field before callback must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR unknown argument given to redis.register_function"
                    .to_string()
            )
        );

        // Sanity: all four valid fields together still load.
        store
            .function_load(
                b"#!lua name=lib_ok\n\
                  redis.register_function{function_name='f', callback=function() return 1 end, description='d', flags={'no-writes'}}",
                false,
            )
            .expect("library with all valid fields must load");
        assert!(store.function_libraries.contains_key("lib_ok"));
    }

    #[test]
    fn function_load_table_form_rejects_missing_function_name() {
        // Upstream function_lua.c::luaRegisterFunction validates
        // function_name BEFORE callback, so a table-form invocation
        // missing function_name surfaces 'ERR redis.register_function
        // must get a function name argument' even when callback is
        // also missing. fr previously fell through to extract_
        // function_metadata, returned None, and surfaced the wrong
        // 'No functions registered' wording. Differential probe vs
        // vendored 7.2.4 confirmed the wording. (frankenredis-fnnam)
        let mut store = Store::new();

        // callback present, function_name missing
        let err = store
            .function_load(
                b"#!lua name=lib1\n\
                  redis.register_function{callback=function() return 1 end}",
                false,
            )
            .expect_err("missing function_name must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR redis.register_function must get a function name argument"
                    .to_string()
            )
        );

        // empty table → function_name fires before callback
        let err = store
            .function_load(b"#!lua name=lib2\nredis.register_function{}", false)
            .expect_err("empty table must error with function_name wording");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR redis.register_function must get a function name argument"
                    .to_string()
            )
        );

        // description-only table
        let err = store
            .function_load(
                b"#!lua name=lib3\nredis.register_function{description='x'}",
                false,
            )
            .expect_err("description-only must error with function_name wording");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR redis.register_function must get a function name argument"
                    .to_string()
            )
        );

        assert!(store.function_libraries.is_empty());
    }

    #[test]
    fn function_load_table_form_rejects_missing_callback() {
        // Upstream function_lua.c::luaRegisterFunction rejects a
        // table-form register_function call that omits the
        // `callback` field with 'ERR Error registering functions:
        // ERR redis.register_function must get a callback argument'.
        // fr's textual parser previously only checked for
        // function_name=, so a library like
        //     register_function{function_name='nocb'}
        // silently registered an empty function. Differential probe
        // vs vendored 7.2.4 confirmed the wording. (frankenredis-fncb)
        let mut store = Store::new();
        let code = b"#!lua name=lib1\n\
                     redis.register_function{function_name='nocb'}";
        let err = store
            .function_load(code, false)
            .expect_err("missing callback must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR redis.register_function must get a callback argument"
                    .to_string()
            )
        );
        assert!(
            !store.function_libraries.contains_key("lib1"),
            "library must not be registered when callback is missing"
        );

        // Sanity: a properly-formed table-form call with callback
        // present still loads.
        let ok_code = b"#!lua name=lib_ok\n\
                        redis.register_function{function_name='f', callback=function() return 1 end}";
        store
            .function_load(ok_code, false)
            .expect("library with callback must load");
        assert!(store.function_libraries.contains_key("lib_ok"));
    }

    #[test]
    fn function_load_rejects_duplicate_function_name_within_library() {
        // Upstream functions.c::functionLibCreateFunction rejects a
        // second registration with the same name inside one library
        // with 'ERR Error registering functions: ERR Function
        // already exists in the library'. fr previously pushed a
        // duplicate entry, so FUNCTION LIST would show the function
        // twice. Differential probe vs vendored 7.2.4 confirmed the
        // wording. (frankenredis-fnfdup)
        let mut store = Store::new();
        let code = b"#!lua name=lib1\n\
                     redis.register_function('dupe', function() return 1 end)\n\
                     redis.register_function('dupe', function() return 2 end)";
        let err = store
            .function_load(code, false)
            .expect_err("duplicate fname must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Error registering functions: ERR Function already exists in the library"
                    .to_string()
            )
        );
        assert!(
            !store.function_libraries.contains_key("lib1"),
            "library must not be registered when duplicate fname is rejected"
        );
    }

    #[test]
    fn function_load_rejects_duplicate_name_argument() {
        // Upstream functions.c rejects a second `name=` token with
        // 'Invalid metadata value, name argument was given multiple
        // times'. fr previously silently overwrote the first name.
        // (frankenredis-fnhdr)
        let mut store = Store::new();
        let code = b"#!lua name=a name=b\nredis.register_function('f', function() return 1 end)";
        let err = store
            .function_load(code, false)
            .expect_err("duplicate name= must error");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Invalid metadata value, name argument was given multiple times".to_string()
            )
        );
        assert!(
            !store.function_libraries.contains_key("a"),
            "first name must not be registered"
        );
        assert!(
            !store.function_libraries.contains_key("b"),
            "second name must not be registered"
        );
    }

    #[test]
    fn function_load_table_form_does_not_confuse_value_substring_with_key() {
        // Regression: when function_name='describe_user', the
        // `description` substring inside the value used to bleed
        // into the description slot via a naive find('description').
        // The new key-boundary parser ignores substring matches
        // that aren't real `key=` tokens. (br-frankenredis-r85v)
        let mut store = Store::new();
        let code = b"#!lua name=lib_dbu\nredis.register_function{function_name='describe_user', callback=function() return 1 end}";
        store.function_load(code, false).expect("library must load");

        let lib = store
            .function_libraries
            .get("lib_dbu")
            .expect("library present");
        assert_eq!(lib.functions.len(), 1);
        assert_eq!(lib.functions[0].name, "describe_user");
        assert_eq!(
            lib.functions[0].description, None,
            "description must remain None when the table omits the field"
        );
    }

    #[test]
    fn function_load_extracts_per_function_description_from_table_form() {
        // Upstream function_lua.c accepts `description` in
        // redis.register_function{function_name=...,
        //   description='d', callback=fn}. We previously dropped
        // the description, leaving FUNCTION LIST description=nil
        // even when the script set it. (br-frankenredis-r85v)
        let mut store = Store::new();
        let code = b"#!lua name=desclib\nredis.register_function{function_name='myfn', description='hello world', callback=function() return 1 end}";
        store.function_load(code, false).expect("library must load");

        let lib = store
            .function_libraries
            .get("desclib")
            .expect("library present");
        assert_eq!(lib.functions.len(), 1);
        assert_eq!(lib.functions[0].name, "myfn");
        assert_eq!(
            lib.functions[0].description.as_deref(),
            Some("hello world"),
            "description from register_function table-form must be captured"
        );
    }

    #[test]
    fn function_dump_restore_roundtrip_preserves_function_description_from_code() {
        // Upstream FUNCTION DUMP persists library code only; function
        // descriptions survive because restoring reloads the same
        // `redis.register_function{..., description=...}` code.
        // (br-frankenredis-r85v)
        let mut original = Store::new();
        let library = b"#!lua name=desclib\n\
            redis.register_function{function_name='fn1', description='the description', callback=function(keys, args) return 1 end}\n";
        original
            .function_load(library, false)
            .expect("seed library must load");

        let dumped = original.function_dump();
        let mut restored = Store::new();
        restored
            .function_restore(&dumped, "REPLACE")
            .expect("self-generated FUNCTION DUMP payload must restore");

        let lib = restored
            .function_libraries
            .get("desclib")
            .expect("library should be present");
        assert_eq!(lib.functions.len(), 1);
        assert_eq!(lib.functions[0].name, "fn1");
        assert_eq!(
            lib.functions[0].description.as_deref(),
            Some("the description")
        );
    }

    #[test]
    fn function_dump_restore_roundtrip_preserves_multilibrary_snapshot_order() {
        let alpha = sample_function_library("alpha", "afn1", "afn2");
        let beta = sample_function_library("beta", "bfn1", "bfn2");
        let mut original = Store::new();
        original
            .function_load(&beta, false)
            .expect("beta library must load");
        original
            .function_load(&alpha, false)
            .expect("alpha library must load");
        let expected = function_library_snapshot(&original);
        let dumped = original.function_dump();

        let mut restored = Store::new();
        restored
            .function_restore(&dumped, "REPLACE")
            .expect("self-generated multi-library FUNCTION DUMP payload must restore");

        assert_eq!(function_library_snapshot(&restored), expected);
        assert_eq!(restored.function_dump(), dumped);
    }

    #[test]
    fn function_restore_invalid_dump_is_atomic_even_with_flush_policy() {
        let mut store = Store::new();
        let library = sample_function_library("sentinel", "alpha", "beta");
        store
            .function_load(&library, false)
            .expect("sentinel library must load");
        let before = function_library_snapshot(&store);
        let invalid_dump = vec![1, 0, 0, 0, 4, 0, 0, 0, b'n', b'a', b'm', b'e'];

        let err = store
            .function_restore(&invalid_dump, "FLUSH")
            .expect_err("truncated function dump must fail");
        // After wrapping FUNCTION DUMP in the upstream version+CRC64
        // envelope (br-frankenredis-r83v), a payload without the
        // 10-byte footer fails the checksum gate first with the
        // upstream wording rather than the body-parse error.
        assert_eq!(
            err,
            StoreError::GenericError("ERR DUMP payload version or checksum are wrong".to_string())
        );
        assert_eq!(
            function_library_snapshot(&store),
            before,
            "failed FUNCTION RESTORE must not clear or partially mutate state"
        );
    }

    #[test]
    fn function_restore_rejects_payload_with_future_rdb_version() {
        // Upstream cluster.c::verifyDumpPayload rejects RDB versions
        // higher than the local RDB_VERSION. We mirror that so a
        // forged future-version FUNCTION DUMP can't slip past the
        // body parser. (br-frankenredis-r83v)
        let mut store = Store::new();
        let library = sample_function_library("vguard", "alpha", "beta");
        store
            .function_load(&library, false)
            .expect("seed library must load");
        let mut dump = store.function_dump();
        // Bump the version field (last 10 bytes are version+crc64;
        // version is bytes [..2] of the footer).
        let footer_offset = dump.len() - 10;
        // Replace version with FUNCTION_DUMP_RDB_VERSION + 1.
        let bumped = (Store::FUNCTION_DUMP_RDB_VERSION + 1).to_le_bytes();
        dump[footer_offset] = bumped[0];
        dump[footer_offset + 1] = bumped[1];
        // Recompute CRC so this fails the version gate, not the CRC
        // gate — proves the version check is the gate that fires.
        let new_crc = fr_persist::crc64_redis(&dump[..footer_offset + 2]);
        dump[footer_offset + 2..].copy_from_slice(&new_crc.to_le_bytes());

        let err = store
            .function_restore(&dump, "FLUSH")
            .expect_err("future-version dump must fail");
        assert_eq!(
            err,
            StoreError::GenericError("ERR DUMP payload version or checksum are wrong".to_string())
        );
    }

    #[test]
    fn function_restore_flush_replaces_existing_libraries() {
        let mut source = Store::new();
        source
            .function_load(&sample_function_library("seedlib", "alpha", "beta"), false)
            .expect("seed library must load");
        let source_snapshot = function_library_snapshot(&source);
        let dumped = source.function_dump();

        let mut restored = Store::new();
        restored
            .function_load(&sample_function_library("stale", "gamma", "delta"), false)
            .expect("stale library must load");

        restored
            .function_restore(&dumped, "FLUSH")
            .expect("FUNCTION RESTORE FLUSH must replace existing libraries");

        let restored_snapshot = function_library_snapshot(&restored);
        assert_eq!(restored_snapshot.len(), 1);
        assert_eq!(restored_snapshot[0].0, source_snapshot[0].0);
        assert_eq!(restored_snapshot[0].1, source_snapshot[0].1);
        assert_eq!(restored_snapshot[0].2, source_snapshot[0].2);
        let mut function_names = restored_snapshot[0].3.clone();
        function_names.sort();
        assert_eq!(
            function_names,
            vec!["alpha".to_string(), "beta".to_string()]
        );
    }

    #[test]
    fn function_restore_unknown_policy_is_atomic() {
        let mut store = Store::new();
        store
            .function_load(&sample_function_library("seedlib", "alpha", "beta"), false)
            .expect("seed library must load");
        let before_snapshot = function_library_snapshot(&store);
        let before_dump = store.function_dump();

        let err = store
            .function_restore(&before_dump, "BROKEN")
            .expect_err("unknown FUNCTION RESTORE policy must fail");
        assert_eq!(
            err,
            StoreError::GenericError(
                "ERR Wrong restore policy given, value should be either FLUSH, APPEND or REPLACE."
                    .to_string()
            )
        );
        assert_eq!(function_library_snapshot(&store), before_snapshot);
        assert_eq!(store.function_dump(), before_dump);
    }

    #[test]
    fn function_restore_empty_policy_defaults_to_append_for_disjoint_payload() {
        let mut payload_store = Store::new();
        payload_store
            .function_load(&sample_function_library("addon", "epsilon", "zeta"), false)
            .expect("payload addon library must load");
        let payload_dump = payload_store.function_dump();

        let mut restored = Store::new();
        restored
            .function_load(&sample_function_library("seedlib", "alpha", "beta"), false)
            .expect("existing seed library must load");

        restored
            .function_restore(&payload_dump, "")
            .expect("empty FUNCTION RESTORE policy must behave like APPEND");

        let mut expected = Store::new();
        expected
            .function_load(&sample_function_library("seedlib", "alpha", "beta"), false)
            .expect("expected seed library must load");
        expected
            .function_load(&sample_function_library("addon", "epsilon", "zeta"), false)
            .expect("expected addon library must load");

        assert_eq!(
            function_library_snapshot(&restored),
            function_library_snapshot(&expected)
        );
        assert_eq!(restored.function_dump(), expected.function_dump());
    }

    #[test]
    fn function_restore_empty_policy_collision_is_atomic() {
        let mut payload_store = Store::new();
        payload_store
            .function_load(&sample_function_library("seedlib", "gamma", "delta"), false)
            .expect("replacement seed library must load");
        payload_store
            .function_load(&sample_function_library("addon", "epsilon", "zeta"), false)
            .expect("addon library must load");
        let payload_dump = payload_store.function_dump();

        let mut restored = Store::new();
        restored
            .function_load(&sample_function_library("seedlib", "alpha", "beta"), false)
            .expect("original seed library must load");
        restored
            .function_load(&sample_function_library("keepme", "theta", "iota"), false)
            .expect("disjoint existing library must load");
        let before_snapshot = function_library_snapshot(&restored);
        let before_dump = restored.function_dump();

        let err = restored
            .function_restore(&payload_dump, "")
            .expect_err("empty policy must default to APPEND collision semantics");
        assert!(
            matches!(err, StoreError::GenericError(ref message) if message.contains("already exists")),
            "unexpected empty-policy collision error: {err:?}"
        );
        assert_eq!(function_library_snapshot(&restored), before_snapshot);
        assert_eq!(restored.function_dump(), before_dump);
    }

